import{r as e,t}from"./jsx-runtime-DAs1UGHr.js";import{t as n}from"./react-BnRWbv_O.js";import{c as r,t as i}from"./chunk-OE4NN4TA-BUT3QMhb.js";import{t as a}from"./createLucideIcon-OFq4gQlE.js";import{t as o}from"./Card-DfmWyPoo.js";import{n as s,t as c}from"./ListTable-DtL1S8P1.js";import{t as l}from"./ParagraphImage-CUaxl9dH.js";var u=a(`circle-chevron-left`,[[`circle`,{cx:`12`,cy:`12`,r:`10`,key:`1mglay`}],[`path`,{d:`m14 16-4-4 4-4`,key:`ojs7w8`}]]),d=a(`circle-chevron-right`,[[`circle`,{cx:`12`,cy:`12`,r:`10`,key:`1mglay`}],[`path`,{d:`m10 8 4 4-4 4`,key:`1wy4r4`}]]),f=JSON.parse(`[{"tag":"e001","title":"The approach of dawn","image":true,"desc":["The approach of dawn has turned the sky a milky grey-green, like jade. The sea is a luminous pane of silver. Holding the tiller of your sailing boat, you keep your gaze fixed on the glittering constellation known as the Spider. It marks the north, and by keeping it to port you know you are still on course.","The sun appears in a trembling burst of red fire at the rim of the world. Slowly the chill of night gives way to brazen warmth. You lick your parched lips. There is a little water sloshing in the bottom of the barrel by your feet, but not enough to see you through another day.","Sealed in a scroll case tucked into your jerkin is the parchment map your grandfather gave to you on his death-bed. You remember his stirring tales of far sea voyages, of kingdoms beyond the western horizon, of sorcerous islands and ruined palaces filled with treasure. As a child you dreamed of nothing else but the magical quests that were in store if you too became an adventurer.","You never expected to die in an open boat before your adventures even began.","Securing the tiller, you unroll the map and study it again. You hardly need to. Every detail is etched into your memory by now. According to your reckoning, you should have reached the east coast of Harkuna, the great northern continent, days ago.","A pasty grey blob splatters on to the map. After a moment of stunned surprise, you look up and curse the seagull circling directly overhead. Then it strikes you – where there’s a seagull, there may be land.","You leap to your feet and scan the horizon. Sure enough, a line of white cliffs lie a league to the north. Have you been sailing along the coast all this time without realising the mainland was so close?","Steering towards the cliffs, you feel the boat judder against rough waves. A howling wind whips plumes of spindrift across the sea. Breakers pound the high cliffs.","The tiller is yanked out of your hands. The little boat is spun around, out of control, and goes plunging in towards the coast.","You leap clear at the last second. There is the snap of timber, the roaring crescendo of the waves – and then silence as you go under. Striking out wildly, you try to swim clear of the razor-sharp rocks. For a while the undertow threatens to drag you down, then suddenly a wave catches you and flings you contemptuously up on to the beach.","Battered and bedraggled you lie gasping for breath until you hear someone walking along the shore towards you. Wary of danger, you lose no time in getting to your feet. Confronting you is an old man clad in a dirty loin-cloth. His eyes have a feverish bright look that is suggestive of either a mystic or a madman.","Now turn to e020."]},{"tag":"e002","title":"Royal escort","desc":["If you have a coded missive, turn to e676 immediately. If not, but you have the codeword Deliver, turn to e098 immediately. If you have neither, read on.","The soldier recognizes you.","He bows and says, 'Welcome, my lord. I will take you see King Nergan.'","He leads you to Nergan’s mountain stockade, where the king greets you warmly.","'Ah, my local champion! It is always a pleasure to see you. However, I was hoping you had spoken with General Beladai of the allied army – we need that citadel. Now go. That is a royal command!'","You leave, climbing down to the foothills of the mountains. Turn to e474."]},{"tag":"e003","title":"Foothills of Harkun","desc":["You have come to the foothills of the Spine of Harkun, in the north west of Sokara. The view is impressive: a massive wall of forested mountains, whose rocky, white-flanked peaks soar skywards into the clouds. These parts of the mountains are unclimbable but you notice a large cave at the bottom of a mountain."],"tables":[{"cols":["Ref","Option"],"rows":[["e665","Investigate the cave"],["e271","Go east to the Citadel of Velis Corin"],["e276","South into the wilderness"]]}]},{"tag":"e004","title":"Reward of Alvir and Valmir","desc":["The priests of Alvir and Valmir are overjoyed that you have returned the golden net. The high priest rewards you with 100 💎 and a MAGIC weapon, a rune-engraved trident. Note the weapon, a trident (⚔️ +1), on your Adventure Sheet, and turn to e220."]},{"tag":"e005","title":"The climb","desc":["It is a tough climb upwards but not impossible. If you have some climbing gear, turn to e652.","If not, make a SCOUTING roll at Difficulty 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e652","Successful SCOUTING roll"],["e529","Failed SCOUTING roll"]]}]},{"tag":"e006","title":"Chest treasure","desc":["The chest springs open with a click. Inside you find 60 💎, a mandolin (CHARISMA +1), and a potion of healing. The potion can be used once, at any time (even in COMBAT) to restore 5 ❤️ points. There is also an ancient religious text about the gods of the Uttaku, called the scroll of Ebron, which reveals that one of the gods of the Uttakin is called Ebron, and that he has fourteen angles.","Note whatever you are taking on your Adventure Sheet, and turn to e010."]},{"tag":"e007","title":"Lost in the forest","desc":["Much to your embarrassment, you get lost in the vast forest. You wander around for days until you finally emerge at the Bronze Hills. Turn to e110."]},{"tag":"e008","title":"Yellowport arrival","desc":["You step through the archway. Immediately the symbols on the stone begin to glow with red-hot energy; your hair stands on end and your body tingles. A crackling nimbus of blue-white force engulfs you, the sky darkens and thunder and lightning crash and leap across the heavens. Suddenly, your vision fades, and everything goes black.","When your sight returns, you find yourself at the gates of a large city, set on an ochre-coloured river. A vile stink of brimstone permeates the air. You wrinkle your face up in disgust and gag involuntarily.","'Welcome to Yellowport!' says a passing merchant.","Turn to e010."]},{"tag":"e009","title":"Storm demons and Devil’s Peak","desc":["If you have the codeword Altitude, turn to e272 immediately. If not, read on.","A notice has been pinned up in the foyer. 'Adventurer priest wanted. See the Chief Administrator.'","Naturally, you present yourself, and the Chief Administrator, a grey-whiskered priest of Elnir, takes you into his office. He shows you a special crystal ball that displays an aerial view of Marlock City. You notice several strange-looking clouds hanging over the city. They are shaped like gigantic demons reaching down to claw at the city laid out below them.","'The crystal ball shows things as they are in the spirit world,' explains the priest. 'These storm demons cannot be seen under normal circumstances, but they are there, almost ready to destroy the city.'","He goes on to tell you that Sul Veneris, the divine Lord of Thunder is one of the sons of Elnir, the Sky God, chief among the gods. He is responsible for keeping the storm demons under control, and thunder is thought to be the sound of Sul Veneris smiting the demons in his wrath.","'Unfortunately, the storm demons have found a way to put Sul Veneris into an enchanted sleep. He lies at the very top of Devil’s Peak, a single spire of volcanic rock, reaching up into the clouds. The peak lies north of Marlock City and the Curstmoor. We need an enterprising priest to get to the top of the peak and free Sul Veneris from his sleep. But I must warn you that several priests have already tried, and we never saw them again.'","If you take up the quest, record the codeword Altitude.","Turn to e100."]},{"tag":"e010","title":"Yellowport","desc":["If you have the codeword Assassin, turn to e050 immediately. If not, read on.","If you have just arrived in Yellowport, tick the first empty box above (use a pencil). The boxes track how often you have visited the city. If this is your fourth visit, turn to e273.","Yellowport is the second largest city in Sokara. It is mainly a trading town, known for exotic goods from distant Ankon-Konu in the south.","The Stinking River brings sulphur from the Lake of the Sea Dragon into the city, where it is processed in large waterfront warehouses run by the merchants’ guild and exported across Harkuna. Despite its wealth, the sulphur makes the city foul and yellowed, and the river is almost unusable for drinking or fishing.","Demand for sulphur remains high, especially from sorcerous guilds, making the trade extremely valuable despite the environmental damage.","Politically, Sokara has changed dramatically. King Corin VII has been deposed and executed in a military coup, and General Grieve Marlock now controls the kingdom.","In Yellowport, the old Council has been dissolved and replaced by a provost marshal, Marloes Marlock, who governs the city under military rule.","You may buy a town house in Yellowport for 200 💎. It provides a place to rest and store equipment. If you buy it, mark it on your sheet and deduct the cost.","To leave Yellowport by sea, you must use the harbourmaster to manage ships and cargo.","If you have the codeword Artefact and the Book of the Seven Sages, turn to e040.","Choose your action below:"],"tables":[{"cols":["Ref","Option"],"rows":[["e523","Seek an audience with the provost marshal"],["e030","Visit the market"],["e555","Visit the harbourmaster"],["e405","Go the merchants’ guild"],["e302","Explore the city by day"],["e442","Explore the city by night"],["e300","Visit your town house (if box ticked)"],["e506","Visit the Gold Dust Tavern"],["e141","Visit the temple of Maka"],["e316","Visit the temple of Elnir"],["e220","Visit the temple of Alvir and Valmir"],["e526","Visit the temple of Tyrnai"],["e621","Travel north-east towards Venefax"],["e233","Head north-west to Trefoille"],["e082","Follow the Stinking River north"],["e558","Strike out north-west, across country"]]}]},{"tag":"e011","title":"Obsidian standing stones","desc":["A narrow path leads up the hill. The summit is crowned with a circle of large obsidian standing stones, hewn from solid rock.","Despite the bitter wind that sweeps across the hills, the stones are unweathered and appear newly placed.","They form three archways, each carved with mystic symbols and runes of power.","Turn to e065."]},{"tag":"e012","title":"Merfolk encounter","desc":["You tell them a story of tragic love between a merman and a human princess. The mer-folk are moved to tears, and one of them kisses you, allowing you to breathe underwater.","The mer-folk lead you into the depths, where they swim playfully around you.","Suddenly, a hideous form emerges from the murk. It resembles a giant squid, but carries a spear in one tentacle and wears crude armour. Its black eyes show cold intelligence. The mer-folk flee in panic, leaving you alone with the creature.","If you have the codeword Anchor, turn to e116. Otherwise, turn to e238."]},{"tag":"e013","title":"The Violet Ocean","desc":["'The Violet Ocean’s a dangerous place, Cap’n,' says the first mate. 'The crew won’t follow you there if they don’t think you’re good enough.'","If your Rank is 4 or higher, turn to paragraph 55 in Over the Blood-Dark Sea. If your Rank is lower, the first mate advises against the voyage.","If you take his advice, turn back to e507.","If you insist on the journey, you must make a CHARISMA roll at Difficulty 12 to convince the crew.","If successful, turn to paragraph 55 in Over the Blood-Dark Sea. Otherwise, turn back to e507."]},{"tag":"e014","title":"Backstab ambush","image":true,"desc":["Someone stabs you in the back. Lose 5 ❤️ points.","If you still live, you spin around just as a beefy, disreputable-looking thug comes at you again with a long dagger.","'Get the snooping swine!' yells the man with the eyepatch. You are forced into COMBAT.","If you lose, you are dead unless you have a resurrection deal.","If you win, turn to e476."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Thug","3","6","13"]]}]},{"tag":"e015","title":"Drunken officers","desc":["Three drunken army officers accost you on the street.","If you have the title Protector of Sokara, turn to e542 immediately.","'Sho, what have we... hic... here,' sneers one of them drunkenly.","'Out of the way, you stinking dog!' says another, shoving you in the chest."],"tables":[{"cols":["Ref","Option"],"rows":[["e044","Step out of the way"],["e266","Return the insult"]]}]},{"tag":"e016","title":"Sea dragon hoard","desc":["If there is a tick in the box, turn to e251 immediately. If not, put a tick there now and read on.","If you have the codeword Avenge, turn to e648 immediately. Otherwise read on.","You remain quiet as a mouse behind a pile of coins. After a long wait, the sea dragon slithers into the water and swims away.","You now have time to loot the hoard. You may choose up to three treasures:"],"tables":[{"cols":["Treasure","Effect"],"rows":[["Enchanted sword","⚔️ +3"],["Plate armour","🛡️ +5"],["Ebony wand","MAGIC +2"],["Money","500 💎"],["MAGIC mandolin","CHARISMA +2"],["Gold compass","SCOUTING +2"],["MAGIC lockpicks","THIEVERY +2"],["Silver holy symbol","SANCTITY +2"]]}],"note":["After taking your third treasure, the sea dragon returns.","You climb up through a hole in the roof onto an island in the middle of the lake.","From there you escape on a passing boat and reach Cadmium village.","Turn to e135."]},{"tag":"e017","title":"Faery mound","desc":["The horse and you hit the wall. There is a bright flash, and you find yourself passing straight through it – it is a faery mound.","The horse transforms in a puff of smoke into a small, knobbly-limbed goblin who collapses under your weight.","You are inside a cavern lit by tiny faery folk glowing like fireflies. The other horses have also transformed into goblins, elves, and faeries.","'What have we here?' whispers a pale elf woman dressed in silvery cobwebs and wearing a gold crown.","'An overweight mortal sitting on poor old Gobrash, your majesty!' groans the goblin beneath you.","You realize you are in great danger. The queen signals to her people close in around you ominously. Make a SANCTITY roll at Difficulty 9."],"tables":[{"cols":["Ref","Result"],"rows":[["e626","Successful SANCTITY roll"],["e268","Failed SANCTITY roll"]]}]},{"tag":"e018","title":"Militia encounter","desc":["You spin them a tale about how your poor brother, a mercenary in Grieve Marlock’s personal guard, lost his legs in the fight to overthrow the old king, and that you have spent all your money on looking after him.","Several of the militia are brought to tears by your eloquent speech – they end up having a whip-round among themselves for your brother, and they give you 15 💎!","Chuckling to yourself, you return to the city centre.","Turn to e010."]},{"tag":"e019","title":"Dragon Knights trial","desc":["!!! Put a tick in an empty box. If all three boxes are now ticked, gain the codeword Anvil.","The Dragon Knights are impressed with your ⚔️ skills.","Your opponent comes round, ruefully rubbing his neck. Grudgingly, he admits to your superior skill and hands you his weapon and armour.","You get an ordinary sword and a suit of heavy plate (🛡️ +6). You take your leave.","Turn to e276."]},{"tag":"e020","title":"Isle of the Druids","image":true,"desc":["‘Well, well, well, what have we here, friends?’ asks the old man. He seems to be talking to someone next to him, although you are certain he is alone.","‘Looks like a washed up adventurer to me!’ he says in answer to his own question, ‘all wet and out of luck.’","He carries on having a conversation – a conversation that quickly turns into a heated debate. He is clearly quite mad.","‘Excuse me, umm, EXCUSE ME!,’ you shout above the hubbub in an attempt to grab the old man’s attention. He stops and stares at you.","‘Is this the Isle of the Druids?’ you ask impatiently.","‘Indeed it is,’ says the old man, ‘I see that you are from a far land so it is up to me to welcome you to Harkuna. But I think you may have much to do here as it is written in the stars that someone like you would come. Your destiny awaits you! Follow me, young adventurer.’","The old man turns smartly about and begins walking up a path towards some hills. You can just see some sort of monolithic stone structure atop one of them.","‘Come on, come on, I’ll show you the Gates of the World,’ the old man babbles."],"tables":[{"cols":["Ref","Option"],"rows":[["e192","Follow him"],["e128","Explore the coast"],["e257","Head into the nearby forest"]]}]},{"tag":"e021","title":"Thug encounter","image":true,"desc":["While making your way through the back streets of the poor quarter you are set upon a knife-wielding thug, who is intent of relieving you of your purse. If you don’t want to fight him, you can try a CHARISMA rollat a Difficulty of 8 to try to talk your way out of this unpleasant situation. If you succeed, the thug leaves, confused by yourrhetoric (turn to 10 and choose again.) Otherwise, you must fight him.","If you defeat him, you find 15 💎 on his body. If you are defeated, you are stunned into unconsciousness. You come round with 1 ❤️ point, and he has robbed you of 50 💎 (or of all your money if you have less than 50 💎).","Turn to e010."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Thug","4","7","6"]]}]},{"tag":"e022","title":"Golem chamber","desc":["You reach down and deftly pull out the ceramic plug. A gush of foul-smelling emerald green liquid spills on to the floor, and the golem twitches once before collapsing. The other golem is coming to life, however. You’ll have to be quick to get it in time!"],"tables":[{"cols":["Ref","Result"],"rows":[["e539","Successful COMBAT roll (Difficulty 9)"],["e647","Failed COMBAT roll"]]}]},{"tag":"e023","title":"Grave warning","desc":["As you stride forward, they look up with expressions of luminous rage.‘Get you back, mortal,’ warns one, ‘or I’ll touch you withmy grave-cold hands and then it’ll be your dying day!’"],"tables":[{"cols":["Ref","Option"],"rows":[["e479","Attack them"],["e520","Call on your god to banish them"]]}]},{"tag":"e024","title":"King subdual","desc":["You will need to subdue the king and his henchmen with aspell.Make a MAGIC roll at Difficulty 12."],"tables":[{"cols":["Ref","Result"],"rows":[["e644","Successful MAGIC roll (Difficulty 12)"],["e208","Failed MAGIC roll"]]}]},{"tag":"e025","title":"Audience with King Nergan","desc":["Captain Vorkung is impressed with your claims of loyalty to the rightful king. He decides you might be useful to their cause, and you are led, blindfolded, through a secret pass to a mountain stockade.","King Nergan gives you an audience in a makeshift throne room. He is a young, and handsome man, who seems committed to his country. He leads you aside, into a private chamber. ‘I have need of one such as you,’ he says. ‘Yellowport groans under the yoke of Governor Marloes Marlock, the brother of General Grieve Marlock. If you can get into the palace at Yellowport and assassinate Marloes, I will be eternally grateful.’ If you have the codeword Artery, turn to e399 immediately. Otherwise, if you wish to accept the mission to kill the Governor of Yellowport, record the codeword Ambuscade.","When you are ready, the King wishes you well, and you are led out of the stockade, and back down to the foothills of the Coldbleak Mountains. Turn to e474."]},{"tag":"e026","title":"Voyage to Dweomer","desc":["You set sail for Dweomer. The journey takes a few days but, amazingly, it is uneventful. The captain can’t believe his luck, as you disembark at Dweomer harbour, on the Sorcerers’ Isle. Turn to e100."]},{"tag":"e027","title":"Denied audience","desc":["Either you are recklessly brave, or very foolish to visit the palace where you assassinated the governor. Provost Marshal Royzer has established new security procedures, and it is impossible for you to see him. Return to e010."]},{"tag":"e028","title":"The horses vanish","desc":["You jump into the air, and hit the ground rolling. You come up, bruised but alive, in time to see the horses ride straight into the rocky wall of a low hill! To your amazement, they pass straight through the rock and disappear. Silence falls across the land like a blanket. There is no sign of them, not even tracks. You camp for the night and the next day set off once more."],"tables":[{"cols":["Ref","Option"],"rows":[["e560","North across country"],["e588","East to the road"],["e250","To Trefoille"],["e100","To Marlock City"],["e099","West towards the River Grimm"]]}]},{"tag":"e029","title":"Coastal voyage near Yellowport","desc":["Your ship is sailing in the coastal waters beside Yellowport. There are a number of other ships, mostly merchantmen, but there are also a few warships of the Sokaran Imperial Navy. ‘At least we won’t be plagued by pirates with the navy around,’ says the first mate.","Roll two dice."],"tables":[{"cols":["Ref","Result"],"rows":[["e613","Score 2–4: Storm"],["e439","Score 5–9: Uneventful voyage"],["e165","Score 10–12: Sokaran war galley"]]}]},{"tag":"e030","title":"Market of Yellowport","desc":["The market is large and busy. At the corner of Brimstone Plaza, gigantic braziers burn sweet-smelling incense in an attempt to overpower the rotten-egg smell that permeates the whole city. There are many stalls and goods to choose from. You may buy any of the items listed, as long as you have the money and the space to carry it. You may also sell any items you own that are listed below, for the price stated – if you do, don’t forget to cross them off your Adventure Sheet. Items with no purchase price are not available locally.","One trader is offering a treasure map for sale at 200 💎, and will buy any old treasure map for 150 💎. If you buy the map, note this paragraph number (30) for reference and turn to 200.","If you wish to buy cargo for a ship, you need to visit the warehouses at the harbourmaster. When you are ready to return to the city centre, turn to e010."],"tables":[{"cols":["Armour","Buy","Sell"],"rows":[["Leather (🛡️ +1)","50 💎","45 💎"],["Ring mail (🛡️ +2)","100 💎","90 💎"],["Chain mail (🛡️ +3)","200 💎","180 💎"],["Splint armour (🛡️ +4)","—","360 💎"],["Plate armour (🛡️ +5)","—","720 💎"],["Heavy plate (🛡️ +6)","—","1440 💎"]]},{"cols":["Weapon","Buy","Sell"],"rows":[["Without ⚔️ bonus","50 💎","40 💎"],["⚔️ bonus +1","250 💎","200 💎"],["⚔️ bonus +2","—","400 💎"],["⚔️ bonus +3","—","800 💎"]]},{"cols":["Magical Equipment","Buy","Sell"],"rows":[["Amber wand (MAGIC +1)","500 💎","400 💎"],["Ebony wand (MAGIC +2)","—","800 💎"],["Cobalt wand (MAGIC +3)","—","1600 💎"]]},{"cols":["Other items","Buy","Sell"],"rows":[["Mandolin (CHARISMA +1)","300 💎","270 💎"],["Lockpicks (THIEVERY +1)","300 💎","270 💎"],["Holy symbol (SANCTITY +1)","200 💎","100 💎"],["Compass (SCOUTING +1)","500 💎","450 💎"],["Rope","50 💎","45 💎"],["Lantern","100 💎","90 💎"],["Climbing gear","100 💎","90 💎"],["Bag of pearls","—","100 💎"],["Rat poison","60 💎","50 💎"],["Silver nugget","—","200 💎"]]}]},{"tag":"e031","title":"Rebirth at Blessed Springs","desc":["A dark emptiness surrounds you. Then, as if in your sleep, you see a tiny glimmer of light off in the distance. Suddenly you wake up, and find yourself coughing and spluttering, up to your neck in water. You look around – you are floundering in the holy waters of Blessed Springs.","Standing at the side of the pool is a tall, slim, moustached man who says ‘I am Aklar the Bold. I found you as bottled dust in the lair of Vayss the Sea Dragon. By sprinkling your ashes into the holy waters, I have brought you back to life. I think a reward is in order, don’t you?’ You explain that you have nothing to give. Aklar frowns in annoyance: ‘Blast, I knew I should have taken one of the other bottles! Well, you’ll just have to owe me a favour. A big favour.’. You can hardly refuse. Record the codeword Aklar. ‘Well, I must be about my business – we shall meet again, count on it.’ With that he leaves. You stagger out of the pool.","Turn to e510."]},{"tag":"e032","title":"Scorpion valley","desc":["You head across the hot, dusty and sparsely vegetated land. Vultures circle overhead – presumably they think you’re going to die. You wander on, until you come to a ridge. Down below, in a shallow valley, is a great mound of earth. Scorpion men crawl in and out of the many burrows that riddle the earth. The number of scorpion men in the valley makes your heart quail; unless you have the codeword Artefact, the place is too deadly to enter.","If you have the codeword Artefact, turn to e406. Otherwise, turn to e492."]},{"tag":"e033","title":"Resurrection at Temple of Tyrnai","desc":["Resurrection costs 200 💎 if you are an initiate, and 800 💎 if not. Once you have arranged for resurrection you need not fear death, as you will be magically restored to life here at the temple.","To arrange resurrection, pay the fee and write ‘Temple of Tyrnai, The War-Torn Kingdom 640’ in the Resurrection box on your Adventure Sheet. If you are later killed, turn to e640 in The War-Torn Kingdom.","You can have only one resurrection arranged at any one time. If you arrange another resurrection later at a different temple, the original one is cancelled. Cross it off your Adventure Sheet. You do not get a refund.","When you are finished here, turn to e282."]},{"tag":"e034","title":"Failed climb","desc":["You make it only 50 feet up the sheer rockface before you lose your footing and fall to the ground. Lose 4 ❤️ points. If you still live, turn to e658 where you can try again, if you like."]},{"tag":"e035","title":"Windswept cliff","desc":["You come to the top of a windswept cliff. An ancient pillar of jumbled rock, pitted and weatherbeaten, stands at the cliff’s edge, like a broken finger pointing at the sky. Seagulls sing their song of desolation in the air. Judging by the runes etched into the rock, the tor dates back to the time of the Shadar, a race that ruled Harkuna so long ago, they are lost in myth and legend."],"tables":[{"cols":["Ref","Option"],"rows":[["e515","Examine the runes"],["e097","Go down to the beach"],["e602","Take the road to Trefoille"],["e166","Take the road to Marlock City"]]}]},{"tag":"e036","title":"Lost in the forest","desc":["Soon you realize you are completely lost in this strange, magical forest. You wander around for days, barely able to find enough food and water. Lose 4 ❤️ points. If you still live, you eventually stagger out of the forest to the coast.","Turn to e128."]},{"tag":"e037","title":"Shark catch","desc":["Your men have been fishing with a net. This time, however, they have caught a large shark. Afterwards, when it has been cut open, you find the remains of some poor sailor. Inside his leather pouch, you find a bag of pearls, which you can take if you wish.","Turn to e507."]},{"tag":"e038","title":"Storm at sea","desc":["Heavy black clouds race towards you across the sky, whipping the waves into a frenzy. The crew mutter among themselves fearfully. If you have the blessing of Alvir and Valmir, which confers Safety from Storms, you can ignore the storm. Cross off the blessing and turn to e209.","Otherwise the storm hits with full fury. Roll one die if your ship is a barque, two dice if it is a brigantine, or three dice if a galleon. Add one to the roll if the crew’s quality is good; add 2 if it is excellent."],"tables":[{"cols":["Score","Result"],"rows":[["1–3","Ship sinks → e325"],["4–5","The mast splits → e397"],["6–20","You weather the storm → e209"]]}]},{"tag":"e039","title":"Wreck exploration","desc":["You and some of your crew clamber aboard the wreck. You find some dead sailors amid the wreckage. Their bodies are curiously bloated."],"tables":[{"cols":["Ref","Result"],"rows":[["e194","Successful SCOUTING roll (Difficulty 9)"],["e465","Failed SCOUTING roll (Difficulty 9)"]]}]},{"tag":"e040","title":"Reward at the Gold Dust Tavern","desc":["You take the Book of the Seven Sages to Pyletes the Sage at the Gold Dust Tavern. He thanks you effusively for bringing it to him. Your reward is secret learning from the temple of Molhern, god of knowledge. Add 1 to the ability of your choice. Also gain the title Illuminate of Molhern – write this in the Titles and Honours box on your Adventure Sheet. Lose the codeword Artefact and cross off the Book of the Seven Sages. Turn to e010."]},{"tag":"e041","title":"The Golden Net","desc":["The inside of the dome is lit with an eerie yellowish glow that comes from the sea-moss that carpets the ceiling. At the far end, a grotto in the wall contains an idol made from sea-shells and coral, presumably of Oannes, the god of the repulsive ones. At its feet lies the golden net of Alvir and Valmir, the object of your quest. Between you and it swim several of the giant squid-creatures, carrying out various undersea chores."],"tables":[{"cols":["Ref","Option"],"rows":[["e035","Swim back to the Shadar Tor"],["e121","Fight your way to the golden net"],["e592","Trust your magical prowess"],["e487","Rack your memory for a solution"]]}]},{"tag":"e042","title":"Ambush of ratmen","image":true,"desc":["Two hulking shapes appear out of the shadows as if from nowhere. They are hideous creatures – manlike, standing on two legs, but with the tail and hairy features of a gigantic rat. Their yellowing teeth snap at you as they lunge for you; the ratmen also wield wicked-looking shortswords in their hands. ‘Gut the human!’ yells one of them in a bestial voice. You must fight them, both at once, as if they were one opponent. If you have some rat poison, you can add 3 to your dice rolls. Cross the rat poison off the Adventure Sheet if you use it.","If you win, turn to e423. If you lose, turn to e308."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Two Ratmen","6","9","9"]]}]},{"tag":"e043","title":"Tomb guardian","image":true,"desc":["You must fight. Luckily, your MAGIC weapon will be effective.","If you win, turn to e490. If you lose, you are dead, unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Tomb Guardian","6","8","12"]]}]},{"tag":"e044","title":"Step aside","desc":["You decide that discretion would be the better part of valour in this case, and step aside. The officers laugh contemptuously, and swagger past. Nothing else happens tonight. Turn to e100."]},{"tag":"e045","title":"Ghoul attack","desc":["The little girl runs off before you can talk to her. You thread your way through the pitted tombstones and brooding crypts of the cemetery, under a pale moon that bathes the graveyard in a sickly, pallid light.","Suddenly, a foul stench fills your nostrils, and a figure rises up out of the shadows! Yellow eyes glow with feral blood-lust, and the creature sinks its black teeth into your arm before you can react. Lose 4 ❤️.","If you still live, you have been infected. You gain Disease (Ghoulbite). Until you find a cure, subtract 1 from your SANCTITY, ⚔️, and CHARISMA abilities (no ability can drop below 1). The ghoul, a rotting, walking corpse, lunges for you again."],"tables":[{"cols":["Ref","Option"],"rows":[["e617","Fight it"],["e144","Invoke the power of the gods"],["e303","Use salt and iron filings (if you have any)"]]}]},{"tag":"e046","title":"Guild investment","desc":["Lose the codewords Almanac, Brush and Eldritch if you have them. You can invest money in multiples of 100 💎. The guild will buy and sell commodities on your behalf using this money until you return to collect it. ‘Don’t forget that you can lose money as well,’ mutters a sullen merchant. Write the sum you are investing in the box here – or withdraw a sum invested previously. Then turn to e405."]},{"tag":"e047","title":"Forest of Larun","desc":["The Forest of Larun is a mighty swathe of densely packed trees, a slice of primordial nature in the middle of busy, industrious Sokara."],"tables":[{"cols":["Ref","Option"],"rows":[["e596","Venture deeper into the forest"],["e110","North to the Bronze Hills"],["e333","West to the River Grimm"],["e560","South into the countryside"],["e387","East to the road"]]}]},{"tag":"e048","title":"Ghoul problem in the crypt","desc":["The warden is in charge of security. ‘We have had an unfortunate, umm… accident,’ he says worriedly. ‘In the crypt below the temple we sometimes experiment with the corpses of the dead – you know, the occasional zombie, part of the rituals in honour of the particular aspect of Nagil we revere here. It seems a ghoul has escaped from these pits, and is terrorizing the city at night. We’d rather someone like you sorted the problem out before the city militia got to hear of it. Destroy it and bring me the ghoul’s head.’","If you want to take up the mission, record the codeword Ague. ‘Search for it at night!’ says the warden as you leave.","Turn to e100."]},{"tag":"e049","title":"Ambushed on the rocks","desc":["Not taking any chances, you charge the soldier, yelling a war cry. He starts back in astonishment. Just then, several archers pop up from behind the rocks above, and let loose a volley of arrows. One takes you in the leg. Lose 3 ❤️ points.","If you still live, you fall to one knee, and the soldier melts away into the rocks. Alone, and wounded in the leg, you cannot climb upwards. You have to go back down though the descent will be difficult with a dodgy leg.","Roll a die, adding 1 if you have some climbing gear."],"tables":[{"cols":["Ref","Score"],"rows":[["e529","1–3"],["e474","4–6"]]}]},{"tag":"e050","title":"Provost Marshal Royzer","desc":["The new provost marshal of Yellowport is Royzer – he used to be Marloes Marlock’s second in command. Since the assassination of the old provost, Royzer has ruled the city with an iron hand – patrols are frequent and spies are everywhere. You will have to be careful not to get yourself recognised. Turn back to e010 and choose an option from the list there."]},{"tag":"e051","title":"Boarding action at sea","desc":["The war galley puts alongside, and grappling hooks fly through the air, fastening your ships together. The captain leaps across and his men swarm on to your ship. A battle ensues. Roll three dice if you are a Warrior, or two dice if you belong to any other profession. Add your Rank to this roll. Then, if your crew is poor quality, subtract 2 from the total. If the crew quality is good, add 2. If the crew quality is excellent, add 3."],"tables":[{"cols":["Ref","Outcome"],"rows":[["e680","0–4 Calamity; you are killed"],["e153","5–9 Crushing defeat; lose 1–6 ❤️"],["e242","10–13 A draw"],["e625","14+ Outright victory"]]}]},{"tag":"e052","title":"Blessing of Lacuna","desc":["If you are an initiate it costs only 10 💎 to purchase Lacuna’s blessing. A non-initiate must pay 25 💎. Cross off the money and mark SCOUTING in the Blessings box on your Adventure Sheet.","The blessing works by allowing you to try again when you fail a SCOUTING roll. It is good for only one reroll. When you use the blessing, cross it off your Adventure Sheet. You can only have one SCOUTING blessing at any one time. Once it is used up, you can return to any branch of the Temple of Lacuna to buy a new one.","When you are finished here, turn to e544."]},{"tag":"e053","title":"Ink sac and coral jewellery","desc":["The creature bursts open in death, spilling a black inky cloud into the water. The sac in which this ink is kept falls free from its body. You can take the ink sac if you wish – note it on your Adventure Sheet. You also find coral jewellery worth about 15 💎. Nothing else occurs during your foray into the depths, so you return to land. You climb back up the path that leads to the clifftop tor without incident."],"tables":[{"cols":["Ref","Option"],"rows":[["e602","Take the road to Trefoille"],["e166","Take the road to Marlock City"]]}]},{"tag":"e054","title":"Freeing Sul Veneris","desc":["You drive back the storm demons long enough for you to work free one of the stakes that is holding Sul Veneris down.","Turn to e365."]},{"tag":"e055","title":"Cannibal cult ambush","image":true,"desc":["You remember that this is a trap set up by the cannibal cultists of Badogor. While one pretends to be hurt, two others skulk in the shadows, waiting to ambush the curious. Forewarned you are able to take them by surprise. You cut one down in seconds and the figure on the ground runs off with a shriek of terror. The third cultist, however, turns to fight you.","If you win, you find a bag of pearls on his body. Turn to e010."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Cultist","3","5","7"]]}]},{"tag":"e056","title":"Strange metal craft","desc":["A strange-looking craft is bobbing in the water. It is shaped like a cone, floating on its base, and as you draw nearer, you realize it is made entirely of metal! Its sail, a huge piece of cloth, seems to have collapsed and is spread out around it, on the surface of the sea. Great blue and white letters, in some foreign script, are painted on its side. You notice an opening on one side."],"tables":[{"cols":["Ref","Option"],"rows":[["e496","Enter the strange craft"],["e855","Leave it and sail on"]]}]},{"tag":"e057","title":"Escape through Yellowport streets","desc":["You manage to lose them amid the backstreets of Yellowport. Once the heat is off, you return to the city centre.","Turn to e010."]},{"tag":"e058","title":"Eyepatch ambush","desc":["He doesn’t notice you hiding in the shadowy doorway of a nearby derelict house. As he passes, you step out and attack, taking him completely by surprise. He goes down with your first blow. Searching him, you find 25 💎, which you can take if you wish. Then you flip up his eyepatch. Nestling in the eye socket is a sparkling gem, a flame opal. You pluck it free. Note the flame opal eye on your Adventure Sheet and delete the codeword Barnacle. Quickly, you haul the body into the shadows and head for the city centre.","Turn to e400."]},{"tag":"e059","title":"Hidden room in the bookcase","desc":["Your deft fingers find a false spine of carved wood among the titles in the bookcase. Pressing it, you hear a click and the bookcase swings out from the wall. Beyond lies a hidden room where you find a verdigris key. Note this on your Adventure Sheet if you decide to take it."],"tables":[{"cols":["Ref","Option"],"rows":[["e010","Leave at once"],["e386","Go upstairs to find Lauria"],["e534","Wait for her to return"]]}]},{"tag":"e060","title":"Wild country encounter","image":true,"desc":["You are crossing the wild country of north-east Sokara. Roll one die."],"tables":[{"cols":["Score","Result"],"rows":[["1–2","Caught in an animal trap! Lose 2 ❤️"],["3–4","Nothing happens"],["5–6","Attacked by a wolf, must fight. If you win, you get a wolf pelt."]]},{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Wolf","3","5","7"]]},{"cols":["Ref","Option"],"rows":[["e518","North"],["e458","South"],["e201","West"]]}]},{"tag":"e061","title":"Cult of Badogor initiation","desc":["‘Wait,’ you cry, ‘I have seen the light! I wish to join your cult!’ ‘What!’ yells the chef. Then his shoulders sag in resignation. ‘We cannot refuse a new member,’ says the leader with obvious disappointment. ‘And we cannot eat our own people,’ he adds sadly.","A short ceremony later – fortunately, the initiation does not involve any cannibalistic rites – and you are a full member of the Cult of Badogor. Write Unspeakable Cultist in the Titles and Honours box on your Adventure Sheet. You lose 1 point of SANCTITY permanently for joining such a vile cult.","You take your leave, and they wish you well, all smiles and friendship. ‘Remember, never say his name! And don’t forget to bring us new recruits,’ says the leader. ‘And some people for dinner!’ adds the chef. Hastily, you head for the city centre.","Turn to e010."]},{"tag":"e062","title":"Sokaran surrender","desc":["The Sokarans surrender. Their captain has been killed in the battle, and his marines have had the fight knocked out of them. The war galley isn’t carrying any cargo, but you find an officer’s pass on the body of the captain, and a chest in his cabin, which contains 150 💎. You have to hand out 50 💎 to your crew, but you can add 100 💎 to your Adventure Sheet. You leave the galley to limp back to Yellowport while you sail on.","Turn to e439."]},{"tag":"e063","title":"The Gob-gobbler plea","desc":["If you have the codeword Attar, turn to e578 immediately. If not, read on. A small boy runs up to you, saying ‘Help us, help us! The Man-eating Blood-Thursday Gob-gobbler has got my little sister!’ His mother, a flaxen-haired beauty, comes up behind him. ‘Surely, you mean blood-thirsty not Thursday,’ you ask. ‘Oh no,’ replies the young mother, ‘the Man-eating Blood-Thursday Gob-gobbler is so named because it hunts only on Thursdays!’ The boy’s name is Mikail, and his mother is Lynn. Her husband is away in the army, and her young daughter, Haylie, was taken by the beast last Thursday. Apparently, several people have disappeared, never to be seen again. ‘Please, help us!’ plead the villagers."],"tables":[{"cols":["Ref","Option"],"rows":[["e600","Help them"],["e427","Refuse to help"]]}]},{"tag":"e064","title":"Exploding chest trap","desc":["Your amateurish tinkering sets the trap off, and the chest explodes! You take the full force of the blast – lose 5 ❤️ points. If you are still alive, you also find that the contents of the chest have been vaporized – except for a sturdy metal scroll case, containing a piece of ancient religious text about the gods of Uttaku. You discover from the scroll that one of the gods of the Uttakin is called Ebron, and that he has fourteen angles. Note the scroll of Ebron on your Adventure Sheet if you wish to take it.","Turn to e010."]},{"tag":"e065","title":"Stone gates of the island","desc":["There are three stone gates engraved with ancient runes. Each gate is marked with a name – Yellowport, Marlock City, and Wishport. From here, you can see the coast and the whole island, which is heavily forested."],"tables":[{"cols":["Ref","Option"],"rows":[["e128","Explore the coastline"],["e257","Head into the forest"],["e008","Step through the Yellowport arch"],["e180","Step through the Marlock City arch"],["e330","Step through the Wishport arch"]]}]},{"tag":"e066","title":"Ghostly horse charge","desc":["You stand your ground. The ghostly horses stream past you on either side, neighing wildly at the sky. Nimbly, you leap at one, and manage to wrap your arms around its neck, and swing on to its back. The horse feels quite solid, but appears to be a luminous, pale-green colour. You look up through a cloud of sparks emanating from the horse’s mane just in time to see a rocky wall of a low hill looming up out of the evening mist. Your horse is galloping full tilt right into it!"],"tables":[{"cols":["Ref","Option"],"rows":[["e017","Hold on"],["e028","Leap off"]]}]},{"tag":"e067","title":"Lost at sea","desc":["Your ship is thrown about like flotsam and jetsam. When the storm subsides, you take stock. Much has been swept overboard – you lose 1 Cargo Unit, if you had any, of your choice. Also, the ship has been swept way off course and the mate has no idea where you are. ‘We’re lost at sea, Cap’n!’ he moans.","Turn to e090."]},{"tag":"e068","title":"Renouncing Alvir and Valmir","desc":["To renounce the worship of Alvir and Valmir, you must pay 30 💎 in compensation to the priesthood. The priest simply points to a ship limping into harbour – its shattered masts, torn sails and battered hull mute testimony to its storm-tossed voyage. ‘The captain did not revere the Twin Gods,’ whispers the coral-jewelled priest darkly. Do you want to change your mind? If you are determined to renounce your faith, pay the 30 💎 and delete Alvir and Valmir from the God box on your Adventure Sheet.","Turn to e154."]},{"tag":"e069","title":"Renouncing Tyrnai","desc":["To renounce the worship of Tyrnai, you must pay 50 💎 to the warrior priests, and suffer the Ceremony of the Wrathful Blow. A priest will strike you once – it is better to be struck by a priest than by Tyrnai himself! If you are determined to renounce your initiate status, pay the 50 💎, delete Tyrnai from the God box on your Adventure Sheet. The High Priest smashes you across the jaw, saying ‘I’m doing you a favour – believe me!’ Lose 1 ❤️ point. If you earlier arranged a resurrection here, it is cancelled with no refund.","When you are finished, turn to e526."]},{"tag":"e070","title":"Lost at sea","desc":["Your ship is thrown about like flotsam and jetsam. When the storm subsides, you take stock. Much has been swept overboard – you lose 1 Cargo Unit, if you had any, of your choice. Also, the ship has been swept way off course and the mate has no idea where you are. ‘We’re lost at sea, Cap’n!’ he moans.","Turn to e090."]},{"tag":"e071","title":"Temple of Nagil","desc":["If you have the codeword Ague, turn to e517 immediately. If not, read on. Nagil is the Lord of the Lands of the Dead, and his temple in Marlock City is covered in friezes and gargoyles of ornate design, depicting the souls of the dead on their journey to the underworld. Inside, it is cool and dark, hung with black velvet drapes. A scroll tacked to the wall reads: ‘Wanted: person of unusual resourcefulness. See temple warden.’"],"tables":[{"cols":["Ref","Option"],"rows":[["e409","Become an initiate"],["e187","Renounce worship"],["e478","Make resurrection arrangements"],["e048","Visit the warden"],["e100","Leave the temple"]]}]},{"tag":"e072","title":"Resisting the gas","desc":["You manage to shrug off the effects of the gas."],"tables":[{"cols":["Ref","Option"],"rows":[["e371","Attack the beast"],["e052","Run off"]]}]},{"tag":"e073","title":"Blessing of Elnir","desc":["If you are an initiate it costs only 10 💎 to purchase Elnir’s blessing. A non-initiate must pay 25 💎. Cross off the money and mark CHARISMA in the Blessings box on your Adventure Sheet. The blessing works by allowing you to try again when you make a failed CHARISMA roll. It is only good for one reroll. When you use the blessing, cross it off your Adventure Sheet. You can have only one CHARISMA blessing at any one time. Once it is used up, you can return to any branch of the temple of Elnir to buy a new one.","When you are finished here, turn to e568."]},{"tag":"e074","title":"Passage to Yellowport","desc":["A fisherman will take you all the way to Yellowport for 15 💎. Cross the money off your Adventure Sheet. Amazingly, despite the apparent fragility of the small vessel, you arrive without incident.","Turn to e010."]},{"tag":"e075","title":"Temple of Sig Mission","desc":["The high priest takes you to a private chamber. ‘You may be just what the temple needs,’ he says, ‘a good, old-fashioned thief! There is a suit of armour made entirely of gold – ceremonial only of course. Nevertheless, we would like to, er, have it donated to us.’ ‘I see,’ you reply, ‘and where is the armour?’ ‘Well that’s the tricky part – it’s in the Temple of Tyrnai, in Caran Baru. In fact, it’s worn by the idol of Tyrnai himself in the temple! Can you bring us the gold chain mail of Tyrnai? In return, we will instruct you in the roguish arts.’ If you want to take up the mission for the Temple of Sig, record the codeword Armour.","Turn to e235."]},{"tag":"e076","title":"Street Brawl Victory","desc":["You are an accomplished street brawler, and after only a few minutes’ furious fighting, the three officers are laid out unconscious in the street. Several people gathered to watch the brawl – most of them give a cheer at your performance. General Marlock’s troops have not endeared themselves to the population. You find about 25 💎 on the officers’ bodies and an officer’s pass.","Take whatever you require and turn to e100."]},{"tag":"e077","title":"Cure at Temple of Maka","desc":["‘It is fortunate we have a Chosen One of Maka at this temple,’ says the high priestess. ‘Only the Chosen Ones have the goddess-given powers to cure the afflicted!’ It costs 75 💎 – only 30 if you are an initiate of Maka – to be cured of a poison or a disease. Make any necessary payment and delete the disease or poison, and its effects, from your Adventure Sheet.","Turn to e141."]},{"tag":"e078","title":"SCOUTING Test","desc":["Make a SCOUTING roll at Difficulty 10."],"tables":[{"cols":["Ref","Option"],"rows":[["e524","Successful SCOUTING roll"],["e415","Failed SCOUTING roll"]]}]},{"tag":"e079","title":"Escape the Tunnels","desc":["Make a SCOUTING roll at Difficulty 14, as you try to lose them in the tunnels. It is hard because they know the layout better than you do."],"tables":[{"cols":["Ref","Option"],"rows":[["e224","Successful SCOUTING roll"],["e003","Failed SCOUTING roll"]]}]},{"tag":"e080","title":"Pickpocket Encounter","desc":["You grab the woman’s wrist a split-second before she can cut the strings of your money pouch. You drag her around to face you, but she meets your outraged scowl with a swashbuckling grin. ‘You’ve got good reflexes,’ she says. ‘Most of the street scum around here are too drink-sodden or dimwitted to notice the loss of a few Shards. Want to earn some real money?’"],"tables":[{"cols":["Ref","Option"],"rows":[["e425","Accept her offer"],["e108","Refuse and leave"]]}]},{"tag":"e081","title":"Golem Fight","image":true,"desc":["This could be a tough fight."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Golem","5","10","10"]]},{"cols":["Ref","Option"],"rows":[["e094","If you win"],["e488","If you lose"]]}]},{"tag":"e082","title":"Stinking River","desc":["You are following the course of the Stinking River – and it certainly does stink, laden with sulphur as it is. Roll a die. Score 1 or 2: Stung by a large golden insect. You are poisoned (⚔️ –1 until you find a cure). Score 3 or 4: Nothing happens. Score 5 or 6: Catch a smoulder fish. Note it on your Adventure Sheet."],"tables":[{"cols":["Ref","Option"],"rows":[["e310","Follow the river north"],["e010","Follow the river south to Yellowport"],["e558","Go west to the road"],["e278","Go east into the countryside"]]}]},{"tag":"e083","title":"Lost at Sea","desc":["Your ship is thrown about like flotsam and jetsam. When the storm subsides, you take stock. Much has been swept overboard - you lose 1 Cargo Unit, if you had any, of your choice. Also, the ship has been swept way off course and the mate has no idea where you are. ‘We’re lost at sea, Cap’n!’ he moans.","Turn to e090."]},{"tag":"e084","title":"At the Harbour","desc":["Your ship awaits you in the harbour. The crew are in good spirits, as ever when a new voyage is about to begin."],"tables":[{"cols":["Ref","Option"],"rows":[["e142","Go ashore"],["e222","Set sail"]]}]},{"tag":"e085","title":"Scorpion Bight","desc":["You are sailing around Scorpion Bight."],"tables":[{"cols":["Ref","Option"],"rows":[["e190","Sail north along the coast"],["e029","Sail west towards Yellowport"],["e136","Sail east into the Sea of Whispers"],["e416","Sail south into the Violet Ocean"],["e176","Go ashore at Scorpion Bight"]]}]},{"tag":"e086","title":"Temple of the Three Fortunes","desc":["The temple of the Three Fortunes is a squat, square building. A frieze above the door depicts three woman weaving a tapestry. ‘That’s the Tapestry of Fate, where our destiny is woven,’ comments a priest."],"tables":[{"cols":["Ref","Option"],"rows":[["e258","Become an initiate"],["e573","Renounce worship"],["e603","Seek a blessing"]]}]},{"tag":"e087","title":"Road to Blessed Springs","image":true,"desc":["You are on the road between Blessed Springs and Venefax. Pilgrims, the sick and injured travel this route to the holy waters of Blessed Springs to find salvation. Roll a die. Score 1 or 2: Attacked by a mad pilgrim. You must fight. If you win, you get his staff. Score 3 or 4: Nothing happens. Score 5 or 6: Blessed by a priest. Write Safety from Storms in the Blessings box on your Adventure Sheet."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Pilgrim","3","5","6"]]},{"cols":["Ref","Option"],"rows":[["e510","Go to Blessed Springs"],["e427","Go to Venefax"],["e548","Go north into the countryside"]]}]},{"tag":"e088","title":"Investments Outcome","desc":["To find out how well your investments have done, roll two dice. Add 1 to the dice roll if you are an initiate of the Three Fortunes. Also add 1 if you have the codeword Almanac, add 2 if you have the codeword Brush, and add 3 if you have the codeword Eldritch. Score 2-4: Lose entire sum invested. Score 5-6: Loss of 50%. Score 7-8: Loss of 10%. Score 9-10: Investment remains unchanged. Score 11-12: Profit of 10%. Score 13-14: Profit of 50%. Score 15-16: Double initial investment. Score 17+: Triple initial investment.","Now turn to e104, where you can withdraw or leave the sum written in the box there after adjusting it according to the result rolled."]},{"tag":"e089","title":"Curse of the Undead Pirate","desc":["The undead pirate reaches for you, but it is too slow. Then it speaks, its voice seeming to sound inside your head. ‘Damn you, and your kind, thieving sea centaur! I curse you forever – may you never swim again in the seas you love. You will walk for the rest of your life as a human, doomed to wander the surface world, unable to find the peace of coral caves!’","Quickly, you swim away, unable to believe your luck! What a convenient curse. You find yourself already changing back to a human, and you make it to your ship, coughing and spluttering. Your crew haul you aboard. The gems are worth 300 💎 – add that much to your money. You sail on, lucky to be still human.","Turn to e507."]},{"tag":"e090","title":"Lost at Sea Navigation","desc":["Your ship is limping through unknown waters. The sun beats down, and the wind drops to a whisper. ‘What direction, Cap’n?’ asks the bosun.","Make a SCOUTING roll at Difficulty 10."],"tables":[{"cols":["Ref","Option"],"rows":[["e633","Successful SCOUTING roll"],["e004","Failed SCOUTING roll"]]}]},{"tag":"e091","title":"Gambler’s Den","desc":["He smiles and takes you into the Gambler’s Den. It is a smoke-filled casino, full of all kinds of dubious characters, playing cards and dice. If you want to gamble, decide how much you want to bet, to a maximum of 20 💎, and roll two dice. Score 2: win five times your bet. Score 3-4: win twice your bet. Score 5-9: lose your bet. Score 10-11: win twice your bet. Score 12: win five times your bet.","When you are ready to leave, put a tick in the box and turn to e109, unless the box is already ticked, in which case turn to e100."]},{"tag":"e092","title":"Flame Opal","desc":["He falls dead at your feet. Searching him, you find 25 💎 you can take if you wish. Then you flip up his eyepatch. Nestling in the eye-socket is a sparkling gem, a flame opal. You pluck it free. Note the flame opal eye on your Adventure Sheet and lose the codeword Barnacle. You hurry off, before a patrol arrives.","Turn to e400."]},{"tag":"e093","title":"Mad Beggar","desc":["If you have the codeword Azure, turn to e359 immediately. If not, read on. A mad beggar, covered in sores and grime, accosts you in the street. ‘O noble one, aid me for the love of the gods!’ he rants, frothing at the mouth and gesticulating wildly. ‘I need coins to eat, food to spend, and blessings to wear!’"],"tables":[{"cols":["Ref","Option"],"rows":[["e010","Ignore him and return to city centre"],["e227","Give him 5 💎"],["e632","Bless him"]]}]},{"tag":"e094","title":"Temple Theft","desc":["At last, the golem is defeated. You manage to get into the temple without being noticed by anyone else. Inside, it is cool and dark, filled with an unearthly stillness. You reach forward to strip the armour off the idol of Tyrnai.","Make a THIEVERY roll at Difficulty 12."],"tables":[{"cols":["Ref","Option"],"rows":[["e509","Successful THIEVERY roll"],["e228","Failed THIEVERY roll"]]}]},{"tag":"e095","title":"No More Missions","desc":["You are greeted warmly and politely by the provost marshal who treats you as one of his own. However, there are no more missions, and after thanking you once again, he politely sends you on your way.","Return to e010."]},{"tag":"e096","title":"Militia Fight","image":true,"desc":["One of the militiamen kicks over a table, blocking your escape. You set your back to a corner of the room and grimly prepare to fight for your life. Fight them one at a time:"],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["First Militiaman","4","7","5"],["Second Militiaman","4","7","4"],["Third Militiaman","4","7","5"]]},{"cols":["Ref","Option"],"rows":[["e432","If you win"],["e218","If you surrender"]]}]},{"tag":"e097","title":"Song of the Sea","desc":["You climb down a narrow track to the beach. The sea pounds the rocky shore, and the spray lashes your face. A mournful, yet utterly captivating singing suddenly fills your ears. You look out to sea, and spot several mermaids and mermen, cavorting in the surf. ‘Come, come to us…’ one of them calls in a lilting voice that fills you with a yearning desire to plunge into the sea and swim out to them.","Make a SANCTITY roll at Difficulty 10."],"tables":[{"cols":["Ref","Option"],"rows":[["e584","Successful SANCTITY roll"],["e159","Failed SANCTITY roll"]]}]},{"tag":"e098","title":"Raiders in the Mountains","desc":["The soldier recognizes you and bows. ‘My lord,’ he says, ‘We are a small group now, left here to act as raiders behind enemy lines. Thanks to your heroic actions, the Citadel of Velis Corin is now ours – the king has moved his court there. Go to the citadel if you would speak with the king.’ There is nothing else of interest in the mountains, so you return to the foothills.","Turn to e474."]},{"tag":"e099","title":"River Grimm","desc":["You are on the east bank of the River Grimm, a great, powerful river, which rushes past towards the sea. You can travel to Golnir from here."],"tables":[{"cols":["Ref","Option"],"rows":[["e168","Cross the bridge to Conflass (Cities of Gold and Glory)"],["e306","Ford the river to the south (Cities of Gold and Glory)"],["e333","Follow the river north"],["e175","Head for the Curstmoor"],["e560","Head towards Devil’s Peak"],["e579","Go south to the mouth of the river"],["e100","Go to Marlock City"]]}]},{"tag":"e100","title":"Marlock City","desc":["Marlock City is a huge sprawling metropolis, enclosed in a fortified wall said to have been built one thousand years ago by the ancient Shadar Empire. It is the capital city of Sokara. Marlock City was once known as Sokar, until General Grieve Marlock led the army in bloody revolt against the old king, Corin VII, and had him executed. The general renamed the city after himself – it is now a crime to call it Sokar.","The general lives in the old king’s palace, and calls himself the Protector-General of all Sokara. Whereas the old king was corrupt, the general rules with a fist of iron. Some people like the new regime; others are royalists, still loyal to Nergan, the heir to the throne, who has gone into hiding somewhere.","Outside the city gates hang the bodies of many dead people – labels around their necks read: ‘Rebels, executed by the state for the good of the people’. ‘You’d best behave yourself if you don’t want to end up like one of them,’ grates a guardsman, nodding towards the swinging corpses, as you pass through the great eagle-headed gates of Marlock City.","You can buy a town house in Marlock City for 200 💎. Owning a house gives you a place to rest, and to store equipment. If you buy one, cross off 200 💎 and tick the box by the town house option. To leave Marlock City by sea, or to buy or sell ships and cargo, go the harbourmaster."],"tables":[{"cols":["Ref","Option"],"rows":[["e158","Visit the Three Rings Tavern"],["e154","Visit the temple of Alvir and Valmir"],["e071","Visit the temple of Nagil"],["e235","Visit the temple of Sig"],["e568","Visit the temple of Elnir"],["e396","Visit the market"],["e142","Visit the harbourmaster"],["e571","Go to the merchants’ guild"],["e138","Explore the city"],["e434","Visit your town house (if box ticked)"],["e535","Visit the House of Priests"],["e601","Visit the general’s palace"],["e377","Travel east towards Trefoille"],["e166","Head south-east towards the Shadar Tor"],["e099","Follow the River Grimm north"],["e175","Journey north into the Curstmoor"],["e579","Head west to the River Grimm delta"]]}]}]`),p=JSON.parse(`[{"tag":"e101","title":"Cult Escape","desc":["You yell the name of their god again and again. The cultists clap their hands over their ears, hopping about in horror. ‘Aargh!’ howls the leader. ‘Stop your blaspheming, you heathen devil!’ In their confusion, you make it to your equipment. Now you can fight your way out.","Make a COMBAT roll of Difficulty 13. If you fail, turn to e204.","If you succeed, you manage to fight your way to freedom with the loss of 4 ❤️ points and head back to town, turn to e010."]},{"tag":"e102","title":"General’s Orders","desc":["If you have the codeword Defend, turn to e655 immediately. If not, read on. ‘What are you doing back here,’ asks Grieve Marlock, angrily. ‘You should be defending the citadel! You know, that castle in the Pass of Eagles, up north! Get back there and talk to Orin Telana!’","If you have a coded missive, turn to e677. Otherwise, you are shown out in short order. Turn to e100."]},{"tag":"e103","title":"Copper Island Voyage","desc":["You set sail for Copper Island. The uneventful journey takes only a few days. The captain cannot believe how smooth the voyage has been. You disembark at the harbour of Copper Island.","Turn to e099 in Over the Blood-Dark Sea."]},{"tag":"e104","title":"Investments","desc":["Lose the codewords Almanac, Brush and Eldritch if you have them. You can invest money in multiples of 100 💎. The guild will sell and buy commodities on your behalf using this money until you return to collect it. ‘Don’t forget that you can lose money as well,’ mutters a sullen merchant who leaves the guild penniless. Write the sum you are investing in the box here – or withdraw a sum invested previously.","Then turn back to e571."]},{"tag":"e105","title":"Scorpion Shaman","image":true,"desc":["You will have to fight it. If you win, turn to e532.","If you lose, your adventures are over unless you have a resurrection dead."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Scorpion Shaman","5","8","9"]]}]},{"tag":"e106","title":"Pearl Deal","desc":["Cross off the money. The young man smiles ingratiatingly, and hands you the pearls.","Make a MAGIC roll at a Difficulty of 10."],"tables":[{"cols":["Ref","Option"],"rows":[["e306","Successful MAGIC roll"],["e489","Failed MAGIC roll"]]}]},{"tag":"e107","title":"Tyrnai’s Blessing","desc":["If you are an initiate it costs only 10 💎 to purchase Tyrnai’s blessing. A non-initiate must pay 25 💎. Cross off the money and mark ⚔️ in the Blessings box on your Adventure Sheet. The blessing works by allowing you to try again when you fail a COMBAT roll. It is good for only one reroll. When you use the blessing, cross it off your Adventure Sheet. You can only have one ⚔️ blessing at any one time. Once it is used up, you can return to any branch of the temple of Tyrnai to buy a new one.","When you are finished, turn to e282."]},{"tag":"e108","title":"Undersea Dream","desc":["That night, your sleep is restless. You dream a most vivid dream. You are attacked by a gigantic sea monster, a mighty octopoid thing that encircles the ship with tree-like tentacles and pulls it under the waves. You sink into the bottle-green depths until you are caught in a glowing golden net. You wake in an undersea palace of multi-coloured coral, with mermaids to attend you. They lead you past trident-armed merman guards into a great hall. Seated upon two giant shells, like thrones, are the king and queen of the deep, with green hair, sea-grey eyes, and crowns of pale gold. Shoals of iridescent angel fish dart about in an intricate flashing dance of colour, dancing for the rulers of the land beneath the waves. In awe, you bow before them. The queen indicates that you should entertain them, for they are bored! A silver flute appears in your hands.","Make a CHARISMA roll at Difficulty 11."],"tables":[{"cols":["Ref","Option"],"rows":[["e132","Successful CHARISMA roll"],["e457","Failed CHARISMA roll"]]}]},{"tag":"e109","title":"Gambler Watch","desc":["You are about to leave when you see a crowd gathered around a slim pasty-faced scholar at a card table. ‘By the Three Fortunes, but I’m hot tonight!’ he cries. It seems he is on a winning streak.","You notice a couple of dodgy-looking ruffians watching the scholar carefully."],"tables":[{"cols":["Ref","Option"],"rows":[["e540","Wait and follow the scholar"],["e100","Return to the city centre"]]}]},{"tag":"e110","title":"Bronze Hills Mine","desc":["You are walking through Bronze Hills. Virtually the whole area has been given over to mining. Everywhere, quarries and mineshafts abound. It is a horrible expanse of torn-up earth – hardly any areas of green are left. Great heaps of excavated rock, leeched of their useful minerals, mar the landscape. You find a quarry that is open to the public.","That is to say, if you pay 50 💎, you can dig for an hour in a silver mine."],"tables":[{"cols":["Ref","Option"],"rows":[["e668","Pay 50 💎 and mine for silver"],["e400","Go to Caran Baru"],["e047","South into the Forest of Larun"],["e333","West to the River Grimm"],["e276","North-west to the Western Wilderness"]]}]},{"tag":"e111","title":"Arcane Limits","desc":["Your knowledge of the arcane arts is too limited to help you here."],"tables":[{"cols":["Ref","Option"],"rows":[["e121","Fight your way to the golden net"],["e035","Swim back to Shadar Tor"]]}]},{"tag":"e112","title":"Merchants’ Guild (Caran Baru)","desc":["The merchants’ guild is comparatively small here. Most of its work involves financial services for the army. Here you can bank your money for safe-keeping, but there are no facilities for investment.","You can deposit or withdraw money – note that you are in Caran Baru and turn to e605 – or return to the town centre, turn to e400."]},{"tag":"e113","title":"Audience at the Temple","desc":["If you have the codeword Armour, turn to e550 immediately. If not, but you are a Rogue, turn to e075. Otherwise, the high priest has little to say to you; your audience is cut short.","Turn to e235."]},{"tag":"e114","title":"Grateful Administrator","desc":["You are known as the priest who outwitted the storm demons to save Sul Veneris. You are shown in to see the chief administrator, who welcomes you freely. He can heal you of all lost ❤️ points and cure you of a disease or poison free of charge. He cannot, however, lift a curse. ‘Whenever you need help, come to me!’ he says.","When you are ready, turn to e100."]},{"tag":"e115","title":"Ghoul Hunt","desc":["If you are on a quest for the temple of Nagil, to bring them the head of an escaped ghoul, turn to e446.","If you do not want to look for the ghoul yet, or have already done so, turn to e226."]},{"tag":"e116","title":"Repulsive Ones","desc":["Put a tick in the box. If there is one there already, turn to e322 immediately. Otherwise read on. You realize the creature is one of the legendary repulsive ones.","It is swimming past you, intent on its own business, so you follow it, in the hope it will lead you to the sunken city of Ziusudra.","Turn to e547."]},{"tag":"e117","title":"Eyepatch Hunt","desc":["There are several people with eyepatches but none with a velvet one. You ask around among the taverns and bars of the rougher areas in Caran Baru.","Make a CHARISMA roll at Difficulty 11."],"tables":[{"cols":["Ref","Option"],"rows":[["e149","Successful CHARISMA roll"],["e468","Failed CHARISMA roll"]]}]},{"tag":"e118","title":"Bronze Hills Mines","desc":["The overseer of the mines is a fat, cruel-looking man. He welcomes you with a promise, ‘In one month, you’ll be dead, slave.’ You spend the next few weeks in chains, working 15 hours a day, deep underground, digging at a rock face in the tunnels of the mines in the Bronze Hills. You are fed on gruel and black bread.","You realize you will not live long down here and that you must escape if you are to survive.","If you have the codeword Ashen, turn to e351. Otherwise turn to e565."]},{"tag":"e119","title":"House Ambush and Betrayal","desc":["Gain the codeword Ashen. You hear the shouts from outside, muffled by the swirling sulphurous fog. A stab of icy panic pulses at your heart, and an instant later the door bursts open. Three militiamen armed with maces burst through the doorway. Behind them, a tall cadaverous gentleman wrapped in a cape is stamping in fury. ‘A thief in my house!’ he rages. ‘Do your duty!’ You realize the truth: Lauria has used you as a decoy to cover her escape. You’ll get even later – if you survive. The militiamen race forward to seize you.","Make a COMBAT roll at a Difficulty of 12."],"tables":[{"cols":["Ref","Option"],"rows":[["e588","Successful COMBAT roll"],["e096","Failed COMBAT roll"]]}]},{"tag":"e120","title":"Shadar Tor Coastal Waters","desc":["You ship is sailing in the coastal waters off the Shadar Tor. You can just see the tor, a jumbled mass of rocks, sitting on the clifftops as it has done for a thousand years.","Roll two dice:"],"tables":[{"cols":["Ref","Score","Result"],"rows":[["e324","2-4","Storm"],["e559","5-9","An uneventful voyage"],["e207","10-12","A merchant ship"]]}]},{"tag":"e121","title":"Underwater COMBAT at the Repulsive Ones","image":true,"desc":["You wait outside, hoping to take the repulsive ones singly as they emerge. You will have to fight the three of them, but you may do so one at a time.","Subtract 1 from your dice rolls for every fight because you are unused to underwater COMBAT.","If you beat all three, turn to e213. If you lose, your adventuring days are over, unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["First Repulsive One","4","6","10"],["Second Repulsive One","3","5","10"],["Third Repulsive One","4","6","10"]]}]},{"tag":"e122","title":"Guildmaster Vernon’s Ratmen Mission","desc":["If you have the codeword Acid, turn to e543 immediately. If not, but you have a copper amulet, turn to e384 immediately. Otherwise, read on.","Guildmaster Vernon of Yellowport is surprisingly eager to see you. He is a hugely fat and bejewelled merchant, and he tells you that a group of ratmen have made a base in the sewers beneath the city. They come out at night to raid the warehouses and homes of the merchants of Yellowport.","‘We need an adventurer like yourself to destroy their king,’ explains the guildmaster. ‘Without him, the ratmen wouldn’t be able to organize a feast in a larder. We will pay you 450 💎 if you succeed.’ Vernon tells you that the sewers can be entered via an old disused well in the poor quarter.","Whenever you are ready to enter the sewers, and you are in Yellowport, turn to e460. Note this option on your Adventure Sheet. Now you can return to the city centre, turn to 10, or go down the sewers straight away."]},{"tag":"e123","title":"Ford at the River Grimm","desc":["This is the east bank of the River Grimm, near its source in the Spine of Harkun, far to the north.","You reach a ford where you can travel to the west bank for 1 Shard. You could try swimming across instead, but the current is strong: you need to succeed at a SCOUTING roll at a Difficulty of 10 to do so."],"tables":[{"cols":["Ref","Option"],"rows":[["e053","Swim or pay to cross (Cities of Gold and Glory)"],["e076","Failed attempt to swim (Cities of Gold and Glory)"],["e276","East into the wilderness"],["e003","North to the mountains"],["e333","Follow the riverbank south"]]}]},{"tag":"e124","title":"Storm at Sea","desc":["Heavy black clouds race towards you across the sky, whipping the waves into a frenzy. The crew mutter among themselves fearfully.","If you have the blessing of Alvir and Valmir, which confers Safety from Storms, you can ignore the storm. Cross off your blessing and turn to e420. Otherwise the storm hits with full fury.","Roll one die if your ship is a barque, two dice if it is a brigantine, or three dice if it is a galleon. Add 1 to the roll if you have a good crew; add 2 if you have an excellent crew."],"tables":[{"cols":["Ref","Score","Result"],"rows":[["e346","1–3","Ship sinks"],["e583","4–5","The mast splits"],["e420","6–20","You weather the storm"]]}]},{"tag":"e125","title":"The Beggar's Gift","desc":["You mumble a prayer to the gods, but you're not sure if you got the ritual right.","The beggar thanks you and babbles, 'Yes, yes, a new doublet for an old beggar – I shall wear it with pride!' He wanders off, stopping passersby to show off what he thinks are his new clothes. Poor old fool.","You return to the city centre. Turn to e010."]},{"tag":"e126","title":"Sul Veneris and the Storm Demons","desc":["If you have the codeword Aloft, turn to e199 immediately. If not, read on.","You come across a strange sight. A man lies staked out on the ground, asleep. Blue energy crackles up and down his body, and a hefty-looking hammer, glowing red, is still attached to his belt. It is Sul Veneris, the one you have come to free.","As you are about to lift the stakes, a whistling, keening blast of ferocious wind engulfs you. You are surrounded by whirling storm demons – vaguely man-shaped creatures of thunderous energy which try to sweep you into the air and off the edge of the peak.","You try to recite the rituals of dismissal associated with such demons. Make a SANCTITY roll at Difficulty 12."],"tables":[{"cols":["Ref","Result"],"rows":[["e421","Successful SANCTITY roll"],["e210","Failed SANCTITY roll"]]}]},{"tag":"e127","title":"THIEVERY Check","desc":["Make a THIEVERY roll at Difficulty 9."],"tables":[{"cols":["Ref","Result"],"rows":[["e269","Successful THIEVERY roll"],["e183","Failed THIEVERY roll"]]}]},{"tag":"e128","title":"The Forested Island","desc":["You make your way around the coast. The interior of the island appears to be heavily forested. After a while, however, you come to a bay in which a couple of ships are anchored. A small settlement nestles on the beach, and you make your way towards it.","Turn to e195."]},{"tag":"e129","title":"A Voice from the Shadows","desc":["'Psst, come here, friend!' someone whispers from the shadows."],"tables":[{"cols":["Ref","Option"],"rows":[["e641","Go over to him"],["e100","Ignore him and leave"]]}]},{"tag":"e130","title":"The Dragon Knights Stand Down","desc":["You are greeted by several of the knights.","'We'll not fight you anymore,' says the Blue Dragon Knight. 'We keep losing,' says the Green Dragon Knight. 'And it's costing us a fortune in armour, not to say a lot of bruises!' says the Red Dragon Knight.","You are turned away, unless you have the codeword Axe, in which case turn to e521. Otherwise, turn to e276."]},{"tag":"e131","title":"The Sea Gypsies' Island","desc":["On the island is a community of sea gypsies. They hail you, but then they seem to recognize you. Rapid activity takes place, and within seconds a huge sail has been raised, and the island scuds away – it seems they would rather not meet you a second time.","Turn to e085."]},{"tag":"e132","title":"The Enchanted Flute","desc":["You play the flute like never before. The king and the queen are enchanted by the haunting melodies you are able to coax from the enchanted flute. Unfortunately, you have played too well. The king puts you under a spell, so that you find you cannot stop.","Make a SANCTITY roll at Difficulty 11."],"tables":[{"cols":["Ref","Result"],"rows":[["e413","Successful SANCTITY roll"],["e307","Failed SANCTITY roll"]]}]},{"tag":"e133","title":"Forced Back by the Flames","desc":["You are forced back by the flames. Some townsfolk, covered in wet blankets, manage to get the woman out. They are treated like heroes – you are forgotten. Such is life.","Turn to e100."]},{"tag":"e134","title":"The High Priest is Away","desc":["'The high priest is out of town,' a clerk tells you. 'Yeah, until the heat dies down!' quips a passing member of the temple. The clerk glares at her angrily.","Turn to e235."]},{"tag":"e135","title":"Lake of the Sea Dragon – Cadmium","desc":["The shores of the Lake of the Sea Dragon are swept by ochre waves, and the air smells foul. A sickly, pale green seaweed is the only vegetation that can survive in the sulphurous waters of the lake. A small fishing village, Cadmium, has grown up on the shores of the lake."],"tables":[{"cols":["Ref","Option"],"rows":[["e382","Talk to a fisherman"],["e292","Visit the local market"],["e203","Hire a boat and go fishing"],["e474","Go north to the Coldbleak Mountains"],["e548","North east into the farmlands"],["e278","South east into open countryside"],["e576","South, following the Stinking River"],["e387","West along the road"]]}]},{"tag":"e136","title":"The Sea of Whispers","desc":["The Sea of Whispers. The sea is uncannily quiet and flat as a pane of glass under a grey-blue sky. At night, however, the waters seem to come alive with an eerie whispering. One of your crew tells you that the sounds you heard at night are the sea centaurs speaking to one another across the waves.","Roll two dice:"],"tables":[{"cols":["Ref","Score","Result"],"rows":[["e639","2–4","Storm"],["e507","5–7","An uneventful voyage"],["e337","8–10","An unusual catch"],["e108","11–12","A strange dream"]]}]},{"tag":"e137","title":"The Golnir Merchantman","desc":["The merchantman appears to be from Golnir. It keeps well away from you, no doubt fearing piracy.","Turn to e559."]},{"tag":"e138","title":"Marlock City Streets","desc":["If you have the codeword Ague, turn to e115. If not, read on.","You take a stroll through the streets – Marlock City is teeming with people."],"tables":[{"cols":["Ref","Option"],"rows":[["e015","Explore the Barracks area"],["e129","Visit the Street of Entertainers"],["e619","Enter the residential quarter"]]}]},{"tag":"e139","title":"Spotted by the Guard","desc":["You are spotted by a spear-armed guard. It gives an ululating cry of alarm, and many others swarm out of the mound.","You have little choice but to run – with a pack of deadly killers close behind. Desperately, you try to lose them in the night.","Roll a die, and subtract one from the score. If the result is less than or equal to your Rank, turn to e295. Otherwise, turn to e663."]},{"tag":"e140","title":"Arrival at Yellowport","desc":["The ship drops you at Yellowport docks. You make your way to the city centre.","Turn to e010."]},{"tag":"e141","title":"The Temple of Maka","desc":["The Temple of Maka, the terrible goddess of disease and famine, is a large underground chamber accessible via an ornate entrance in the middle of the Plaza of the Gods, where all the temples stand in Yellowport.","Down below, the walls are bare earth; the ceiling is covered in the roots of growing plants, for Maka is also the goddess of the harvest, who must be kept happy else disease and famine will strike the people, their crops and their livestock, bringing ruin to all."],"tables":[{"cols":["Ref","Option"],"rows":[["e368","Become an initiate"],["e261","Renounce her worship"],["e481","Seek a blessing"],["e077","Ask to be cured of disease or poison"],["e010","Leave the temple"]]}]},{"tag":"e142","title":"The Harbourmaster's Office","desc":["All shipping in and out of Marlock City must come through the offices of the harbourmaster. Here you can buy passage to far lands, or even a ship of your own, to fill with cargo and crew.","You can buy one-way passage on a ship to the following destinations (see table below).","If you buy a ship, you are the captain and can take it where you wish, exploring or trading. You also get to name it. There are three types of ship, and four types of crew quality. You can also buy cargo for your ship to sell in other ports.","If you buy a ship, add it to the Ship's Manifest and name it as you wish. The quality of the ship's crew is average, unless you pay to upgrade it. If you already own a ship you can sell it to the harbourmaster at half the above prices.","It costs 50 💎 to upgrade a poor crew to average, 100 💎 to upgrade an average crew to good, and 150 💎 to upgrade a good crew to excellent.","Cargo can be bought at Marlock City and sold at other ports for profit. If you own a ship, you can buy as many Cargo Units as it has room for. You may also sell cargo, if you have any. Prices quoted here are for entire Cargo Units.","Fill in your current cargo on the Ship's Manifest – assuming you own a ship!","If you own a ship and wish to set sail, turn to e084. If not, you can go to the city centre. Turn to e100."],"tables":[{"cols":["Ref","Destination","Cost"],"rows":[["e372","Yellowport","10 💎"],["e455","Wishport","15 💎"],["e234","Sorcerer's Isle","30 💎"],["e424","Copper Island","30 💎"]]},{"cols":["Ship Type","Cost","Capacity"],"rows":[["Barque","250 💎","1 Cargo Unit"],["Brigantine","450 💎","2 Cargo Units"],["Galleon","900 💎","3 Cargo Units"]]},{"cols":["Cargo","Buy","Sell"],"rows":[["Furs","190 💎","180 💎"],["Grain","190 💎","180 💎"],["Metals","700 💎","635 💎"],["Minerals","500 💎","460 💎"],["Spices","820 💎","760 💎"],["Textiles","325 💎","285 💎"],["Timber","190 💎","180 💎"]]}]},{"tag":"e143","title":"Renouncing the Worship of Elnir","desc":["To renounce the worship of Elnir, you must pay 40 💎 to the priesthood by way of compensation. A passing noble says disdainfully, 'Ha! Only those born to rule have the fibre to worship the Sky Lord. Those who renounce Elnir never reach the top!'","Do you want to change your mind? If you are determined to renounce your faith, pay the 40 💎 and delete Elnir from the God box on your Adventure Sheet.","When you have finished here, turn to e316."]},{"tag":"e144","title":"Banishing the Ghoul","desc":["You call on the powers of the gods to banish this foul, blasphemous travesty of life. The Ghoul shrinks back for a moment, snarling.","Make a SANCTITY roll at Difficulty 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e223","Successful SANCTITY roll"],["e289","Failed SANCTITY roll"]]}]},{"tag":"e145","title":"King Skabb Attacks","image":true,"desc":["King Skabb gives a cry of anger and leaps at you in desperation, swinging a spiked mace in his hand. You must fight him, adding 3 to your ⚔️ if you have some rat poison to put on your weapon. If you use the poison, cross it off your Adventure Sheet.","If you lose, your adventuring career will be over, unless you have a resurrection deal. If you win, turn to e554."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["King Skabb","5","7","10"]]}]},{"tag":"e146","title":"The Challenge of Yanryt the Son","desc":["He seems to see something he approves of because he says, 'Perhaps. But first you must prove yourself. There is a knight, a man of great evil. He is known as the Black Dragon Knight – defeat him in battle and I will teach you. Bring me back his black dragon shield as proof of your valour.' With that he turns and walks away.","'But how will I find him? And then how will I find you?' you cry.","'Would you have me kill him for you as well?' he asks over his shoulder. 'As for the second, ask for me in the Blue Griffon Tavern in Caran Baru. My name is Yanryt the Son.'","Gain the codeword Axe and turn to e412."]},{"tag":"e147","title":"The Old Troubadour's Tale","desc":["An old troubadour tells an epic tale of adventure and romance involving three heroes, a princess and a dragon. Afterwards you find yourself talking to him at the bar. He tells you about the time he was captured by the Manbeasts of Nerech, and that by soothing their savage ferocity with music, he was able to escape.","If you are a Troubadour, turn to e469. Otherwise turn to e100."]},{"tag":"e148","title":"The Tree Surrenders","desc":["'Stop, stop, I surrender!' yells the tree. You cease your attack. 'I guess you can pass, in view of recent events!' it says grudgingly. Then it uproots itself with a great tearing sound and shuffles out of the way. 'There you go!' mutters the tree, 'You can blooming well pass.'","Get the codeword Apple.","You walk through the thorn bush gate. Beyond, you find several huge oak trees whose branches are so big that they are able to support the homes of many people.","Turn to e358."]},{"tag":"e149","title":"The One-Eared Man","desc":["A man accosts you as you are leaving a tavern. His breath reeks of rotting teeth, and his ear has been cut off – the mark of a man punished for piracy.","'Give me 10 💎 and I will tell you what you want to know,' he says."],"tables":[{"cols":["Ref","Option"],"rows":[["e533","Pay the money (cross off 10 💎)"],["e468","Refuse to pay"]]}]},{"tag":"e150","title":"Bound for Marlock City","desc":["Cross off the 10 💎. You get a berth on a merchantman headed for Marlock City. It is a trouble-free journey.","'I pay everyone off – the Sokarans, the pirates,' says the captain. 'That way I get left alone.'","You disembark in Marlock City. Turn to e100."]},{"tag":"e151","title":"Damor the Hermit","desc":["Inside the cave, you find Damor the Hermit, floating cross-legged in the air. 'I told you never to come back!' he shouts angrily. He waves his hand, and you are teleported back down to the bottom of the mountain before you can say a word.","Turn to e244."]},{"tag":"e152","title":"The Venefax Market","desc":["If you have the codeword Attar, turn to e623 immediately.","You clamber down a ladder into a long, low hall, the Venefax Market. A sign reads, 'Closed on Thursday'. Fortunately, it's not Thursday, and a stocky, barrel-chested man with piggy eyes introduces himself as Fourze, the Master of the Market.","There is not much for you to buy or sell in this provincial market. Items with no purchase price are not available locally.","When you are finished, turn back to e427."],"tables":[{"cols":["Armour","Buy","Sell"],"rows":[["Leather (🛡️ +1)","50 💎","45 💎"],["Ring mail (🛡️ +2)","–","90 💎"]]},{"cols":["Weapons","Buy","Sell"],"rows":[["Without ⚔️ bonus","50 💎","40 💎"],["⚔️ bonus +1","–","200 💎"]]},{"cols":["Other Items","Buy","Sell"],"rows":[["Rope","50 💎","45 💎"],["Lantern","100 💎","90 💎"],["Climbing gear","100 💎","90 💎"],["Scorpion antidote","100 💎","90 💎"]]}]},{"tag":"e153","title":"Forced to Surrender","desc":["You and your men are forced to surrender. The Sokarans take all your money and cargo, if you have any.","'Count yourself lucky I haven't decided to call you rebels and sell the lot of you into slavery!' says the captain.","They depart, leaving you and your crew with the bitter taste of defeat. Disconsolately, you sail on. Turn to e439."]},{"tag":"e154","title":"The Temple of Alvir and Valmir","desc":["The temple of Alvir and Valmir, Divine Rulers of the House of the Sea, is right on the teeming harbour of Marlock City. Its sea-green marbled porticos are draped in a hundred silver nets. Brother and sister, Alvir and Valmir rule below the waves. Alvir brings the souls of the drowned in his nets before his sister, Valmir, for judgement.","A swaggering ship's captain emerges from the temple, saying to you in passing, 'Never, I mean never go to sea without paying your respects to the twin gods – unless ye want to sail through a world of storms!'"],"tables":[{"cols":["Ref","Option"],"rows":[["e343","Become an initiate"],["e068","Renounce their worship"],["e275","Seek a blessing"],["e100","Leave the temple"]]}]},{"tag":"e155","title":"Back Aboard Ship","desc":["One of the Trading Post sailors rows you out to your ship anchored in the bay. 'Welcome aboard, Cap'n,' says the mate. The sky is clear and the smell of the sea fills your heart with wanderlust."],"tables":[{"cols":["Ref","Option"],"rows":[["e136","Set sail into the Sea of Whispers"],["e195","Return to the Trading Post"]]}]},{"tag":"e156","title":"No Cure Available","desc":["The priest looks you over. 'I'm afraid we have no one skilled enough to cure you. However, I believe the Temple of Maka in Yellowport might be able to help. And the holy waters at Blessed Springs are known to be efficacious in this kind of case.'","Turn to e100."]},{"tag":"e157","title":"Beaten and Robbed","desc":["You try to prove your loyalty to the new regime, but they don't believe a word of it. They beat you into unconsciousness and leave you lying in the gutter. They rob you of all the money you had, but leave your possessions untouched. You come round with only 3 ❤️ points.","Turn to e010."]},{"tag":"e158","title":"The Three Rings Tavern","desc":["The Three Rings Tavern is a comfortable inn near the city centre. The tavern costs you 1 Shard a day. Each day you spend here, you can recover 1 ❤️ point if injured, up to the limit of your normal unwounded ❤️ score."],"tables":[{"cols":["Ref","Option"],"rows":[["e147","Pay 3 more Shards and buy some drinks"],["e100","Leave the tavern"]]}]},{"tag":"e159","title":"Taken by the Mer-folk","desc":["Your mind falls into a waking dream, and you walk lazily into the waters. The mer-folk, laughing and singing, take you down to their undersea home of living coral, where they stop you from drowning with their faery MAGIC. They keep you for several weeks, until you are no longer an amusement to them.","You wake up, as if from a long sleep, with only a shadowy memory of your ordeal, to find yourself washed up in the harbour of Yellowport. You have lost all the possessions you were carrying (erase them from your Adventure Sheet) but you still have your money.","Turn to e010."]},{"tag":"e160","title":"The Tomb of the Wizard King","desc":["If there is a tick in the box, turn to e461 immediately. If not, put a tick there now, and read on.","You learned the password 'Rebirth' in the library of Dweomer. 'My aren't we the wise one,' carps the door sarcastically. 'Still, a job's a job, eh?' it mutters.","The door lifts straight up, and you step into the shadows of the Tomb of the Wizard King. It is lit by still-burning torches that give off an eerie eldritch glow. In the middle of the large round chamber, a sarcophagus lies, surrounded by a pentacle drawn in blood. You notice the blood still seems fresh!","Make a MAGIC roll at Difficulty 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e674","Successful MAGIC roll"],["e309","Failed MAGIC roll"]]}]},{"tag":"e161","title":"The Governor's Guards","desc":["The governor is a seasoned veteran of many battles, a hardy man. He is quick to react and calls his guards before you can kill him. You are subdued by sheer numbers.","'Take this dirty rebel assassin to the dungeons!' sneers Marloes Marlock.","The guards take all your money and possessions. Cross them off and turn to e454."]},{"tag":"e162","title":"Stripping the Idol of Tyrnai","desc":["With the golems out of the way, you can get on with business. You reach forward to strip the armour off the idol of Tyrnai.","Make a THIEVERY roll at Difficulty 12."],"tables":[{"cols":["Ref","Result"],"rows":[["e509","Successful THIEVERY roll"],["e228","Failed THIEVERY roll"]]}]},{"tag":"e163","title":"The Wrong Head","desc":["You hold up the pirate captain's head. The guildmaster looks up expectantly, but his face quickly darkens.","'This is not Amcha!! Everyone knows he has only one eye – this poor fellow is probably some beggar you killed in an alley somewhere. You think you can swindle the guild with this pathetic ruse! Out! Get out! And don't come back until you bring me the head of Amcha One-Eye!'","The guildmaster has you removed by his guards, and you are dumped into the street. Turn to e100."]},{"tag":"e164","title":"The Dank Tunnels","desc":["The dank tunnels, running with rivulets of foul water, take you deeper into the unknown. You mark the twisting passages with chalk so that you can find your way back.","Shortly, you come out into a large, rough-hewn cavern, wreathed in shadows that dance and flicker in the light you have brought.","A sound makes you start in surprise. Make a SCOUTING or a THIEVERY roll against Difficulty 11."],"tables":[{"cols":["Ref","Result"],"rows":[["e247","Successful SCOUTING/THIEVERY roll"],["e042","Failed SCOUTING/THIEVERY roll"]]}]},{"tag":"e165","title":"Sokaran War Galley","desc":["A Sokaran war galley hails you and draws up alongside. 'We're coming aboard for an inspection!' yells the captain of the galley. His men attempt to grapple your ship."],"tables":[{"cols":["Ref","Option"],"rows":[["e552","Let them board"],["e444","Try to escape"]]}]},{"tag":"e166","title":"The Refugee Road","desc":["You are on the road between Marlock City and the Shadar Tor. Along most of the length of the road, a thin sliver of a shanty town has grown up. Tents and lean-tos line the way. You find out that the people living here are refugees from Trefoille. The city was burnt to the ground during the recent civil war, in which the old king was overthrown.","Roll a die:"],"tables":[{"cols":["Score","Result"],"rows":[["1–2","A pick-pocket! You lose 10 💎"],["3–4","Nothing happens"],["5–6","You find a lantern by the side of the road"]]},{"cols":["Ref","Option"],"rows":[["e100","Go to Marlock City"],["e035","Head for the Shadar Tor"]]}]},{"tag":"e167","title":"Lost in the Mountain Passes","desc":["You lose your pursuers in the treacherous rocky passes of the mountains. Eventually, you reach the safety of the foothills.","Turn to e474."]},{"tag":"e168","title":"Falling Between the Golems","desc":["As you stretch out your hand, you lose your footing and plummet to the ground, right between the two golems! They turn their heads with a grating rumble and open their mouths to speak. The sound that comes out is a bell-like gonging that alerts the temple. You pick yourself up and fall back on the last resort of a rogue – running for your life! Warrior priests swarm out of the temple in pursuit.","Roll one die and subtract one from the total. If the result is less than or equal to your Rank, turn to e395, otherwise turn to e551."]},{"tag":"e169","title":"Pirates and Sokarans","desc":["If there is a tick in the box, turn to e443 immediately. If not, put a tick there now, and read on.","You see a couple of Sokaran warships pursuing two other ships. Your first mate says, 'See the Red Pennants on them thar ships? They be pirates, running from the Sokarans!'"],"tables":[{"cols":["Ref","Option"],"rows":[["e286","Help the Sokarans"],["e394","Help the pirates"],["e443","Ignore the battle"]]}]},{"tag":"e170","title":"Becoming an Initiate of Lacuna","desc":["Becoming an initiate of Lacuna gives you the benefit of paying less for blessings and other services the temple can offer. It costs 60 💎 to become an initiate. You cannot do this if you are already an initiate of another temple.","If you choose to become an initiate, write Lacuna in the God box on your Adventure Sheet and remember to cross off the 60 💎.","Once you have finished here, turn to e615."]},{"tag":"e171","title":"The Flour-Dusted Villagers","desc":["You have soon laid the figures out like three logs on the village green. They are badly hurt, but still alive. Now that you can get a better look at them, you see that they are dusted all over with flour, giving them a spectral appearance.","You summon the other villagers. At first they are loath to venture out and inspect the three strangers, but the fact that you survived convinces them there are no ghosts to worry about.","'Why, it's Old Megan!' cries a man as he claps eyes on one of the three. 'And here's Bradok the miller, and Lame Pootmar! Why are they all covered in flour? Where're the ghosts?'","You shake your head and sigh at the stupidity of the yokels. 'There weren't any ghosts,' you explain. 'It was these three all along.'","Turn to e671."]},{"tag":"e172","title":"The Scholar's Reward","desc":["'Thank you, thank you,' coughs the scholar. He gives you a vial of yellow dust as a reward. Note it on your Adventure Sheet.","'I found this at an ancient archaeological site I have been studying,' he says. 'I believe it needs to be thrown into the holy waters at the village of Blessed Springs, although quite what happens then, I have no idea.'","He thanks you again and takes his leave. Turn to e100."]},{"tag":"e173","title":"Washed Ashore","desc":["You find yourself washed up on a rocky shore, battered and cold, but lucky to be alive. You haul yourself up the beach on to land. Fortunately for you, you find the village of Blessed Springs.","Turn to e510."]},{"tag":"e174","title":"The Gorlock","image":true,"desc":["You advance, weapon at the ready. As you draw closer, something rushes out of the cave with a shrieking cry. It is the gorlock, a beast with legs like a bird, a body like a reptile, with two short forelimbs and a beaked, lizard-like head. Its two legs do indeed have backward-pointing feet. You'll have to fight.","If you win, turn to e315. If you lose, your bones will join the others at the entrance of the cave, unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Gorlock","4","6","7"]]}]},{"tag":"e175","title":"The Ghost Horses of Curstmoor","desc":["If there is a tick in the box, turn to e673 immediately. If not, put a tick there now, and read on.","You are trekking across the aptly named Curstmoor. A great rolling expanse of blasted heath stretches before you. Grey clouds hang over a mournful, dirty-water coloured plain, studded with rocky outcrops and low hills. A raven flutters to the ground nearby, eyeing you curiously. His brothers caw loudly into the echoing sky.","Dusk falls, and in the dim twilight, a herd of horses comes streaking out of the night, straight at you. As they near, it seems to you that their hooves are not touching the ground, and from their manes trail wispy clouds of sparks, like tiny stars."],"tables":[{"cols":["Ref","Option"],"rows":[["e390","Get out of their way"],["e066","Mount one of them"]]}]},{"tag":"e176","title":"The Crew Refuses to Follow","desc":["The crew are very nervous about your orders. They drop anchor in a bay, and will row you to shore, but they absolutely refuse to come with you. In fact, they won't even wait for you to come back.","If you insist on going ashore, your crew will sail for Yellowport and meet you there. 'If you ever make it back,' adds the first mate ominously.","If you want to go ashore, note on your Adventure Sheet that your ship is now docked in Yellowport and turn to e032. Otherwise, turn to e085 and choose again."]},{"tag":"e177","title":"A Safe Place to Rest","desc":["You can leave possessions and money here to save having to carry them around with you. You can also rest here safely and recover any Stamina points you have lost. Record in the box anything you wish to leave.","Each time you return, roll two dice:"],"note":["Turn to e400."],"tables":[{"cols":["Score","Result"],"rows":[["2–9","Your possessions are safe"],["10–11","A break-in. Any money left here has gone"],["12","Raiding nomads take all your possessions"]]}]},{"tag":"e178","title":"The Woman in Black Leather","desc":["A pale woman in black leather brushes past you in the street, casting you an enigmatic look.","Make a THIEVERY roll at a Difficulty of 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e635","Successful THIEVERY roll"],["e198","Failed THIEVERY roll"]]}]},{"tag":"e179","title":"Suspected as a Spy","desc":["You claim that you have come to swear allegiance to Nergan, the rightful king of Sokara. Captain Vorkung is not convinced. He narrows his eyes suspiciously.","'You'd better leave – now. Before I decide you are a spy, and have you shot!'","One of the archers looses a shaft, and an arrow thuds into the ground at your feet, quivering menacingly.","You realize it is time to leave, and climb down the mountain. Turn to e474."]},{"tag":"e180","title":"Through the Archway","desc":["You step through the archway. Immediately the symbols on the stone begin to glow with red-hot energy; your hair stands on end and your body tingles. A crackling nimbus of blue-white force engulfs you, the sky darkens and thunder and lightning crash and leap across the heavens. Suddenly, your vision fades, and everything goes black.","When your sight returns, you find yourself outside the gates of a huge, fortified city. A guard starts in surprise at the sight of you, then shakes his head as if to clear it, sure he must have imagined what he just saw.","The gates open, and a troop of heavy cavalry canter past. 'Make way for the Marlock City militia!', says the guard.","When they have passed, you walk into the city. Turn to e100."]},{"tag":"e181","title":"The Green Man Inn","desc":["The Green Man Inn costs you 1 Shard a day. Each day you spend here, you can recover 1 Stamina point if injured, up to the limit of your normal unwounded Stamina score.","When you are ready, turn to e195."]},{"tag":"e182","title":"Ship Lost to the Sea","desc":["Your ship, crew and cargo are lost to the deep, dark sea. Cross them off your Adventure Sheet. Your only thought now is to save yourself.","Roll two dice. If the score is greater than your Rank, you are drowned – turn to e680. If the score is less than or equal to your Rank, you manage to find some driftwood and make it back to shore. Lose ❤️ points equal to the score of one dice roll and, if you can survive that, turn to e591."]},{"tag":"e183","title":"Sniffed Out by the Ratmen","desc":["You find a shadowy natural alcove in the rocky wall of a tunnel. Desperately, you squeeze yourself into it, using all your skill to hide in the darkness.","Several ratmen run past, but others sniff you out with their highly developed sense of smell. You are overwhelmed by sheer numbers. Turn to e308."]},{"tag":"e184","title":"The Blue Griffon Tavern","desc":["The Blue Griffon Tavern is frequented by soldiers and mercenaries. The tavern costs you 1 Shard a day. Each day you spend here, you can recover 1 ❤️ point if injured, up to the limit of your normal unwounded ❤️ score.","If you have the codeword Axe or if you have a black dragon shield and want to find Yanryt the Son, turn to e451.","If not, but you want to spend a further 3 💎 buying drinks all round at the bar and listen for rumours, turn to e341.","Or you can return to the town centre – turn to e400."]},{"tag":"e185","title":"Bluffing the Sokaran Captain","desc":["You tell him who you are, and that General Grieve Marlock's brother, the Governor of Yellowport, is your personal friend. His eyes widen as recognition dawns on his fat, greedy face.","'Ah, er... my lord!,' he cries. 'I was merely jesting! Umm.... We were, I mean to say, perhaps you need an escort?'","'I think we require a levy in order to carry out the important mission the governor has entrusted to me,' you say. 'Sixty 💎 ought to do it, Captain!'","The Sokaran captain hands over the 60 💎 (add it to your Adventure Sheet) and leads his men off your ship.","You sail on. Turn to e439."]},{"tag":"e186","title":"Selling the Leash","desc":["You pass the leash over to the man in the palanquin, who leans out and hands you over 75 💎. You leave the slave market. Turn to e400."]},{"tag":"e187","title":"Renouncing the Worship of Nagil","desc":["You tell the high priest that you wish to renounce the worship of Nagil. He brings out a small wax dummy and carves your name into it. Then he sets fire to it. The wax melts into a puddle on the floor and the priest steps into it, leaving the imprint of his foot.","'Such is the fate of those who would deny Nagil, the Lord of Death,' he says.","When you ask if you must pay compensation to the temple, he shakes his head, saying, 'It is you who loses, not we.'","Do you want to reconsider? If you are determined to renounce your faith, delete Nagil from the God box on your Adventure Sheet. You must lose any outstanding resurrection arrangements. When you have finished here, turn to e100."]},{"tag":"e188","title":"Back in the Dungeons","desc":["You are thrown into a stinking prison cell.","'Well, well, we meet again, my old friend,' says a half-dead old man with white hair.","You recognize the poor old man whom you met the last time you were thrown into the dungeons! He launches into the same old story about the gorlock, the creature with the backward-pointing feet. By the end of it, you are looking forward to being sold into slavery and sent to work in the tin mines of Caran Baru. Turn to e118."]},{"tag":"e189","title":"Lost Undersea","desc":["There is nothing in your limited knowledge of undersea wildlife to help you."],"tables":[{"cols":["Ref","Option"],"rows":[["e035","Swim back to the Shadar Tor"],["e121","Fight your way to the golden net"],["e592","Try MAGIC"]]}]},{"tag":"e190","title":"Coastal Waters off Blessed Springs","desc":["You are sailing along the coast off Blessed Springs and Fort Brilon. Gulls cluster around the ship, looking for food. Their cries echo across the vast seas.","Roll two dice:"],"tables":[{"cols":["Ref","Score","Result"],"rows":[["e038","2–4","Storm"],["e209","5–9","An uneventful voyage"],["e504","10–12","A shipwreck"]]}]},{"tag":"e191","title":"The Provost Marshal's Mission","desc":["The provost marshal is a rich and powerful man, cunning and capable.","'I have need of someone like you,' he says. 'A group of rebels, loyal to the old king, are hiding out in the Coldbleak Mountains. Their leader, Nergan Corin, is dangerous to us, as he is heir to the old throne and a rallying point for the rebels. Penetrate their stronghold and slay Nergan Corin, and you will be richly rewarded. I can promise you 500 💎 and a title if you succeed.'","If you take the mission, gain the codeword Artery.","If you have the codeword Ambuscade, turn to e375. Otherwise, the provost marshal dismisses you. Turn to e010."]},{"tag":"e192","title":"The Gates of the World","desc":["During your short trip upward, the old man regales you with tales of your destiny and fate, continuously arguing with himself as he does so.","You reach a hill covered with a circle of large obsidian standing stones. Despite the bitter wind that blows across these hills the stones are unweathered and seem almost newly laid.","'Here are the Gates of the World,' says the mad old man. The stones are laid in such a way that they form three archways, each carven with mystic symbols and runes of power.","'Each gate will take you to a part of the world of Harkuna, though I know not where,' explains the old man. Abruptly, he turns around and sets off down the hill, babbling to himself. His voice fades as he descends the hill, leaving you alone with the brooding stones and the howling wind.","Turn to e065."]},{"tag":"e193","title":"Washed Up on a Rocky Shore","desc":["You find yourself washed up on a rocky shore, battered and cold, but alive. You head inland until you come to a road. Turn to e621."]},{"tag":"e194","title":"The Ker'ilk Attack","image":true,"desc":["You know what the strange swellings on the dead bodies mean. They have been injected with the eggs of the ker'ilk, hideous lobster-like beings of the deep. Soon the eggs will hatch, and the young will feed on the bodies of the sailors. You also know that the adults never stray far from their eggs, and warn your men that the ker'ilk are nearby.","Your warning is timely – several horrific-looking creatures, like giant lobsters, all spines and pincers, surge out of the waters. Your men, however, are ready. A battle ensues – you must fight one of the creatures.","If you win, turn to e519. If you lose, you'll end up as food for ker'ilk young, unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Ker'ilk","4","9","8"]]}]},{"tag":"e195","title":"The Trading Post","desc":["Gain the codeword Aspen if you do not already have it.","The Trading Post is a small village, set up here by enterprising settlers from the mainland. Its main export appears to be furs from the forest. The Mayor, a fat genial fellow who greets you personally, insists that one day the Trading Post will be a thriving town. There is not a lot here yet, however: a small market, a quay, the settlers' houses, and a shrine to Lacuna the Huntress, goddess of nature."],"tables":[{"cols":["Ref","Option"],"rows":[["e544","Visit the shrine to Lacuna"],["e452","Visit the market"],["e332","Visit the quayside"],["e181","Visit the Green Man Inn"],["e011","Climb the hill that overlooks the town"],["e257","Go inland, into the Old Forest"]]}]},{"tag":"e196","title":"Ghoulbite Infection","desc":["If you were wounded by the ghoul you have been infected with a disease (Ghoulbite). Note that, until you can find a cure, you must subtract one from your SANCTITY, ⚔️ and CHARISMA abilities (no ability can drop below one). If you were already suffering from Ghoulbite, there are no further effects.","In any case, you hack off the hideous head and leave. Note you have a ghoul's head and turn to e100."]},{"tag":"e197","title":"The Blessing of Sig","desc":["The blessing of Sig costs 10 💎 if you are an initiate, 30 💎 otherwise. If you buy the blessing, cross off the money and mark THIEVERY in the Blessings box on your Adventure Sheet.","The blessing works by allowing you to reroll any failed THIEVERY attempt once. When you use the blessing, cross it off your Adventure Sheet. You can then make a second try at the roll. You can have only one blessing for each ability at any one time. Once your THIEVERY blessing is used up, you can return to any branch of the temple of Sig to buy a new one.","When you are finished here, turn back to e235."]},{"tag":"e198","title":"The Pickpocket","desc":["Musing to yourself about the strange woman, you pause at the end of an alleyway to buy roast chestnuts as you watch her striding off into the evening smog enveloping the city.","'That'll be a Shard,' grunts the chestnut vendor.","You reach for your money pouch. Then your hands fumble in panic. The pouch has gone! After a moment the truth dawns on you. You stare grimly in the direction that the black-garbed woman went, but there is no sign of her now.","'I'll have them chestnuts back then!' growls the vendor when he sees you can't pay.","Lose all the money you were carrying and turn to e010."]},{"tag":"e199","title":"The Storm Demon","image":true,"desc":["If there is a tick in the box, turn to e634 immediately. If not, put a tick there now, and read on.","A strange, vaguely humanoid shape, flickering with energy, soars down to attack you. You must fight.","If you win, it fades away, leaving a clear blue jewel worth 200 💎. Note the money on your sheet directly.","If you lose, it's the end of you, unless you have a resurrection deal. If you still live, there's nothing else up here, so you climb down again. Turn to e658."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Storm Demon","3","6","8"]]}]},{"tag":"e200","title":"The Old Map of the Forest of the Forsaken","desc":["You have acquired an old map of the Forest of the Forsaken in Golnir (in Cities of Gold and Glory), showing a safe path that leads to the Tower of Despair. It seems to conflict with the location of the Tower on your own map of Golnir from Cities of Gold and Glory. Which is correct?","This map is the fourth map included in the Map Pack document. As long as you retain this treasure map, you may peruse it at will. Should you lose or sell the treasure map however, you should then no longer consult the map of the Forest of the Forsaken.","To return to the Yellowport market, turn to e030."]}]`),m=JSON.parse(`[{"tag":"e201","title":"The Road to Caran Baru","desc":["The road between the Citadel and Caran Baru is chock-a-block with troops and carts. It looks like there is a war in the north."],"tables":[{"cols":["Ref","Option"],"rows":[["e271","Head for the citadel"],["e400","Go south to Caran Baru"],["e276","Head west"],["e060","Head east"]]}]},{"tag":"e202","title":"The Ratman King","desc":["Gingerly, you open the door. It leads to a curtained alcove, through which you observe the room beyond. It is a long, low hall – clearly an ancient Uttakin temple, from a time when the Masked Lords of Uttaku ruled all of Harkuna, but now part of the sewers of Yellowport.","A cheap wooden chair has been placed on the altar to act as a throne. On it sits a large and extremely ugly ratman. He has a tacky amulet around his neck, and a rusty iron hoop for a crown. About four ratmen are kneeling before him, engaged in conversation.","'But, Skabb...' one of the ratmen is saying. 'That's Great King Skabb to you, dung-breath!!' bellows the rat on the throne."],"tables":[{"cols":["Ref","Option"],"rows":[["e428","Charge in to the attack"],["e595","Sneak in to assassinate the king"],["e024","Use sorcery to get close to Skabb"],["e336","Bluff your way in"]]}]},{"tag":"e203","title":"Hiring a Fishing Boat","desc":["You can hire a fishing boat for 15 💎 a day. It comes with a fishing net."],"tables":[{"cols":["Ref","Option"],"rows":[["e267","Pay 15 💎 and go fishing"],["e135","Don't go fishing"]]}]},{"tag":"e204","title":"Overwhelmed by the Cultists","desc":["There are simply too many of them, and you are beaten into submission. Your end is grisly indeed – killed, boiled with herb and garlic, and eaten by the cannibal cultists of Badogor the Unspoken!","Your adventures end here – unless you have a resurrection deal."]},{"tag":"e205","title":"The Runes of Old Shadar","desc":["The runes are written in Old Shadar, an ancient language from thousands of years ago. You realize that the runes form a spell that will give you the power to breathe underwater for a few hours."],"tables":[{"cols":["Ref","Option"],"rows":[["e493","Use the spell and swim out to sea"],["e097","Go down to the beach"],["e602","Take the road to Trefoille"],["e166","Take the road to Marlock City"]]}]},{"tag":"e206","title":"The Crew Refuses the Unbounded Ocean","desc":["The crew absolutely refuses to sail into the Unbounded Ocean. 'There's no land out there, and the seas are infested with Demons of the Deep – if we go too far, we'll fall off the edge of the world!' says the first mate.","You have no choice but to reconsider your destination. Turn back to e507 and choose again."]},{"tag":"e207","title":"Ship on the Starboard Bow","desc":["If there is a tick in the box, turn to e137 immediately. If not, put a tick there now, and read on.","The look-out cries, 'Ship on the starboard bow!' You spot a crippled merchant ship, limping towards Marlock City. It looks like a trading vessel from the Feathered Lands."],"tables":[{"cols":["Ref","Option"],"rows":[["e293","Assist"],["e464","Attack"]]}]},{"tag":"e208","title":"The Sleep Vapour","desc":["Using your sorcerous powers you breathe a cloud of greenish vapour over the ratmen. Coughing and gasping, they sink into an enchanted slumber – all but King Skabb. Standing on the altar, he is able to keep his head above the vapours.","Turn to e145."]},{"tag":"e209","title":"Coastal Waters off Fort Brilon","desc":["You are sailing in the coastal waters off Fort Brilon and Blessed Springs."],"tables":[{"cols":["Ref","Option"],"rows":[["e249","Sail north along the coast of Nerech"],["e430","Sail south to Scorpion Bay"],["e136","Sail east into the Sea of Whispers"]]}]},{"tag":"e210","title":"Fighting the Storm Demons","image":true,"desc":["They fall back for a moment, but your invocation fails to take hold, and they close in. You must fight them one at a time.","If you win, turn to e054. If you lose, you are tossed off the peak and end up as a messy paste on the ground below. That's the end of you, unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["1st Storm Demon","4","7","8"],["2nd Storm Demon","4","7","8"],["3rd Storm Demon","4","7","8"]]}]},{"tag":"e211","title":"Waiting in Ambush","desc":["When he emerges, you are waiting for him. Make a THIEVERY roll at Difficulty 11."],"tables":[{"cols":["Ref","Result"],"rows":[["e058","Successful THIEVERY roll"],["e304","Failed THIEVERY roll"]]}]},{"tag":"e212","title":"Dissolved in Acid","desc":["You are dissolved in the acid, until all that is left of you is a pile of yellow dust. Vayss scoops you up and puts you into a bottle on his shelf. Cross off all the possessions and money you were carrying, and turn to e031."]},{"tag":"e213","title":"The Golden Net","desc":["Each creature bursts open in death, spilling a black empty cloud into the water. The sac in which this ink is kept falls free from its body. You can take the ink sacs if you wish – note up to three of them on your Adventure Sheet. You also find coral jewellery worth about 45 💎 that you can take as cash.","You swim down and take the golden net (note it on your Adventure Sheet) and swim for the Shadar Tor as fast as you can."],"tables":[{"cols":["Ref","Option"],"rows":[["e602","Take the road to Trefoille"],["e166","Take the road to Marlock City"]]}]},{"tag":"e214","title":"Overwhelmed by the Ker'ilk","desc":["You try to stop the panic, but your men are too far gone. They are already diving over the side, trying to swim back to your ship. Unfortunately, they are even more vulnerable in the sea, and the ker'ilk take them at will. Soon you are all overwhelmed, and you are taken alive to be injected with eggs – a most horrible end.","Your adventures are over, unless you have a resurrection deal with a temple."]},{"tag":"e215","title":"Caran Baru Market","desc":["Caran Baru market consists of several covered arcades – much of its stock is for miners and soldiers, and it is run with business-like efficiency by the Sokaran military. Items with no purchase price are not available locally.","When you have finished, turn back to e400."],"tables":[{"cols":["Armour","Buy","Sell"],"rows":[["Leather (🛡️ +1)","50 💎","45 💎"],["Ring mail (🛡️ +2)","100 💎","90 💎"],["Chain mail (🛡️ +3)","200 💎","180 💎"],["Splint armour (🛡️ +4)","400 💎","360 💎"],["Plate armour (🛡️ +5)","800 💎","720 💎"],["Heavy plate (🛡️ +6)","–","1440 💎"]]},{"cols":["Weapons","Buy","Sell"],"rows":[["No ⚔️ bonus","50 💎","40 💎"],["⚔️ bonus +1","250 💎","200 💎"],["⚔️ bonus +2","500 💎","400 💎"],["⚔️ bonus +3","–","800 💎"]]},{"cols":["Magical Equipment","Buy","Sell"],"rows":[["Amber wand (MAGIC +1)","500 💎","400 💎"],["Ebony wand (MAGIC +2)","–","800 💎"],["Cobalt wand (MAGIC +3)","–","1600 💎"]]},{"cols":["Other Items","Buy","Sell"],"rows":[["Mandolin (CHARISMA +1)","300 💎","270 💎"],["Lockpicks (THIEVERY +1)","–","270 💎"],["Holy symbol (SANCTITY +1)","–","100 💎"],["Compass (SCOUTING +1)","500 💎","400 💎"],["Rope","50 💎","45 💎"],["Lantern","100 💎","90 💎"],["Climbing gear","100 💎","90 💎"],["Bag of pearls","–","100 💎"],["Rat poison","60 💎","50 💎"],["Silver nugget","–","150 💎"]]}]},{"tag":"e216","title":"Murder in the Palace","desc":["The cry goes up throughout the palace, 'Murder! Assassin!' and the hunt is on – for you. You will need all your skill to get out of the palace alive.","Roll one die, subtracting one if you are a Rogue, Troubadour, or a Wayfarer. If you score less than or equal to your Rank, turn to e407. Otherwise, turn to e566."]},{"tag":"e217","title":"The Ancient Willow","desc":["You come across a forest glade. Birds twitter in the trees, and woodland animals frolic playfully about. In the middle of the glade stands a mighty willow, ancient beyond reckoning. The trunk is hollow, and a wooden door has been set in the entrance. You step into the glade.","Make a SANCTITY roll at Difficulty 9."],"tables":[{"cols":["Ref","Result"],"rows":[["e356","Successful SANCTITY roll"],["e646","Failed SANCTITY roll"]]}]},{"tag":"e218","title":"Captured by the Militia","desc":["The militia take you alive. You lose all your money and possessions. Cross them off your Adventure Sheet. Then you are thrown into the dungeons of Yellowport.","Turn to e454."]},{"tag":"e219","title":"Ship Lost to the Deep","desc":["Your ship, crew and cargo are lost to the deep, dark sea. Cross them off your Adventure Sheet. Your only thought now is to save yourself.","Roll two dice. If the score is greater than your Rank, you are drowned – turn to e680. If the score is less than or equal to your Rank, you manage to find some driftwood and make it back to shore.","Lose ❤️ points equal to the score of one die roll and, if you can survive that, turn to e436."]},{"tag":"e220","title":"The Temple of Alvir and Valmir","desc":["The temple of Alvir and Valmir is built like an upside-down galleon. Alvir and Valmir are brother and sister, King and Queen of the Land beneath the Waves, masters of the sea. Their servants and soldiers are the souls of the drowned, and when seas are rough and storm-tossed, sailors say that Alvir and Valmir are arguing again.","If you have the codeword Anchor, turn to e531.","Otherwise, you notice a sign on the temple door, which says: 'Wanted: brave adventurer – apply to the high priest.'"],"tables":[{"cols":["Ref","Option"],"rows":[["e294","Become an initiate"],["e624","Renounce worship"],["e448","Seek a blessing"],["e411","Talk to the high priest"],["e010","Leave the temple"]]}]},{"tag":"e221","title":"Recognized as the Assassin","desc":["One of the militiamen recognizes you and shouts, 'That's the one who assassinated Marloes Marlock! Get him!'","You turn tail and flee with fifteen militiamen on your heels. Roll one die. If you score less than or equal to your Rank, turn to e057. Otherwise, turn to e252."]},{"tag":"e222","title":"Coastal Waters near Marlock City","desc":["Your ship is sailing in the coastal waters near Marlock City.","Roll two dice:"],"tables":[{"cols":["Ref","Score","Result"],"rows":[["e124","2–4","Storm"],["e420","5–9","An uneventful voyage"],["e169","10–12","Sea battle"]]}]},{"tag":"e223","title":"The Ghoul Destroyed","desc":["The ghoul staggers back, howling at the night sky, and gnashing its teeth. Suddenly, brownish ichor spills from its eyes and the flesh begins to shrivel on its bones. It collapses in on itself, leaving only a mound of putrescent matter, atop of which rests its head, now lifeless, empty eye-sockets staring at the moon.","You grab the head and set off. Note you have a ghoul's head and turn to e100."]},{"tag":"e224","title":"Escaping Through the Tunnels","desc":["Using your wilderness-honed sense of direction you dart through the maze of tunnels. Soon the sounds of pursuit fade, until they are but a dim echo. Heaving a sigh of relief, you press on.","Turn to e580."]},{"tag":"e225","title":"The Empty Cave","desc":["You find a cave, with piles of human bones outside it. However, it is quite empty without signs of habitation – the beast that lived here is dead or departed. You make your way back down to Blessed Springs.","Turn to e510."]},{"tag":"e226","title":"Marlock City by Night","desc":["You take a stroll through the streets – Marlock City has a busy night life."],"tables":[{"cols":["Ref","Option"],"rows":[["e015","Explore the barracks area"],["e129","Go to the Street of Entertainers"],["e619","Search the residential quarter"]]}]},{"tag":"e227","title":"The Mad Beggar's Meal","desc":["Cross off 5 💎. The mad beggar takes the money and swallows the lot in one gulp. 'A gourmet meal!' he babbles.","If you want to bless him, turn to e632. If not, he wanders off ranting and you head back to the city centre, turn to e010."]},{"tag":"e228","title":"The Trap at the Idol","desc":["A stone slab at the base of the idol shifts ominously as you put your foot on it. A wickedly barbed spear springs out of the ground, straight into your leg. Lose 5 ❤️.","If you still live, you remove the chain mail and sling it over your shoulder. Note the gold chain mail of Tyrnai on your Adventure Sheet. Because it is made of gold, it is useless if worn as armour.","As you glance at the jaguar-headed idol, its eyes seem to turn to look at you. Make a SANCTITY roll at Difficulty 8."],"tables":[{"cols":["Ref","Result"],"rows":[["e625","Successful SANCTITY roll"],["e279","Failed SANCTITY roll"]]}]},{"tag":"e229","title":"The Guildmaster's Welcome","desc":["The guildmaster welcomes you warmly. He has no further missions for you, though he treats you with respect because you brought Amcha to justice.","If you are completely broke, without a Shard in your pocket or in the bank, he will give you 200 💎. If you have any money at all, he will not help.","Turn to e100."]},{"tag":"e230","title":"Captured and Hanged","desc":["You are caught in a narrow defile and seized by many men. You are hauled before Captain Vorkung, who sentences you to be hanged. Sentence is carried out immediately. Your adventures are over, unless you have a resurrection deal.","If you do have a resurrection deal, turn to the paragraph you have noted. Also, through a quirk of magical fate, somehow the royal ring has travelled with you through the lands of the dead. Retain it on your Adventure Sheet."]},{"tag":"e231","title":"Footprints in the Grass","desc":["You notice that the figures have left footprints on the damp grass and cannot, therefore, be ghosts."],"tables":[{"cols":["Ref","Option"],"rows":[["e023","Step out and confront the figures"],["e541","Stay hidden and follow when they leave"]]}]},{"tag":"e232","title":"Damor the Hermit","desc":["If there is a tick in the box, turn to e151 immediately. If not, put a tick there now, and read on.","The interior of the cave is cool and refreshing, a paradise compared with the savage heat of your gruelling climb. You find a man, floating cross-legged in the middle of the air! He is dressed only in a loincloth, and is painfully thin. His face is shrouded in a great luxuriant growth of glossy black hair, a beard like no other you have ever seen.","At the sight of you, he gives an exasperated sigh, and says, 'I am Damor the Hermit. A HERMIT. That means I like to live alone – got that? Alone! So go away!'","'I nearly died getting here, old man!' you reply testily.","'Yes, you'd have to be pretty tough to get through the curse I put on the path, I suppose,' he says somewhat apologetically.","If you have the codeword Anthem, turn to e285. Otherwise, turn to e480."]},{"tag":"e233","title":"The Grizzled Swordsman","desc":["If there is a tick in the box, turn to e412. If not, put a tick there now, and read on.","You are on the cobbled road between Yellowport and Trefoille. It is well-kept by the Sokaran military.","You spot a man up ahead, striding towards you. Suddenly, five or six bandits appear from the wayside to assault him. The lone figure executes a series of movements, almost faster than the eye can see, and you see his sword flashing in the sun. Moments later, the bandits are all lying dead or dying around him.","You stop to compliment him on his swordsmanship. The man, a grizzled veteran of many campaigns, regards you with steely grey eyes and says, 'I have learned much of the arts of war in my time, it is true.'","Impressed by his skill and demeanour, you venture to ask him to teach you some of these arts. He looks you up and down with a critical eye.","If you are a Warrior, turn to e146. Otherwise turn to e567."]},{"tag":"e234","title":"Voyage to Sorcerer's Isle","desc":["The ship's captain says, 'I'll take you to Dweomer, on the Sorcerer's Isle but it's a dangerous place. You'd better be sure you can handle it – if you're not at least a Master of your profession, I'd advise against it. It's up to you though.'","You must have Over the Blood-dark Sea to travel to Sorcerer's Isle. If you want to go, cross off 30 💎 and turn to e026. Otherwise, if you are in Marlock City, turn back to e142; if you are in Yellowport, return to e555."]},{"tag":"e235","title":"The Temple of Sig the Cunning","desc":["The temple of Sig the Cunning, patron of vagabonds, troubadours, lovers, thieves and rogues, is a ramshackle warehouse in the poor quarter. Inside, however, there is so much wealth it makes you gasp – the idol of Sig, a saturnine two-faced young human of indeterminate sex, is covered in gems.","'As you can see, we have been made rich by generous, er, donations!' says a black-robed priest."],"tables":[{"cols":["Ref","Option"],"rows":[["e113","Seek an audience with the high priest"],["e437","Become an initiate"],["e563","Renounce worship"],["e197","Seek a blessing"]]}]},{"tag":"e236","title":"Fourze Unmasked","desc":["You find Fourze inside, desperately trying to get out of his suit and run off. At the sight of a hardened adventurer, rather than a timid villager, he surrenders and confesses all. He terrified people with the monster disguise to keep them away from the farm. He and his men were kidnapping villagers, chaining them in the cellar below and selling them to a slaver from Caran Baru, for work in the slave mines. You find Haylie and several other villagers down below in the cellar.","'Don't hurt me,' begs Fourze, 'I'm only trying to make a few Shards.' 'What! By selling your own people into slavery,' says one of the villagers, giving him a good kick.","You lead them back to Venefax. Turn to e414."]},{"tag":"e237","title":"Pleading Your Love of Trees","desc":["You explain what a tree-lover you are, and that your heart has always been at home in forests. You portray yourself as the greenest adventurer ever.","Make a CHARISMA roll at Difficulty 10. Add 3 to the dice roll if you are a Wayfarer, and add 1 if you are an initiate of Lacuna."],"tables":[{"cols":["Ref","Result"],"rows":[["e391","Successful CHARISMA roll"],["e410","Failed CHARISMA roll"]]}]},{"tag":"e238","title":"The Repulsive One","image":true,"desc":["The vile-looking creature shoots towards you with a terrifying predatory speed. You have no choice but to fight it.","You must subtract 2 from your dice rolls for this fight, as you are unused to underwater COMBAT. If you win turn to e053. If you lose, your adventuring days are over, unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Repulsive One","5","10","10"]]}]},{"tag":"e239","title":"The Summit of Devil's Peak","desc":["The climb is long and hard, but at last you heave yourself up on to the top of Devil's Peak – a flat expanse of weathered black rock.","If you have the codeword Altitude, turn to e126. Otherwise, turn to e199."]},{"tag":"e240","title":"Arriving at Marlock City","desc":["You sail into the teeming harbour of Marlock City. Sokaran warships escort you in. 'Troubled times,' comments a sailor.","Turn to e100."]},{"tag":"e241","title":"Renouncing the Worship of Elnir","desc":["To renounce the worship of Elnir, you must pay 40 💎 to the priesthood by way of compensation. The high priest says nothing – he merely regards you with a mild contempt, as if he expected you to fail in the worship of Elnir. Do you want to change your mind?","If you are determined to renounce your faith, pay the 40 💎 and delete Elnir from the God box on your Adventure Sheet. When you have finished here, turn to e100."]},{"tag":"e242","title":"The Sokarans Retreat","desc":["You fight the Sokarans to a standstill. The Sokaran captain orders the retreat; he and his marines pull back to their galley. You and your crew are too tired to pursue, and the Sokarans pull away.","'I'll get you next time!' yells the captain.","You sail on. Turn to e439."]},{"tag":"e243","title":"No Hidden Panels","desc":["You cannot find any hidden panels – Lauria did say that the real treasure was upstairs. You call to her, but she doesn't reply."],"tables":[{"cols":["Ref","Option"],"rows":[["e386","Go upstairs"],["e534","Wait downstairs"]]}]},{"tag":"e244","title":"Foothills of the Spine of Harkun","desc":["You have come to the foothills of the Spine of Harkun. The great mountains rise up majestically before you, their snow-capped peaks wreathed in clouds. You find a clear, cold stream, where you drink your fill and replenish your water supply."],"tables":[{"cols":["Ref","Option"],"rows":[["e536","Climb upwards"],["e518","Head south"],["e495","Head east to Disaster Bay"],["e271","West to the citadel"]]}]},{"tag":"e245","title":"Lost Footprints","desc":["The footprints cross a stream, and there you lose them. After an hour's fruitless searching by moonlight, you are forced to give up and go back to the village. There you are admonished for being reckless.","'What if the ghosts had taken you with them back to their graves?' says one man grimly.","The next day you are ready to resume your journey."],"tables":[{"cols":["Ref","Option"],"rows":[["e576","Follow the river north"],["e082","Follow the river south"],["e278","East into the countryside"],["e558","West to the main road"]]}]},{"tag":"e246","title":"The Temple of Tyrnai","desc":["If you have already successfully stolen the gold chain mail of Tyrnai for the Temple of Sig, turn to e467. If not, read on.","The Temple of Tyrnai, the God of Battle, Chaos and Strife, is built like a small fortress in one corner of the city, near the barracks. Its heavy wooden gates are flanked by iron statues of bull-headed men wielding clubs. The workmanship is uncannily life-like. Inside, the god is represented by a stone idol of a jaguar-headed warrior. A beautiful suit of gold chain mail adorns the idol."],"tables":[{"cols":["Ref","Option"],"rows":[["e636","Become an initiate"],["e514","Renounce worship"],["e107","Seek a blessing"],["e033","Make resurrection arrangements"],["e305","Try to steal the chain mail"],["e400","Leave the temple"]]}]},{"tag":"e247","title":"Ambushing the Ambusher","image":true,"desc":["The sound was the click of a secret door sliding open in the wall of the caverns. With a swift motion, you step up beside it, back to the wall. A figure emerges but you are able to ambush the ambusher – a deft blow to the back of the head sends the dark figure crashing to the ground.","Another steps forth, however, shouting in a guttural voice. You realize that the figures are ratmen – manlike creatures that stand on two legs, but which have the tail and hairy features of a gigantic rat.","You must fight the ratman. If you have some rat poison, you can apply it to the blade of your weapon and add 3 to your dice rolls for this fight only. If you use the rat poison, cross it off your Adventure Sheet.","If you win, turn to e423. If you lose, turn to e308."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Ratman","3","6","6"]]}]},{"tag":"e248","title":"The Oak Druid Has Nothing More to Say","desc":["If you have a willow staff, turn to e319 immediately. If not, read on.","The Oak Druid, who asked for you to take the oak staff to the Willow Druid, has nothing more to say to you.","You return to the Trading Post. Turn to e195."]},{"tag":"e249","title":"The Coastal Waters of Nerech","desc":["'Nerech's a dangerous place – even its coastal waters, Cap'n,' says the first mate. 'The men probably won't follow you there if they don't think you're good enough to lead them!'","If your Rank is 4 or more, turn to paragraph e050 in The Plains of Howling Darkness.","If your Rank is less than 4, the first mate advises you against making the ocean journey. If you take his advice, turn back to e209.","If you insist on making the trip, you need to make a CHARISMA roll at Difficulty 11 to convince the crew to follow you."],"tables":[{"cols":["Ref","Result"],"rows":[["e050","Successful CHARISMA roll"],["e209","Failed CHARISMA roll"]]}]},{"tag":"e250","title":"The Ruined City of Trefoille","desc":["The city of Trefoille is a terrifying vision of apocalyptic destruction. It had once been a thriving crossroads town, but now it is a burnt-out hulk. It was almost razed to the ground when it declared for the late king, during the recent civil war, and tried to hold out against the army of Grieve Marlock, the current Protector-General of Sokara. It was then sacked by the general's mercenaries, and General Marlock is now trying to rebuild it – craftsmen are hard at work everywhere.","If you have the codeword Amends and want to visit Oliphard the Wizardly, turn to e656. Otherwise there is nothing here but ashes and rubble."],"tables":[{"cols":["Ref","Option"],"rows":[["e602","Take the road to the Shadar Tor"],["e377","Take the road to Marlock City"],["e175","Head into the Curstmoor"],["e558","Take the road north"],["e233","Take the road to Yellowport"]]}]},{"tag":"e251","title":"Back at the Sea Dragon's Lair","desc":["If you have the codeword Avenge, turn to e622 immediately. If not, read on.","The last time you were here, you had only a few minutes to grab some loot. This time, the sea dragon returns almost straight away, and you are forced to climb out of the hole in the roof without getting anything except a pouch of 50 💎. You crawl out on to the island in the middle of the lake and hitch a boat ride back to Cadmium.","Turn to e135."]},{"tag":"e252","title":"Caught by a Second Patrol","desc":["You lead them a merry chase through the backstreets of Yellowport but unfortunately for you, you ran smack dab into another patrol. You are captured and thrown into the dungeons to await your fate, but not before the militiamen take all your money and possessions.","Turn to e454."]},{"tag":"e253","title":"Renouncing the Worship of Lacuna","desc":["To renounce the worship of Lacuna, you must pass an ordeal of judgment. This entails the high priestess throwing several silver daggers at you, while you remain motionless.","'If Lacuna sees it in her heart to forgive you, the daggers will all miss,' she claims."],"tables":[{"cols":["Ref","Option"],"rows":[["e313","Submit to the ordeal"],["e615","Remain an initiate after all"]]}]},{"tag":"e254","title":"A Kiss from the Mer-folk","desc":["You ask for a kiss. 'Oh no!' cry the mer-folk, 'A kiss is not so easily won! Tell us a tale to stir our hearts – then we may reward you.'","Make a CHARISMA roll at Difficulty 9."],"tables":[{"cols":["Ref","Result"],"rows":[["e012","Successful CHARISMA roll"],["e281","Failed CHARISMA roll"]]}]},{"tag":"e255","title":"Reporting to the Provost Marshal","desc":["The provost marshal takes you to an empty side chamber, away from prying ears. Over a glass of fine wine you tell him of your adventures in the Coldbleak Mountains. When you give him the Royal Ring of the House of Corin, he knows that Nergan is dead. Cross the royal ring off your Adventure Sheet.","Marloes Marlock is pleased indeed. He pays you 500 💎 and awards you the title Protector of Sokara. Note it in your Titles and Honours box. The title will give you instant respect and command obedience in Sokara.","Also, after completing such a difficult test, you find the experience has taught you much – gain 1 Rank and roll one die. The result is the number of Stamina points you gain permanently. Note the increase on your Adventure Sheet. Also, don't forget to increase your 🛡️ by 1 as a result of your gain in Rank.","Return to e010 and choose again."]},{"tag":"e256","title":"King's Champion","desc":["The king is overjoyed with the news. 'Excellent! At this rate I will be able to take my rightful place in the throne room of Old Sokar.'","He rewards you with the title King's Champion. Note this in the Titles and Honours box on your Adventure Sheet. The title comes with a cash gift of 500 💎 as well.","You also go up one Rank. Roll one die – the result is the number of Stamina points you gain permanently. Note the increase on your Adventure Sheet. Also, don't forget to increase your 🛡️ by 1 as a result of your gain in Rank.","The king has another mission for you. He explains that an army of steppe Nomads, Trau, Mannekyn people, and Sokaran troops still loyal to Nergan, have gathered on the steppes and are moving to siege the Citadel of Velis Corin, which guards the Pass of Eagles through the Spine of Harkun. Nergan tells you that an alliance of northern nations has declared war on the new Sokaran regime. A certain General Beladai leads the Northern Alliance, and King Nergan has joined forces with him. He asks you to travel to the Steppes and talk to General Beladai.","'An adventurer like yourself might be able to steal into the citadel, and bring about its downfall from within, or some such. If the citadel falls we will have Sokara at our mercy.'","If you want to take up this mission for the King, record the codeword Assault. When you are ready, you are led back down to the foothills of the mountains. Turn to e474."]},{"tag":"e257","title":"Into the Old Forest","desc":["The trees are closely packed, leaning together as if in conference, whispering quietly among themselves. Birds twitter in the distance, and slivers of sunlight lance down through the musty gloom.","As you proceed along a forest track, you think you hear a rustling in the bushes. Later, you spot a shadowy figure darting through the trees – or was it your imagination? An animal snuffling sound right behind you makes you spin round, but there is nothing there.","Make a SCOUTING roll at Difficulty 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e630","Successful SCOUTING roll"],["e036","Failed SCOUTING roll"]]}]},{"tag":"e258","title":"Becoming an Initiate of the Three Fortunes","desc":["Becoming an initiate of the Three Fortunes gives you the benefit of paying less for blessings and other services the temple can offer. It costs 75 💎 to become an initiate. You cannot do this if you are already an initiate of another temple.","If you choose to become an initiate, write The Three Fortunes in the God box on your Adventure Sheet and cross off the 75 💎.","Once you have finished here, turn to e086."]},{"tag":"e259","title":"Fort Brilon","desc":["Fort Brilon, named after a Sokaran King of the first dynasty, is the southernmost castle on the fortified wall that keeps out the rabid, savage manbeasts. What the soldiers fear most is what they call 'Death Duty' – going out on patrols beyond the wall, into Nerech itself.","Roll one die:"],"tables":[{"cols":["Score","Result"],"rows":[["1–2","Thief steals one item from you (your choice)"],["3–4","Nothing happens"],["5–6","Find a manbeast's helmet"]]},{"cols":["Ref","Option"],"rows":[["e365","East into Nerech (The Plains of Howling Darkness)"],["e472","North west to Fort Estgard"],["e548","West into the farmlands"],["e466","South to Blessed Springs"]]}]},{"tag":"e260","title":"The Invulnerable Tomb Guardian","desc":["You are shocked to find that you cannot damage the tomb guardian at all! You have no choice but to run for the door.","Roll one die – if the result is less than or equal to your Rank, you make it back out into the Forest – turn to e047. Otherwise, the whirlwind guardian catches you and buffets you against the stone walls until you are dead – your adventures are over unless you have a resurrection deal."]},{"tag":"e261","title":"Renouncing the Worship of Maka","desc":["To renounce the worship of Maka, you must pay 15 💎 to the priesthood by way of compensation.","A man, lying on a pallet, groans, 'I renounced the goddess, and look at me now...' He is ravaged by disease.","Do you want to change your mind? If you are determined to renounce your faith, pay the 15 💎 and delete Maka from the God box on your Adventure Sheet. When you have finished here, turn to e141."]},{"tag":"e262","title":"Into the Burning Building","desc":["You charge into the burning building in search of the child's mother. You see her lying unconscious at the bottom of the stairs. Desperately, you try to get to her but a burning beam has fallen across your way and the smoke is making you choke.","Roll a die and subtract one from the result. If you score less than or equal to your Rank, turn to e546. Otherwise, turn to e133."]},{"tag":"e263","title":"The Gas-Breathing Beast","desc":["You are passing through a wooded glade when you hear a horrendous trumpeting noise. Suddenly, a massive bear-like form about the size of a large bull appears in front of you. It looks rather like a huge hairy toad, with a gaping, toothy mouth.","The creature breathes a billowing cloud of noxious, sulphurous gas at you. You feel your head swim as you start to fall asleep.","Roll one die and subtract one from the total. If the total is greater than your Rank, turn to e491. Otherwise, turn to e072."]},{"tag":"e264","title":"The Floating Reed Island","desc":["If there is a tick in the box, turn to e131. If not, put a tick there now, and read on.","A large island made of reeds and plants, which grow out of a massive floating bed of kelp, drifts aimlessly across the waters. As you draw near, you see that a number of people have made their home there. The inhabitants hail you and invite you ashore.","Turn to e537."]},{"tag":"e265","title":"A Cry from the Alley","desc":["If you have the title Unspeakable Cultist, turn to e404. If not, read on.","You hear a muffled cry of distress from a dark alley."],"tables":[{"cols":["Ref","Option"],"rows":[["e361","Investigate"],["e010","Walk on"]]}]},{"tag":"e266","title":"Disrespecting the Army","desc":["'You rebel swine,' slurs one of them. 'Not showing proper respect to the army,' says another. 'That can't go unpunished!'","They wade into you, intent on beating you into submission. Make a COMBAT roll at Difficulty 12."],"tables":[{"cols":["Ref","Result"],"rows":[["e076","Successful COMBAT roll"],["e498","Failed COMBAT roll"]]}]},{"tag":"e267","title":"Fishing on the Lake","desc":["You row out into the lake, spread the net, and wait to see what happens.","After an hour or so, a great bubbling and frothing of the lake disturbs your solitude. A massive scaly head, the size of your boat, erupts out of the ochre-coloured water on the end of a long, sinuous neck. Great luminous green eyes look down at you. The creature is covered in brown scales, with a bright red crest running from the head down its thick, ropy neck.","'I am Vayss the Sea Dragon,' it says in a rich, creamy voice, tinged with evil greed. 'To fish in my lake, you have to pay tribute – to wit, one silver nugget. Pay now, or face my wrath.'"],"tables":[{"cols":["Ref","Option"],"rows":[["e505","Hand over a silver nugget"],["e582","Unable or refuse to pay"]]}]},{"tag":"e268","title":"Overwhelmed by the Goblin-folk","desc":["The goblin-folk swarm over you. You try to put up a fight, but there are too many of them. Everything goes black.","You wake up, spluttering, face down on a beach! A wave has just soaked you. 'Going for a swim, are we?' asks an old woman who is gathering shells on the beach. You learn from her that a month has passed since your adventure in the faery mound, and you can remember none of it.","If you were wounded, you are now back to full Stamina. However, you realize you have lost all the money and items you were carrying. Cross them off your Adventure Sheet. Instead, you have a wolf pelt that you are wearing, some rat poison and a silver nugget. The old lady tells you that you are on the delta of the River Grimm.","Turn to e579."]},{"tag":"e269","title":"Hidden in the Shadows","desc":["You find a natural alcove in the wall of a tunnel. Desperately, you squeeze yourself into it, and fade into the shadows. The ratmen come bundling past, whooping and yelling. None of them spot you, and once they have gone you step out, smiling to yourself.","Turn to e580."]},{"tag":"e270","title":"Searching for Secret Panels","desc":["You make a swift inspection of the casements, walls and furnishings, searching for secret panels where treasure might be concealed. Make a THIEVERY roll at a Difficulty of 12."],"tables":[{"cols":["Ref","Result"],"rows":[["e059","Successful THIEVERY roll"],["e243","Failed THIEVERY roll"]]}]},{"tag":"e271","title":"The Pass of Eagles","desc":["You arrive at the Pass of Eagles, a thin chasm sliced right through the Spine of Harkun, as if Tyrnai himself had split the mountains with his sword.","A vast citadel has been built right across the southern end of the pass, bottling it up, so that none can travel into Sokara without passing through the castle. Its white walls and flag-topped towers shine brightly in the sunlight."],"tables":[{"cols":["Ref","Option"],"rows":[["e400","Enter the citadel (The Plains of Howling Darkness)"],["e003","Go to the western foothills"],["e244","The eastern foothills"],["e201","South on the road to Caran Baru"],["e518","Take the road to Fort Mereth"]]}]},{"tag":"e272","title":"The Chief Administrator's Rebuke","desc":["If you have the codeword Aloft, turn to e649 immediately. If not, read on.","The chief administrator is not happy to see you. 'What are you doing here?' he demands. 'You should be at Devil's Peak, north of here! The storm demons still threaten our city. Come back when you have succeeded.'","Turn to e100."]},{"tag":"e273","title":"Yellowport in Turmoil","desc":["You find the city is in turmoil. A rebel group, loyal to the old king, led an uprising against the army. Vicious fighting ensued and the streets ran with blood before the rebellion was brutally put down. Unfortunately, much damage was done during the battle. If you own a town house in Yellowport it has been looted – any possessions you may have cached there have gone.","Make a note of this paragraph number, turn to e300, cross off anything you had stored there, and return here to read on.","If you have the codeword Artefact and the Book of the Seven Sages, turn to e040. If not, turn back to e010 and choose from the options listed there."]},{"tag":"e274","title":"Spotted by the Dragon","desc":["Desperately, you try to sneak behind a pile of coins but the dragon spots you.","'A sneaky little thief, eh! Can't have that, oh no, not at all!' hisses the dragon, and it breathes a cloud of billowing acidic gas all over you. You watch in horror as the coins in front of you begin to melt, and then the cloud engulfs you.","If you have an amulet of protection, turn to e298. Otherwise, turn to e212."]},{"tag":"e275","title":"Blessing of Safety from Storms","desc":["If you are an initiate it costs only 5 💎 to propitiate the twin gods of the sea. A non-initiate must pay 20 💎. Cross off the money and mark Safety from Storms in the Blessings box on your Adventure Sheet.","The blessing works by allowing you to ignore any one storm at sea. When you use the blessing, cross it off your Adventure Sheet. You can only have one Safety from Storms blessing at any one time. Once it is used up, you can return to any branch of the temple of Alvir and Valmir to buy a new one.","Turn to e154."]},{"tag":"e276","title":"Wilderness of North-western Sokara","desc":["You are wandering across the wilderness of north-western Sokara. There is a magnificent castle nearby, with many different pennants flying from its towers."],"tables":[{"cols":["Ref","Option"],"rows":[["e611","Visit the castle"],["e123","Head west to the River Grimm"],["e003","Travel north to the mountains"],["e201","Head north-east"],["e110","Head east into the Bronze Hills"],["e047","Go south into the Forest of Larun"]]}]},{"tag":"e277","title":"Stopped by a Militia Patrol","desc":["A patrol of militiamen – mercenaries in the pay of the dictator, General Grieve Marlock – stop you in the street.","If you have the codeword Assassin, turn to e221 immediately.","If not, but you are a Protector of Sokara, they greet you politely and salute. You return to the city centre without incident – turn to e010.","Otherwise they decide you will be arrested unless you pay 15 💎 as 'taxes'. If you refuse, or don't have 15 💎, turn to e538. If you hand over the money, cross it off and the militiamen leave you alone – turn back to e010."]},{"tag":"e278","title":"Open Flinty Ground","desc":["You are crossing an open expanse of flinty ground. A few herds of sheep roam the low hills.","Roll a die:"],"tables":[{"cols":["Score","Result"],"rows":[["1–2","You get lost. Turn to e082."],["3–4","Nothing happens"],["5–6","A shepherd gives you a wolf pelt"]]},{"cols":["Ref","Option"],"rows":[["e427","To Venefax"],["e310","West to the Stinking River"],["e135","North to the lake"],["e087","East"]]}]},{"tag":"e279","title":"Sacrilege at the Temple of Tyrnai","desc":["What you have just done is probably a sacrilege, desecrating the Temple of Tyrnai, but you don't care. You sneak out of the temple unseen, and head back to town with your prize. Who else could have stolen something from right under the noses of the warrior priests of Tyrnai!","Turn to e400."]},{"tag":"e280","title":"Too Many Wolves","desc":["There are too many wolves to contend with. You withdraw before they get angry.","Turn to e003."]},{"tag":"e281","title":"An Unappreciative Audience","desc":["Your tale of valour and derring-do falls on an unappreciative audience. The mer-folk slip beneath the waves with snorts of derision, leaving you alone on the desolate beach. There is nothing for you to do but return to the clifftop tor."],"tables":[{"cols":["Ref","Option"],"rows":[["e602","Take the road to Trefoille"],["e166","Take the road to Marlock City"]]}]},{"tag":"e282","title":"The Temple of Tyrnai","desc":["If you have the codeword Armour, turn to e246 immediately. If not, read on.","The Temple of Tyrnai, the God of Battle, Chaos and Strife, is built like a small fortress in one corner of the city, near the barracks. Its heavy wooden gates are flanked by iron statues of bull-headed men wielding clubs. The workmanship is uncannily life-like. Inside, the god is represented by a stone idol of a jaguar-headed warrior. A beautiful suit of gold chain mail adorns the idol."],"tables":[{"cols":["Ref","Option"],"rows":[["e636","Become an initiate"],["e514","Renounce worship"],["e107","Seek a blessing"],["e033","Make resurrection arrangements"],["e400","Leave the temple"]]}]},{"tag":"e283","title":"The Ghost Banquet","desc":["'What goes on here?' you ask. 'Why do you behave so oddly?'","The villagers seem quite frightened of you, but one old fellow has nerve enough to reply. 'This banquet is for the ghosts of three travellers who lost their way in a storm, fell into our millpond and were drowned.'","'When was this?' you ask. 'Seven years since. They come every year on this night, and if we didn't placate them with victuals and treasure, there'd be a mess of trouble.'","'How do you know that?' 'Old Megan told us,' he says. 'She knows much about such things.'"],"tables":[{"cols":["Ref","Option"],"rows":[["e590","Stay out at night and watch for the ghosts"],["e576","Follow the river north"],["e082","Follow the river south"],["e278","Head east into the countryside"],["e558","Go west to the main road"]]}]},{"tag":"e284","title":"Tripping the Wire","desc":["You find an open window and squeeze through into a long hall. Your foot, however, snags on a thin wire stretched across the floor. The wire triggers a loud bell-like gonging that alerts the temple. You have little choice but to run for your life – warrior priests swarm out of the temple and the iron statues at its gates come to life to join in the chase.","Roll a die, and subtract one from the total. If the result is less than or equal to your Rank, turn to e395. Otherwise, turn to e551."]},{"tag":"e285","title":"The Greatest Story Ever Told","desc":["You remember a bard in a tavern told you about Damor the Hermit, and that he knew the secret of the Greatest Story Ever Told, so you ask him about it.","'Ahh,' says Damor. 'I have waited for one such as you.' He tells you the secret of the Greatest Story. 'Well, my young adventurer, destiny beckons, for it is fated that your life will be the Greatest Story Ever Told.'","As you consider this, you feel a sense of momentary enlightenment. Gain one Rank and roll one die. The result is the number of Stamina points you gain permanently. Also, don't forget to increase your 🛡️ by 1 as a result of your gain in Rank.","'Right, that's that,' says Damor. 'Now, go away and don't come back!'","For a few hours, he lifts the curse that soured your water so you can make it down again safely. Turn to e244."]},{"tag":"e286","title":"Helping the Sokarans","desc":["When you and your crew join the fray, the battle is short-lived. The pirates are overpowered, though they fight to the last man, preferring death to enslavement or execution. The Sokaran leader, an admiral in the navy, thanks you gravely for your help.","He rewards you with a share of the pirates' booty – you get 400 💎 and 1 Cargo Unit of spices, if you have room for it in your ship's hold.","You sail on. Turn to e420."]},{"tag":"e287","title":"The Gorlock Emerges","desc":["You wait for an hour. At dusk, something emerges. It is the gorlock, a beast with legs like a bird, a body like a reptile, with two short forelimbs and a beaked, lizard-like head. You see that its two legs do have backward-pointing feet. The beast heads off into the hills, and you creep forwards.","Turn to e315."]},{"tag":"e288","title":"Dead in an Alleyway","desc":["You end dead in an alleyway with your throat cut. Your adventures are over, unless you have a resurrection deal."]},{"tag":"e289","title":"The Gods Do Not Answer","desc":["There is a pause, as if you are both waiting for something to happen. You realize the gods have not heard your prayer, as does your enemy. It snarls triumphantly, and slashes you across the chest. Lose 2 ❤️. If you still live, you have no choice but to fight it.","Turn to e290."]},{"tag":"e290","title":"The Merchants' Guild","desc":["If you have the codeword Cutlass, turn to e403 immediately. If not, but you have the codeword Amcha, turn to e512. Otherwise read on.","The guildmaster, a tall gaunt man, welcomes you. 'The guild, in Golnir and Sokara, is plagued by privateers on the high seas. Amcha One-eye is the worst of these lawless dogs – he has cost us thousands of Shards! Bring me the head of Amcha One-eye, and I will reward you! He and his cut-throat crew operate from the Unnumbered Isles – now called the Kingdom of the Reavers because of the pirates who have made their base there. The isles lie to the south.'","If you want to take up the quest, note the codeword Amcha. When you are ready, turn to e100."]},{"tag":"e291","title":"Becoming an Initiate of Elnir","desc":["Becoming an initiate of Elnir gives you the benefit of paying less for blessings and other services the temple can offer. It costs 60 💎 to become an initiate. You cannot become an initiate of Elnir if you are already an initiate of another temple.","If you choose to become an initiate, write Elnir in the God box on your Adventure Sheet and remember to cross off the 60 💎.","Once you have finished here, turn to e316."]},{"tag":"e292","title":"The Local Market at Cadmium","desc":["The local market is very small – only two commodities are available for trade.","When you are finished, turn back to e135."],"tables":[{"cols":["Item","Buy","Sell"],"rows":[["Smoulder fish","60 💎","55 💎"],["Silver nugget","165 💎","150 💎"]]}]},{"tag":"e293","title":"Rescuing the Merchantman","desc":["The merchantman has suffered a lot of damage, and the remaining crewmen are half dead with thirst. You give them water and help to repair the ship. The captain, a woman dressed in multi-coloured feather robes and an ornate head-dress, is most grateful. She tells you her name is Moon of Evening and that she comes from Smogmaw, the city at the Misty Estuary, in far-off Ankon-Konu. She tells you to visit her, if you are ever in Smogmaw, so that she can repay the debt.","Note the codeword Aid. You sail on. Turn to e559."]},{"tag":"e294","title":"Becoming an Initiate of Alvir and Valmir","desc":["Becoming an initiate of Alvir and Valmir gives you the benefit of paying less for blessings and other services the temple can offer. It costs 40 💎 to become an initiate. You cannot do this if you are already an initiate of another temple.","If you choose to become an initiate, write Alvir and Valmir in the God box on your Adventure Sheet and remember to cross off the 40 💎.","Once you have finished here, turn to e220."]},{"tag":"e295","title":"Outrunning the Scorpion Men","desc":["The scorpion men cannot keep up with you, and you leg it all the way back to the road. Maybe you can come back and try again later.","Turn to e492."]},{"tag":"e296","title":"MAGIC Roll","desc":["Make a MAGIC roll at Difficulty 9."],"tables":[{"cols":["Ref","Result"],"rows":[["e494","Successful MAGIC roll"],["e352","Failed MAGIC roll"]]}]},{"tag":"e297","title":"The Dragon Knight Tournament","image":true,"desc":["Decide which armour and weapon you will use in the fight. They will be the ones you are betting with.","Roll a die and check the table below. The result is the knight you must fight.","Because it is not a duel to the death, your weapons are padded, so any Stamina you lose is not permanent – it is recovered after the fight.","If you win, turn to e019. If you are reduced to 0 ❤️, you pass out, turn to e370."],"tables":[{"cols":["Score","Knight","⚔️","🛡️","❤️"],"rows":[["1–2","Blue Dragon","3","8","6"],["3–4","Green Dragon","4","8","8"],["5–6","Red Dragon","5","8","10"]]}]},{"tag":"e298","title":"The Amulet of Protection Saves You","desc":["The amulet of protection dissolves in a flash of smoke – cross it off your Adventure Sheet.","It does protect you, however, and you are obscured by the smoke long enough to get into hiding. The amulet leaves a residue of yellow powder, which the dragon thinks is all that is left of you. He scoops it up and puts it into a bottle, beside the others on his rocky shelf.","Turn to e016."]},{"tag":"e299","title":"Fort Mereth","desc":["Fort Mereth, named after an ancient hero, is the northernmost of the forts that guard Sokara from the ravening manbeasts of Nerech. A fortified wall stretches right across the peninsula.","Roll a die:"],"tables":[{"cols":["Score","Result"],"rows":[["1–2","Get in a fight with a drunken soldier. If you win, you can take his axe."],["3–4","Nothing happens"],["5–6","Opportunity to buy a mandolin (CHARISMA +1) for 100 💎"]]},{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Soldier","4","6","7"]]},{"cols":["Ref","Option"],"rows":[["e020","East into Nerech (The Plains of Howling Darkness)"],["e472","South east to Fort Estgard"],["e548","South into the farmlands"],["e458","West on the road to Caran Baru"],["e518","West on the road to the citadel"]]}]},{"tag":"e300","title":"Your Town House in Yellowport","desc":["You can leave possessions and money here to save having to carry them around with you. You can also rest here safely and recover any Stamina points you have lost. Record in the box anything you wish to leave.","Each time you return, roll two dice:","Turn to e010."],"tables":[{"cols":["Score","Result"],"rows":[["2–9","Your possessions are safe"],["10–11","A thief. All the money left here has gone"],["12","Burglars! Lose all the possessions you have left here"]]}]}]`),h=JSON.parse(`[{"tag":"e301","title":"Passage to the Isle of Druids","desc":["A barque, heading for the Isle of Druids to buy furs, is prepared to take you. Cross off 15 💎. The journey, across the Sea of Whispers, is uneventful, and you dock at the Trading Post on the island a week or so later.","Turn to e195."]},{"tag":"e302","title":"Exploring Yellowport","desc":["You can explore:"],"tables":[{"cols":["Ref","Option"],"rows":[["e093","The poor quarter"],["e587","The harbour area"],["e277","The area around the palace"]]}]},{"tag":"e303","title":"Trapping the Ghoul with Salt and Iron","desc":["Cross the salt and iron filings from your Adventure Sheet. As fast as you can, you lay out a line of powder in front of you. The ghoul gives a moaning wail and shrinks back, unable to cross the line of salt and iron filings. Quickly you run around the ghoul, encircling it with the powder. The creature lunges for you but it cannot cross the line – you keep it at bay at every turn. Soon it is completely trapped.","Casually, you sit on a tombstone and wait for sunrise. When it comes, the ghoul is burnt to a crisp. You take the rotting, charred head and make your way back into town.","Note you have a ghoul's head and turn to e100."]},{"tag":"e304","title":"The Man with the Eyepatch","desc":["He spots you before you can get the jump on him. 'Stinking assassin!' he yells, drawing his sword. You must fight him.","If you win, turn to e092. If you lose, he kills you, and your adventuring days are over, unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Man with eyepatch","5","8","12"]]}]},{"tag":"e305","title":"Attempting to Steal the Chain Mail","desc":["If there is a tick in the box, turn to e367 immediately. If not, put a tick there now, and read on.","Make a MAGIC roll at Difficulty 11."],"tables":[{"cols":["Ref","Result"],"rows":[["e609","Successful MAGIC roll"],["e528","Failed MAGIC roll"]]}]},{"tag":"e306","title":"The Enchanted Pebbles","desc":["Something doesn't feel right about the pearls. You realize a minor enchantment has been put on them – they are in fact tiny pebbles, made to look like pearls. You squeeze them in the palm of your hand, and they revert to their natural state.","'By the twin gods!' exclaims the young man. 'Look at that! They were pebbles all along!'","You stare at him for a long while, fingering your weapon. The Sea Gypsy shifts uneasily from foot to foot, coughing nervously, and hands you another bag of pearls. This time you are sure they are real. Note the bag of pearls on your Adventure Sheet.","You take your leave and resume your journey. Turn to e085."]},{"tag":"e307","title":"Lost in the Music","desc":["It feels like you are playing the flute for an eternity. But at last they tire of your music...","You wake up with a scream. You realize you are not aboard your ship! You find out that you are in the temple of Alvir and Valmir in Yellowport. A priest tells you that your crew brought you here three months ago because they could not wake you from your sleep.","Your ship and crew are long gone now – note that you no longer own a ship. The priests, however, have been looking after all your possessions. Among them is a silver flute (CHARISMA +2). While you have the flute, it adds 2 to your CHARISMA. Note that it is worth 500 💎 and that you can sell it at any market if you like.","You leave the temple. Turn to e010."]},{"tag":"e308","title":"Beaten by the Ratmen","desc":["The ratmen beat you into unconsciousness, and then toss you down an underground sewer outlet. You are washed up on the beaches outside Yellowport, where you come to. You have 1 ❤️ left, and the ratmen have taken all the items and money that you were carrying. Cross them off your Adventure Sheet.","Groggily, you make your way back into the city. Turn to e010."]},{"tag":"e309","title":"Crossing the Pentacle","desc":["As you move closer to the sarcophagus, your foot crosses the edge of the pentacle by a few millimetres – it is enough. The lid of the sarcophagus explodes into the air with a deafening crash, and a pillar of black smoke erupts from the stone coffin! The smoke hurtles towards you, like a miniature tornado.","You must fight the tomb guardian. If you have a weapon with a ⚔️ bonus of +1 or greater, turn to e043. Otherwise, turn to e260."]},{"tag":"e310","title":"The Village of High Therys","desc":["If there is a tick in the box, turn to e614 immediately. If not, read on.","The Stinking River has cut its way through the high ground here. On the edge of the chasm that overlooks the river lies the village of High Therys.","The locals are behaving very oddly. You watch the villagers lay out a fine feast on the village green. A pig is set roasting on a spit, loaves of freshly baked bread are piled beside bowls overflowing with fruits, butter and cheese. Lastly, the richest merchants of the village bring coffers full of silver which they set beside the table. To your amazement, instead of sitting down to dine, the villagers then scurry home and start closing the shutters on their windows.","Turn to e283."]},{"tag":"e311","title":"Refusing the Sokaran Inspection","desc":["He narrows his eyes angrily at your refusal. If your ship is a galleon and you have a good or excellent crew, turn to e335 immediately. If not, read on.","'In that case, I have no choice but to seize your ship!' More of his men swarm on to your ship, and a battle ensues.","Roll three dice if you are a Warrior, or two dice if you belong to any other profession. Add your Rank to this roll. If the crew is poor quality, subtract 2 from the total. If the crew is good, add 2; if it is excellent, add 3."],"tables":[{"cols":["Ref","Score","Result"],"rows":[["e680","0–4","Calamity. You are killed"],["e153","5–9","Crushing defeat. Lose 1–6 ❤️"],["e242","10–13","A draw"],["e062","14+","Outright victory"]]}]},{"tag":"e312","title":"Coastal Waters of Nerech","desc":["'Nerech's a dangerous place – even its coastal waters, Cap'n,' says the first mate. 'The crew won't follow you there if they don't think you're good enough to lead them!'","If your Rank is 4 or more, turn to paragraph e050 in The Plains of Howling Darkness.","If your Rank is less than 4, the first mate advises you against making the ocean journey. If you take his advice, turn to e507.","If you insist on making the trip, you need to make a CHARISMA roll at Difficulty 11 to convince the crew to follow you."],"tables":[{"cols":["Ref","Result"],"rows":[["e050","Successful CHARISMA roll"],["e507","Failed CHARISMA roll"]]}]},{"tag":"e313","title":"The Ordeal of the Silver Daggers","desc":["You stand against the wall as the high priestess draws back her arm, and hurls a stream of daggers at you. Roll two dice. If the total is higher than your 🛡️, a dagger hits you and you lose 1–6 ❤️ (roll a die to see how many). If the two dice score less than or equal to your 🛡️, the daggers all miss.","Either way, if you survive then you are free to leave. Delete Lacuna from the God box on your Adventure Sheet and turn to e400."]},{"tag":"e314","title":"Runes Mean Nothing","desc":["The runes mean nothing to you."],"tables":[{"cols":["Ref","Option"],"rows":[["e097","Go down to the beach"],["e602","Take the road to Trefoille"],["e166","Take the road to Marlock City"]]}]},{"tag":"e315","title":"The Gorlock's Lair","desc":["With the gorlock out of the way, you are free to investigate its lair. Inside the cave, you find 500 💎, a mace and a silver nugget.","Turn to e510."]},{"tag":"e316","title":"The Temple of Elnir","desc":["The temple of Elnir is an imposing edifice of grey stone, inlaid with yellow marbling. Elnir is the god of the sky and of kingship. He is the ruler of the gods.","'His dreams are the clouds before a storm,' says a passing priest."],"tables":[{"cols":["Ref","Option"],"rows":[["e291","Become an initiate of Elnir"],["e143","Renounce his worship"],["e388","Seek a blessing"],["e010","Leave the temple"]]}]},{"tag":"e317","title":"The Familiar Craft","desc":["It is the same craft you got the MAGIC spear from, with the silver-skinned demon inside – still dead you presume. You examine it again, but there is nothing else of interest on board. The figure still lies there unmoving.","You sail on. Turn to e085."]},{"tag":"e318","title":"The Scorpion Man","desc":["A scorpion man scuttles out of the brush to confront you. It resembles a huge scorpion, but with a human head and torso. It holds a sword and shield in its human arms. The creature's eyes blaze with an unearthly yellow light, and it scrabbles towards you with frightening speed, whipping its sting up and around at you. You must fight it.","If you win, turn to e657. If you lose, you are finished, unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Scorpion Man","3","6","8"]]}]},{"tag":"e319","title":"The Willow Staff Delivered","desc":["You give the willow staff to the Oak Druid of the City of Trees. Cross the willow staff off your Adventure Sheet.","'Ah, thank you,' the druid intones, going on, 'a willow staff, eh? I see.'","As a reward, the druid lets you train with the City of Trees' best hunters and trackers. Gain 1 Rank, and roll one die. The result is the number of Stamina points you gain permanently. Also, don't forget to increase your 🛡️ by 1 as a result of your gain in Rank.","When you are ready, you leave the City of Trees and return to the Trading Post. Turn to e195."]},{"tag":"e320","title":"Prisoners of the Cult","desc":["You learn from their conversations that they are from the jungles of distant Ankon-Konu, the Feathered Lands, and that they have come here to find new sacrifices for their god, and new members for their cult. The chef pronounces the cauldron is ready, and they remove the net that holds you."],"tables":[{"cols":["Ref","Option"],"rows":[["e204","Fight"],["e101","Shout 'Badogor!' repeatedly"],["e061","Join their cult"]]}]},{"tag":"e321","title":"The Black Dragon Knight","desc":["The Black Dragon Knight comes out to meet you. His armour is of black steel, and you think you can see glowing red eyes through the slits in his full-face helm. You must fight him.","If you win, turn to e417. If you lose, you are dead, unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Black Dragon Knight","5","9","11"]]}]},{"tag":"e322","title":"Recognized Undersea","desc":["The repulsive one recognizes you from your last undersea trip!","Turn to e238."]},{"tag":"e323","title":"The Gorlock's Lair on the Hill","desc":["A few locals are discussing recent events – it seems some hideous beast has made its lair in a cave on the hill that overlooks the village.","'It's a gorlock,' says a farmer. 'And it's amassed quite a bit of treasure by all accounts – lifted from its victims. A brave adventurer like yourself could get rich if you killed it. You'd be doing us a favour as well.'","You ask what a gorlock looks like, but no one knows. 'Nobody's come back to tell the tale!' says the innkeeper.","You leave the tavern. Turn to e510."]},{"tag":"e324","title":"Storm at Sea","desc":["Heavy black clouds race towards you across the sky, whipping the waves into a frenzy. The crew mutter among themselves fearfully. If you have the blessing of Alvir and Valmir, which confers Safety from Storms, you can ignore the storm. Cross off the blessing and turn to e559.","Otherwise the storm hits with full fury. Roll one die if your ship is a barque, two dice if it is a brigantine, or three dice if a galleon. Add 1 to the roll if you have a good crew; add 2 if you have an excellent crew."],"tables":[{"cols":["Ref","Score","Result"],"rows":[["e607","1–3","Ship sinks"],["e083","4–5","The mast splits"],["e559","6–20","You weather the storm"]]}]},{"tag":"e325","title":"Ship Lost to the Deep","desc":["Your ship, crew and cargo are lost to the deep, dark sea. Cross them off your Adventure Sheet. Your only thought now is to save yourself.","Roll two dice. If the score is greater than your Rank, you are drowned – turn to e680. If the score is less than or equal to your Rank, you manage to find some driftwood and make it back to shore. Lose ❤️ points equal to the score of one die and, if you can survive that, turn to e173."]},{"tag":"e326","title":"Unmasking Old Megan","desc":["You follow the footprints to the mill, where you see an old lady and two men brushing flour off their clothes. 'Another successful year's haunting!' laughs the woman.","Quietly you creep back and tell the villagers what you have discovered. Brimming with outrage, they go straight to the mill and seize the three miscreants.","'Old Megan!' cries one of the villagers when he sees who is the ringleader of the three. 'So, you've been masquerading as a ghost for these seven years, eh? Well, tomorrow we'll take you to the gallows and then you can play the part for real.'","Turn to e671."]},{"tag":"e327","title":"Secret Cache in Yellowport","desc":["You have already cleaned the ratmen out of the tunnels below the city but the old well will make a good cache for equipment and money that you don't want to carry with you. It has an advantage over a town house – there is no risk of burglary or fire. You may also rest here as long as you like, restoring any lost ❤️ points.","Note 'Secret cache, Yellowport – The War-Torn Kingdom e327' on your Adventure Sheet so that you can come here whenever you are in Yellowport.","To go back to the city above, turn to e010."]},{"tag":"e328","title":"Searching for the Ghoul","desc":["You are not sure where to start looking for the ghoul, so you wander around, looking for stories, strange murders – anything that might put you on its trail.","Make a SCOUTING roll at Difficulty 12."],"tables":[{"cols":["Ref","Result"],"rows":[["e419","Successful SCOUTING roll"],["e360","Failed SCOUTING roll"]]}]},{"tag":"e329","title":"No Sign of the Black Dragon Knight","desc":["'Still haven't found him?' he says. 'Did you try the Castle of the Dragon Knights to the west of the Bronze Hills?' As he turns and leaves, he says, 'When you have better tidings, I will return here.'","You follow him, but he is nowhere to be seen. Turn to e400."]},{"tag":"e330","title":"Through the Archway to Wishport","desc":["You must have Cities of Gold and Glory before you can travel to Wishport. Turn back to e192 and choose again if you do not have this book. Otherwise, read on.","You step through the archway. Immediately the symbols on the stone begin to glow with red-hot energy; your hair stands on end and your body tingles. A crackling nimbus of blue-white force engulfs you, the sky darkens and rumbles, thunder and lightning crash and leap across the heavens. Suddenly, your vision fades, and everything goes black.","When your sight returns, moments later, you find yourself at the gates of Wishport. You join the throng of merchants and peasants making their way into the city. Turn to e217 in Cities of Gold and Glory."]},{"tag":"e331","title":"The Book of the Seven Sages","desc":["If there is a tick in the box, turn to e627 immediately. If not, put a tick there now and read on.","You fall into conversation with Pyletes, a kindly old scholar-priest of Molhern, the God of Knowledge.","'Many years ago, the Book of the Seven Sages was stolen from us,' he croaks. 'News suggests that the scorpion men are in possession of it. I need a young adventurer like yourself to travel to Scorpion Bight and return the book to me. In return I can show you how to improve the skill of your choice.'","If you take up the quest, gain the codeword Artefact. Now turn back to e010."]},{"tag":"e332","title":"The Trading Post Quayside","desc":["The quayside at the Trading Post is a simple affair, without the harbour facilities or the shipwrights of the larger ports. There are no ships available to buy here, but if you already own a ship, you can buy and sell cargo.","Prices are for single Cargo Units. Fill in your current cargo on the Ship's Manifest.","You can buy a one-way passage to Yellowport from here at a cost of 15 💎 – turn to e074.","If you own a ship and wish to set sail, turn to e155. If not, turn to e195."],"tables":[{"cols":["Cargo","Buy","Sell"],"rows":[["Furs","135 💎","130 💎"],["Grain","220 💎","210 💎"],["Metals","600 💎","570 💎"],["Minerals","400 💎","310 💎"],["Spices","900 💎","820 💎"],["Textiles","325 💎","285 💎"],["Timber","120 💎","100 💎"]]}]},{"tag":"e333","title":"East Bank of the River Grimm","desc":["You are on the east bank of the River Grimm.","Roll one die:"],"tables":[{"cols":["Score","Result"],"rows":[["1–2","A water sprite curses you – lose a Blessing, if you have one"],["3–4","Nothing happens"],["5–6","Catch a smoulder fish while fishing"]]},{"cols":["Ref","Option"],"rows":[["e099","Cross to the west bank (Cities of Gold and Glory)"],["e047","Head east into the Forest of Larun"],["e123","Follow the river north"],["e099","Follow the river south"]]}]},{"tag":"e334","title":"Renouncing the Worship of Lacuna","desc":["To renounce the worship of Lacuna, you must pay 40 💎 in compensation to the shrine.","'If you forsake the love of the goddess, you will never survive the rigours of the wilderness,' warns the priestess.","If you still want to renounce the worship of Lacuna, cross off the 40 💎 and delete Lacuna from the God box on your Adventure Sheet.","When you are finished, turn to e195."]},{"tag":"e335","title":"The Captain Backs Down","desc":["The captain eyes your crew and your marines. They are a tough-looking lot, seasoned sailors and veterans of quite a few battles at sea.","'Bah!' he exclaims, 'It's not worth the trouble. I'll let it pass this time.'","With that, he returns to his ship and departs. Turn to e439."]},{"tag":"e336","title":"Bluffing Your Way In","desc":["You step in, saying, 'I have a message for King Skabb...' The ratmen stare at you in amazement.","'A human! Get it!' screams Skabb.","The four ratmen charge toward you with a roar, wielding swords, before you can say anything more. Soon they have been joined by many others and you have little choice but to turn and flee for your life! Desperately, you race down the sewer tunnels, with an army of ratmen in hot pursuit."],"tables":[{"cols":["Ref","Option"],"rows":[["e079","Lose them in the tunnels"],["e296","Try some MAGIC"],["e127","Hide"]]}]},{"tag":"e337","title":"The Sea Centaur in the Net","desc":["If there is a tick in the box, turn to e037 immediately. If not, put a tick there now and read on.","The crew have been using a net to catch fish. This time they have caught a sea centaur, a strange-looking creature, with a top half like a man, and a bottom half like a sea horse. It struggles feebly, clutching at the net with webbed fingers, trying to saw it apart with a long, serrated dagger made of some sea shell.","'We'll have to kill it, Cap'n – they're terrible bad luck to have on board,' says the first mate. One of the sailors is already readying his cutlass."],"tables":[{"cols":["Ref","Option"],"rows":[["e522","Give the order to kill it"],["e604","Spare it"]]}]},{"tag":"e338","title":"The Healer of Venefax","desc":["You climb down the ladder into a house with herbs and plants hanging on the walls, and shelves lined with pots, pans and bottles of all sorts. The healer, an old woman, can cure you of poison but is unable to cure disease, lift curses or heal wounds. It will cost you 25 💎 to get cured, if you are poisoned. If you pay, you can restore all of your affected abilities to normal.","When you are ready, turn back to e427."]},{"tag":"e339","title":"Ashes from a Sorceress's House","desc":["You find a burned-out house in the poor quarter where a trader has set up a stall, selling ash and debris. The merchant, a weaselly-looking old woman, is screeching, 'Ashes, ashes from the house of a sorceress! Fifteen Shards a packet!'","If you want to buy some, cross off 15 💎 and note the ashes on your Adventure Sheet. When you are ready, you head back to the centre of the town. Turn to e100."]},{"tag":"e340","title":"Climbing to Devil's Peak","desc":["Make a SCOUTING or THIEVERY roll at Difficulty 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e239","Successful SCOUTING or THIEVERY roll"],["e034","Failed SCOUTING or THIEVERY roll"]]}]},{"tag":"e341","title":"Rumours at the Blue Griffon","desc":["You hear an interesting story about one of Baroness Ravayne's knights, in Golnir. Apparently he is plotting against her!","'Intrigue and treachery in the court of the baroness...' mutters a man before his voice fades to a whisper.","You leave the tavern. Turn to e400."]},{"tag":"e342","title":"The Alchemist's Shop","desc":["The alchemist's shop is lined with potions, jars of exotic substances, herbs, and so on. Alembics and beakers bubble and boil, full of strangely-coloured liquids. The alchemist, a tall, gangly fellow with a beak of a nose, sells potions. You can buy as many as you can afford – each one costs 50 💎.","A potion can be used just before an ability roll or a fight to add 1 to the relevant ability for that one roll or fight only. Each potion can be used only once.","The alchemist can make you a special potion for 250 💎, but he needs an ink sac. If you pay the money, and have an ink sac (cross it off your Adventure Sheet) he will make you a potion of restoration. It can be used only once to heal all lost ❤️ points, cure poison and disease.","Turn to e510."],"tables":[{"cols":["Potion","Effect","Cost"],"rows":[["Potion of strength","⚔️ +1","50 💎"],["Potion of comeliness","CHARISMA +1","50 💎"],["Potion of intellect","MAGIC +1","50 💎"],["Potion of godliness","SANCTITY +1","50 💎"],["Potion of stealth","THIEVERY +1","50 💎"],["Potion of nature","SCOUTING +1","50 💎"],["Potion of restoration (needs ink sac)","Heals all ❤️, cures poison and disease","250 💎"]]}]},{"tag":"e343","title":"Becoming an Initiate of Alvir and Valmir","desc":["Becoming an initiate of Alvir and Valmir gives you the benefit of paying less for blessings and other services the temple can offer. It costs 40 💎 to become an initiate. You cannot become an initiate of Alvir and Valmir if you are an initiate of another temple.","If you choose to become an initiate, write Alvir and Valmir in the God box on your Adventure Sheet and cross off the 40 💎.","Turn to e154."]},{"tag":"e344","title":"Slaying the Governor","desc":["You must make either a COMBAT or a MAGIC roll at Difficulty 14 to slay him. If you fail the roll, turn to e161 immediately. If you are successful, read on.","You cut him down, or enchant him so that he obeys your every command and falls on his own sword. Note the codeword Assassin.","Hurriedly, you flee the palace. Turn to e216."]},{"tag":"e345","title":"A Wrecked Ship","desc":["A ship, impaled on some rocks, is breaking up. Nothing remains save for rotten timbers. However, a little bottle is bobbing in the waves. Inside, a message reads, 'Never sail at night through rocky waters.'","You sail on. Turn to e209."]},{"tag":"e346","title":"Ship Lost to the Deep","desc":["Your ship, crew and cargo are lost to the deep, dark sea. Cross them off your Adventure Sheet. Your only thought now is to save yourself.","Roll two dice. If the score is greater than your Rank, you are drowned – turn to e680. If the score is less than or equal to your Rank, you manage to find some driftwood and make it back to shore. Lose ❤️ points equal to the score of one die roll and, if you can survive that, turn to e453."]},{"tag":"e347","title":"A Congested Road","desc":["The road is nearly blocked by wagons and supply convoys. A troop of soldiers forces its way through the throng – the men bang heads indiscriminately to clear people out of the way.","Roll a die:"],"tables":[{"cols":["Score","Result"],"rows":[["1–2","Banged on the head! Lose 1 ❤️"],["3–4","Nothing happens"],["5–6","Mistaken for a beggar – receive 10 💎 from a passing priest"]]},{"cols":["Ref","Option"],"rows":[["e400","North to Caran Baru"],["e474","East into the Coldbleak Mountains"],["e387","South along the road"],["e047","West into the Forest of Larun"]]}]},{"tag":"e348","title":"Paralysing the Creatures with Seaweed Sap","desc":["You remember what the fishermen say – the root of a certain seaweed, when crushed, gives off a cloud of toxic fluid. This sap is harmless to humans but is known to paralyse marine creatures for a short while. Fortunately, the seaweed grows in abundance here. You swim down with a handful of the roots, squeezing its sap into the waters. The hideous creatures shoot towards you, but are paralysed the instant they enter the cloud of reddish fluid that billows around you.","You take the golden net (note it on your Adventure Sheet) and swim back to the Shadar Tor as fast as you can."],"tables":[{"cols":["Ref","Option"],"rows":[["e602","Take the road to Trefoille"],["e166","Take the road to Marlock City"]]}]},{"tag":"e349","title":"Escaping into the Backstreets","desc":["You are too fast to get caught, and run off into the shadowy backstreets of Caran Baru. Cursing your luck, you consider your next move.","Turn to e400."]},{"tag":"e350","title":"Resurrected at the Temple of Nagil","desc":["You are restored to life at the Temple of Nagil in Marlock City. Your ❤️ is back to normal score. The possessions and cash you were carrying at the time of your death are lost – cross them off your Adventure Sheet. Also remember to delete the entry in the Resurrection box now it has been used.","'Nagil has taken you from the barge of souls that sails to the lands of the dead, and returned you to us,' declares the high priest.","You leave the temple. Turn to e100."]},{"tag":"e351","title":"Lauria in the Mines","desc":["One day, a new slave is brought in to work beside you. Much to your astonishment, it is Lauria, the thief who left you in the lurch when you burgled a wizard's house in Yellowport.","'Sorry about the last time,' she says, 'Business – you know. Now's my chance to make it up to you.'","She explains that she has discovered an escape route. This time, she promises to set up a diversion while you make for a tunnel where a cave-in has left an opening to the outside. Lauria says she will meet you later."],"tables":[{"cols":["Ref","Option"],"rows":[["e662","Go along with her plan"],["e565","Escape on your own"]]}]},{"tag":"e352","title":"A Botched Disguise Spell","desc":["You mutter an enchantment that is intended to give you the appearance of a ratman but you get some of the intricate syllables wrong, and take on the appearance of a particularly wealthy merchant! At the sight of you, the ratmen redouble their efforts, and you are overwhelmed by sheer numbers.","Turn to e308."]},{"tag":"e353","title":"Recognized as a Traitor","desc":["The guard recognizes you, and shouts at the top of his lungs, 'It's the stinking traitor who killed Nergan. Get him!'","Several archers pop up from behind the rocks overhead and start shooting at you. An arrow embeds itself in your shoulder. Lose 3 ❤️. If you still live, you realize you made a bad mistake in coming back here, and you run for your life. As you climb down, you are shot at again.","Roll a die:"],"tables":[{"cols":["Score","Result"],"rows":[["1–2","You are hit twice, lose 6 ❤️"],["3–4","Hit once, lose 3 ❤️"],["5–6","Missed completely, no wounds"]]}],"note":["After that, if you are still alive, you make it back to the foothills of the mountains. Turn to e474."]},{"tag":"e354","title":"The Curse Lifted","desc":["You throw, muttering a prayer for forgiveness to the gods. The weapon soars through the air. It turns, and catches the sunlight, sparkling like a flashing star, before sinking beneath the water with barely a splash. No ripples appear. Your heart feels uplifted, and the curse is no more!","Delete the curse and its effects, and lose the codeword Appease. Turn to e378."]},{"tag":"e355","title":"Investment Returns","desc":["To find out how well your investments have done, roll two dice. Add 1 to the dice roll if you are an initiate of the Three Fortunes. Also add 1 if you have the codeword Almanac, add 2 if you have the codeword Brush, and add 3 if you have the codeword Eldritch."],"tables":[{"cols":["Score","Result"],"rows":[["2–4","Lose entire sum invested"],["5–6","Loss of 50%"],["7–8","Loss of 10%"],["9–10","Investment remains unchanged"],["11–12","Profit of 10%"],["13–14","Profit of 50%"],["15–16","Double initial investment"],["17+","Triple initial investment"]]}],"note":["Now turn to e046, where you can withdraw or leave the sum written in the box there after adjusting it according to the result rolled."]},{"tag":"e356","title":"The Willow Druid's Sacred Grove","desc":["You are pious enough to be allowed to enter the sacred grove. You step in and knock on the door. A kindly old druid opens the door and greets you.","You hand him the oak staff (cross it from your Adventure Sheet). 'Thank you!' says the druid, 'An oak staff, eh! That's an interesting message, to be sure.'","He hands you 50 💎 as payment and a willow staff, saying, 'Please take this staff to the Oak Druid in the City of Trees, on the Isle of Druids – I'm sure he'll reward you, too. Good day, and thanks again!'","With that he shuts the door. You head back into the forest. Turn to e047."]},{"tag":"e357","title":"The Ghostly Feast","desc":["The moon begins to rise, making the ghosts seem to glow. They sit hunched over their feast like vultures, occasionally stirring their hands in the pile of silver coins and tittering eerily."],"tables":[{"cols":["Ref","Option"],"rows":[["e023","Confront them"],["e541","Stay hidden and follow when they leave"]]}]},{"tag":"e358","title":"The City of Trees","desc":["'Welcome to the City of the Trees,' says a passing woman, dressed in the garb of a druid. The city has been built amid the branches of several mighty oaks. Ladders run up and down the trees to houses that perch like nests in the branches. You are not allowed into any houses, but the druids allow you to barter at the market.","Items with no purchase price are not available locally."],"tables":[{"cols":["Armour","Buy","Sell"],"rows":[["Leather (🛡️ +1)","50 💎","45 💎"],["Ring mail (🛡️ +2)","–","90 💎"]]},{"cols":["Weapons"," Buy","Sell"],"rows":[["No ⚔️ bonus","50 💎","40 💎"],["⚔️ bonus +1","250 💎","200 💎"]]},{"cols":["Magical Equipment","Buy","Sell"],"rows":[["Amber wand (MAGIC +1)","500 💎","300 💎"],["Ebony wand (MAGIC +2)","1000 💎","800 💎"],["Cobalt wand (MAGIC +3)","–","1600 💎"]]},{"cols":["Other Items","Buy"," Sell"],"rows":[["Mandolin (CHARISMA +1)","–","270 💎"],["Silver holy symbol (SANCTITY +2)","800 💎","750 💎"],["Gold compass (SCOUTING +2)","900 💎","800 💎"],["Rope","50 💎","45 💎"],["Lantern","100 💎","90 💎"],["Silver nugget","–","150 💎"]]}],"note":["When you are finished, if you are a Wayfarer by profession, turn to e645. Otherwise you leave the City of Trees. Turn to e678."]},{"tag":"e359","title":"The Wandering Tinker","desc":["A wandering tinker accosts you, selling lanterns for 50 💎 each. You can buy no more than three.","Turn to e010."]},{"tag":"e360","title":"The Ghoul Already Destroyed","desc":["You have no luck in tracking down the ghoul. The next day, you hear a rumour doing the rounds in the taverns. A ghoul was found and destroyed by an adventuring priestess of Tyrnai – apparently, the temple of Nagil rewarded her handsomely. Looks like you were pipped at the post.","Turn to e100."]},{"tag":"e361","title":"Ambushed in the Alley","desc":["If there is a tick in the box, turn to e055 immediately. If not, put a tick there now, and read on.","You find a huddled, moaning figure on the ground. As you approach, a net is thrown over you from behind. You glimpse a face painted with white bone dust and big red circles around the eyes just before a terrific blow on the back of your head slams you into unconsciousness.","Turn to e508."]},{"tag":"e362","title":"Dragged to the Dragon's Lair","desc":["The sea dragon dives deep to the bottom of the lake. You are pulled along at a terrific rate through the murky waters. You think your lungs are about to burst when at last the creature surges upwards, breaking the surface.","You find yourself in a cave inside a rocky island, somewhere on the surface of the lake. A hole in the roof lets in a shaft of bright sunlight, that reflects off the water, casting dappled yellow light all over the walls.","Part of the cave is dry ground, heaped with the dragon's treasure hoard – sparkling coins, swords, armour, and the like. You notice a rocky ledge, lined with a number of bottles, full of yellow dust.","The dragon pulls itself on top of its hoard – you have a few seconds to try to hide. Make a THIEVERY roll at a Difficulty of 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e016","Successful THIEVERY roll"],["e274","Failed THIEVERY roll"]]}]},{"tag":"e363","title":"Transformed into a Sea Centaur","desc":["You collapse a rotting beam, just inside the cabin. The roof falls in, and a cloud of debris fills the water, obscuring you completely. You grab the gems, but it is not long before the MAGIC of the sea centaurs takes you over. You live on for a hundred years, as a sea centaur. Your adventure ends here.","You can, however, start afresh with a new character. First make sure to erase all ticks, codewords, and Adventure Sheet details in all your Fabled Lands books. You can begin at e001 in any of the books of the series."]},{"tag":"e364","title":"The Violet Ocean","desc":["'The Violet Ocean's a dangerous place, Cap'n,' says the first mate. 'The crew probably won't follow you there if they don't think you're good enough!'","If your Rank is 4 or more, turn to paragraph e066 in Over the Blood-Dark Sea.","If your Rank is less than 4, the first mate advises you against the ocean journey. If you take his advice, turn to e085.","If you insist on making the trip, you need to make a CHARISMA roll at Difficulty 11 to convince the crew to follow you."],"tables":[{"cols":["Ref","Result"],"rows":[["e066","Successful CHARISMA roll"],["e085","Failed CHARISMA roll"]]}]},{"tag":"e365","title":"Sul Veneris Freed","desc":["Sul Veneris wakes up the moment you remove the stake. He rips the other stakes out of the ground, and soars into the air, with a shout like a clap of thunder. He swings his hammer around his head, and bolts of lightning leap forth to strike the storm demons.","As he rises into the clouds in pursuit of the demons, a bolt of lightning streaks from his hand and strikes you full force! You are thrown backwards but to your amazement you are unhurt. In fact, you feel empowered by the blast. Gain 3 ❤️ permanently.","You have freed Sul Veneris, the Lord of Thunder. Record the codeword Aloft before climbing down to the bottom. Turn to e658."]},{"tag":"e366","title":"The Violet Ocean","desc":["'The Violet Ocean's a dangerous place, Cap'n,' says the first mate. 'The crew probably won't follow you there if they don't think you're good enough!'","If your Rank is 4 or more, turn to paragraph e066 in Over the Blood-Dark Sea.","If your Rank is less than 4, the first mate advises you against the ocean journey. If you take his advice, turn to e439.","If you insist on making the trip, you need to make a CHARISMA roll at Difficulty 11 to convince the crew to follow you."],"tables":[{"cols":["Ref","Result"],"rows":[["e066","Successful CHARISMA roll"],["e439","Failed CHARISMA roll"]]}]},{"tag":"e367","title":"Security Doubled at the Temple","desc":["You have attempted to steal the chain mail before. This time, security has been doubled with warrior priests of Tyrnai in abundance. Inside the temple, there are two more of the bull-headed iron golem guards, and you realize there is no way you can succeed.","You head back to the city centre. Turn to e400."]},{"tag":"e368","title":"Becoming an Initiate of Maka","desc":["Becoming an initiate of Maka gives you the benefit of paying less for blessings and other services the temple can offer. It costs 50 💎 to become an initiate. You cannot become an initiate of Maka if you are already an initiate of another temple.","If you choose to become an initiate, write Maka in the God box on your Adventure Sheet and remember to cross off the 50 💎.","Once you have finished here, turn to e141."]},{"tag":"e369","title":"The Shrine of Lacuna at the Trading Post","desc":["If you have a boar's tusk, turn to e612. If not, read on.","The priestess, dressed in ceremonial leather armour and carrying a silver bow, recognizes you and welcomes you. She offers you the usual services."],"tables":[{"cols":["Ref","Option"],"rows":[["e618","Become an initiate of Lacuna"],["e334","Renounce the worship of Lacuna"],["e052","Seek a blessing"],["e195","Leave the temple"]]}]},{"tag":"e370","title":"Defeated in the Tournament","desc":["You come round, back to your ❤️ score before the fight started. You lose the weapon and armour you were using – cross them off your Adventure Sheet. The Dragon Knights compliment you on your bravery.","'Until the next time!' says your recent opponent.","You take your leave, somewhat bruised. Turn to e276."]},{"tag":"e371","title":"The Gob-gobbler Unmasked","desc":["With a war cry, you leap to the attack. Your first blow rips away a great chunk of its body!","Suddenly, a voice pipes up from inside the Gob-gobbler. 'Help, help, lads, this one's a real fighter!' You realize the Gob-gobbler is a man disguised as a monster. But then two thugs – bandits, by the look of them – run out of the woods to attack you. You must fight them one at a time.","If you win, turn to e422. If you lose, you are dead, unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["First bandit","3","4","6"],["Second bandit","2","3","7"]]}]},{"tag":"e372","title":"Voyage to Yellowport","desc":["Cross off the 10 💎. A sleek yacht takes you on a trouble-free journey to Yellowport.","Turn to e010."]},{"tag":"e373","title":"The Blessing of Tyrnai","desc":["If you are an initiate it costs only 10 💎 to purchase Tyrnai's blessing. A non-initiate must pay 25 💎. Cross off the money and mark ⚔️ in the Blessings box on your Adventure Sheet.","The blessing works by allowing you to try again when you make a failed ⚔️ roll. It is good for only one reroll. When you use the blessing, cross it off your Adventure Sheet. You can have only one ⚔️ blessing at any one time. Once it is used up, you can return to any branch of the temple of Tyrnai to buy a new one.","When you are finished, turn to e526."]},{"tag":"e374","title":"The Cursed Path","desc":["You sense that sorcery is afoot. You make a few magical divinations which tell you that the path is cursed: it will sour the water supply of anyone that travels upon it. However, you can tell that the curse affects only the path. There is just enough room to squeeze your way up beside it, hugging the rock face. You find your water returns to a state that is drinkable.","Eventually, the path leads to a bubbling well of springwater in the rocks, just at the opening of a cave. You refill your canteen, then explore the cave. Turn to e232."]},{"tag":"e375","title":"Alone with the Provost Marshal","desc":["You tell the provost you have important news, best heard by him alone. He takes you to a side chamber without his guards.","If you want to attempt to slay the provost marshal, turn to e344. Otherwise, you tell him some old news and he throws you out – turn to e010."]},{"tag":"e376","title":"Recaptured and Executed","desc":["You manage to slip out of your chains, and sneak off into the tunnels. You make it to the outside, but a troop of guards and a pack of dogs finally track you down. The fate of all escaped slaves is death – you are executed. Your adventuring days are over, unless you have a resurrection deal."]},{"tag":"e377","title":"The Road Between Marlock City and Trefoille","desc":["The road between Marlock City and Trefoille is well maintained with regular guard posts. The Sokarans are nothing if not efficient.","Roll a die:"],"tables":[{"cols":["Score","Result"],"rows":[["1–2","Bad omen – lose one Blessing"],["3–4","Uneventful journey"],["5–6","Find a sword (ordinary weapon)"]]},{"cols":["Ref","Option"],"rows":[["e250","To Trefoille"],["e100","To Marlock City"],["e175","North into the Curstmoor"]]}]},{"tag":"e378","title":"The Pool at Blessed Springs","desc":["You find a wide pool of bubbling, electric blue water. It gives off a strong invigorating scent, like crushed pine leaves.","If you have the codeword Appease, turn to e593 immediately. If not, but you have a vial of yellow dust, turn to e556. Otherwise, you can bathe in the waters – turn to e598, or leave – turn to e510."]},{"tag":"e379","title":"Robbing the Scholar","desc":["The scholar is in no condition to resist now that your work has been done for you by the ruffians. You take his purse. Inside you find 100 💎. Happy with a good bit of banditry, you decide to call it a night.","Turn to e100."]},{"tag":"e380","title":"Rewarded by the Temple of Sig","desc":["'By the Larcenous One!' exclaims the high priest joyfully. 'You are indeed an accomplished rogue.'","Erase the golden chain mail of Tyrnai from your Adventure Sheet. The high priest teaches you secret knowledge of Sig, the God of Deception. You get a 300 💎 reward and you go up 1 Rank. Roll one die – the result is the number of ❤️ points you gain permanently. Also, don't forget to increase your 🛡️ by 1 as a result of your gain in Rank.","If you are under Tyrnai's curse, turn to e564. Otherwise, turn to e100."]},{"tag":"e381","title":"Caught in a Vice","desc":["You dart down a side tunnel but are horrified to meet several ratmen coming to meet you while your pursuers close in behind. You are caught in a vice and, though you fight with desperate bravery, you are overcome.","Turn to e308."]},{"tag":"e382","title":"The Fisherman's Tale","desc":["'Fishing?' you ask, 'Surely nothing can live in these poisonous waters.'","The fisherman shows you a bright yellow fish with grey stripes, saying, 'Only the smoulder fish has adapted to the sulphur – it feeds on the local seaweed. Mind you the smoulder fish is totally inedible.'","'Why hunt it then?' 'Well, each fish is worth quite a bit to sorcerers and the like. We have a standing quota to fill each month for the magical colleges at Dweomer. The sulphur-laden organs burn in a particular way – a very useful ingredient in certain magics, I am told.'","'And where does all this sulphur come from?' 'Scholars say there is an underground volcanic vent. Others believe it is the breath of the sea dragon. Personally, I always drop a silver nugget into the waters once a month to appease the dragon, for his favourite metal is silver.'","Turn to e135."]},{"tag":"e383","title":"Following Fourze","desc":["After a while Fourze circles around, heading across country. Make a SCOUTING roll at Difficulty 9."],"tables":[{"cols":["Ref","Result"],"rows":[["e585","Successful SCOUTING roll"],["e263","Failed SCOUTING roll"]]}]},{"tag":"e384","title":"The Amulet of King Skabb","desc":["Guildmaster Vernon is pleased to see you. You hand him the copper amulet and he exclaims joyfully, 'The amulet of King Skabb! Well done, indeed!'","Cross the copper amulet off your Adventure Sheet. You are given 450 💎 as a reward.","Note the codeword Acid and turn to e010."]},{"tag":"e385","title":"The King is Slain","desc":["The king is taken totally by surprise, and you cut him down. He falls dead at your feet. 'Long live General Marlock,' you mutter under your breath.","You take the king's royal ring as proof of your act. Note it on your Adventure Sheet and get the codeword Ark.","Although you manage to talk your way out of the stockade, the body is discovered as you are heading down the mountain path. Vengeful soldiers set off in pursuit.","Make a SCOUTING or a THIEVERY roll (your choice) at Difficulty 9."],"tables":[{"cols":["Ref","Result"],"rows":[["e167","Successful SCOUTING or THIEVERY roll"],["e230","Failed SCOUTING or THIEVERY roll"]]}]},{"tag":"e386","title":"Lauria's Betrayal","desc":["There is no sign of Lauria, but you do find an open trunk and a window with a knotted rope dangling from it. So – she found the treasure and then made her escape, leaving you behind to face the music. You allow yourself a tight-lipped smile as you hear her voice echoing leadenly from far off in the fog: 'There's a thief at Master Talanexor's house! Quick!'","You'll settle the score with Lauria at a future date. For now, you just have time to escape before a patrol arrives. Gain the codeword Ashen and turn to e010."]},{"tag":"e387","title":"The Weary Pilgrim Tavern","desc":["You are on a road between Caran Baru and Trefoille. You come to the Weary Pilgrim Tavern, a waystation between the cities. The tavern costs you 1 💎 a day. Each day you spend here you can recover 1 ❤️ if injured, up to the limit of your normal unwounded Stamina score.","If you want to spend 3 💎 buying drinks all round so you can glean some rumours, turn to e666. To leave, you can go:"],"tables":[{"cols":["Ref","Option"],"rows":[["e558","South"],["e347","North"],["e047","West into the Forest of Larun"],["e135","East to the lake"]]}]},{"tag":"e388","title":"The Blessing of Elnir","desc":["If you are an initiate it costs only 10 💎 to purchase Elnir's blessing. A non-initiate must pay 25 💎. Cross off the money and mark CHARISMA in the Blessings box on your Adventure Sheet.","The blessing works by allowing you to try again when you make a failed CHARISMA roll. It is good for only one reroll. When you use the blessing, cross it off your Adventure Sheet. You can have only one CHARISMA blessing at any one time. Once it is used up, you can return to any branch of the temple of Elnir to buy a new one.","Turn to e316."]},{"tag":"e389","title":"Fighting the Ker'ilk","desc":["Driving one of the creatures back with your sword, you leap on to the forecastle shouting, 'To me, men!' They rally around you, organizing themselves into a fighting unit and a battle ensues. You must fight one ker'ilk.","If you win, turn to e519. If you lose, you end up as food for ker'ilk young – unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Ker'ilk","4","9","8"]]}]},{"tag":"e390","title":"The Ghost Horses Pass","desc":["The horses rush past you, whinnying and neighing, bellowing at the twilight sky. Soon they disappear from your sight. You make camp, and the next day continue your journey."],"tables":[{"cols":["Ref","Option"],"rows":[["e560","Go north across country"],["e558","Head east to the road"],["e250","Go to Trefoille"],["e100","Go to Marlock City"],["e099","Head west towards the River Grimm"]]}]},{"tag":"e391","title":"The Tree Steps Aside","desc":["Get the codeword Apple.","'Umm, well, I suppose I could let one such as you through,' says the tree thoughtfully. Then it uproots itself with a great tearing sound, and shuffles out of the way. 'There you go!' says the tree, 'You may pass.'","You walk through the thorn bush gate. Beyond, you find several huge oak trees whose branches are so big that they are able to support the homes of many people.","Turn to e358."]},{"tag":"e392","title":"The Azure Prince Restored","desc":["You pass your hands over the mad beggar, mumbling a prayer to the gods.","The beggar cries out, 'A cloud has been lifted from my mind! The curse is dispelled! I remember all!'","His name, he tells you, is Akradai, the Azure Prince of the Horde of the Thundering Skies, nomads of the steppes. 'I was cursed with madness by Shazir of the Ruby Citadel but now you have cured me!' he says. 'I am forever in your debt!' He leaves, with a parting cry, 'Seek me on the steppes and I shall reward you.'","Gain the codeword Azure. Turn to e010."]},{"tag":"e393","title":"The Thug Attacks","desc":["You hear a sound behind you. You spin around just as another man, a beefy, disreputable-looking thug, comes for you with a long dagger. 'Get him!' yells the man with the eyepatch. You must fight.","If you lose, you are dead, unless you have a resurrection deal. If you win, turn to e476."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Thug","3","6","13"]]}]},{"tag":"e394","title":"Helping the Pirates","desc":["When you and your crew join the fray, the battle is short-lived. The Sokarans are overpowered and taken as slaves by the pirates.","The pirate captain, Verin Crookback, is a short, bull-chested man. He walks like a hunchback, because of a crippling wound he took to the shoulder blade, many years ago. He thanks you for your help and rewards you with a share of the booty of the Sokaran war ships – only 50 💎. He also hands you a silver medallion.","'If you ever go to the Kingdom o' the Reavers,' he says, 'flash this about – one of the lads'll recognize it. Villains, the lot of them, but they'll honour one who carries the medallion. Someone will bring you to me – I'll help you, if you need it.'","The pirates take their leave, and you sail on. Turn to e420."]},{"tag":"e395","title":"Escaping the Temple Pursuit","desc":["You make it out of the temple with your pursuers close behind. However, you manage to lose them amid the alleys of Caran Baru, hiding inside a barrel of rotting food – garbage from the army barracks. You emerge stinking, but safe.","Turn to e400."]},{"tag":"e396","title":"The Market Square of Marlock City","desc":["The market square in Marlock City is huge. Armed guards stand around the edge to enforce General Marlock's will. Merchants and traders from all over Harkuna hawk their goods in a dozen languages.","Items with no purchase price listed are not available locally. The general has imposed a sales tax on all trade; the tax has been included in all the prices listed.","To return to the city centre, turn to e100."],"tables":[{"cols":["Armour","Buy","Sell"],"rows":[["Leather (🛡️ +1)","70 💎","25 💎"],["Ring mail (🛡️ +2)","120 💎","70 💎"],["Chain mail (🛡️ +3)","220 💎","160 💎"],["Splint armour (🛡️ +4)","420 💎","340 💎"],["Plate armour (🛡️ +5)","–","700 💎"],["Heavy plate (🛡️ +6)","–","1420 💎"]]},{"cols":["Weapons","Buy","Sell"],"rows":[["No ⚔️ bonus","70 💎","20 💎"],["⚔️ bonus +1","270 💎","180 💎"],["⚔️ bonus +2","–","380 💎"],["⚔️ bonus +3","–","780 💎"]]},{"cols":["Magical Equipment","Buy","Sell"],"rows":[["Amber wand (MAGIC +1)","520 💎","380 💎"],["Ebony wand (MAGIC +2)","–","780 💎"],["Cobalt wand (MAGIC +3)","–","1580 💎"]]},{"cols":["Other Items","Buy","Sell"],"rows":[["Mandolin (CHARISMA +1)","300 💎","250 💎"],["Lockpicks (THIEVERY +1)","300 💎","250 💎"],["Holy symbol (SANCTITY +1)","220 💎","80 💎"],["Compass (SCOUTING +1)","520 💎","430 💎"],["Rope","70 💎","25 💎"],["Lantern","120 💎","70 💎"],["Climbing gear","120 💎","70 💎"],["Bag of pearls","–","80 💎"],["Rat poison","80 💎","30 💎"],["Silver nugget","–","190 💎"]]}]},{"tag":"e397","title":"Storm-tossed and Lost","desc":["Your ship is thrown about like flotsam and jetsam. When the storm subsides, you take stock. Much has been swept overboard – you lose 1 Cargo Unit, if you had any, of your choice. Also, the ship has been swept way off course and the mate has no idea where you are. 'We're lost at sea, Cap'n!' he moans.","Turn to e090."]},{"tag":"e398","title":"The Cave on the Hill","desc":["If there is a tick in the box, turn to e225 immediately. If not, put a tick there now, and read on.","You make your way up the hill. After a while, you spot a cave set into the hillside, a little further up. Judging by the human bones dumped near the entrance, this is the lair of a dangerous beast. Fresh tracks, of some large, two-legged, three-toed creature, lead from the cave into some nearby trees. It seems it is not home at the moment.","If you have the codeword Apache, turn to e463 immediately. If not, make a MAGIC or SCOUTING roll (your choice) at Difficulty 11."],"tables":[{"cols":["Ref","Result"],"rows":[["e577","Successful SCOUTING or MAGIC roll"],["e486","Failed SCOUTING or MAGIC roll"]]}]},{"tag":"e399","title":"Assassinating Nergan Corin","desc":["You were asked by the Governor of Yellowport to assassinate Nergan Corin. It is a good time to make the attempt. If you want to have a go, make a COMBAT or a THIEVERY roll at Difficulty 12. If you succeed, turn to e385. If you fail, turn to e581.","If you would rather join the rebels and kill the governor instead, record the codeword Ambuscade. If you join the rebels, when you are ready, the king wishes you well, and you are led out of the stockade and back down to the foothills of the Coldbleak Mountains. Turn to e474."]},{"tag":"e400","title":"Caran Baru","desc":["Caran Baru is a medium-sized town that acts as a way-station between the citadel to the north and the rich towns of the south. It is a garrison town; many supplies, arms, and soldiers move through Caran Baru on the north-south trail. Shops, temples, traders and the like have sprung up here to serve the needs of the military. There is also a sizeable mining community, for the mines of Sokara lie in the Bronze Hills just outside town, and a slave market where poor unfortunates, sold into slavery, are bought for work in the mines.","You can buy a town house in Caran Baru for 200 💎. Owning a town house gives you a place to rest and to store equipment. If you buy one, tick the box by the town house option.","If you have the codeword Barnacle, turn to e418 immediately. Otherwise, pick from the following options."],"tables":[{"cols":["Ref","Option"],"rows":[["e215","Visit the marketplace"],["e112","Visit the merchants' guild"],["e473","Visit the slave market"],["e282","Visit the temple of Tyrnai"],["e615","Visit the temple of Lacuna"],["e086","Visit the temple of the Three Fortunes"],["e177","Visit your town house 🏠 (if box ticked)"],["e184","Visit the Blue Griffon Tavern"],["e201","Follow the road north to the citadel"],["e110","Go west into the Bronze Hills"],["e060","Travel north east into the country"],["e458","Take the east road to Fort Mereth"],["e474","Head south east into the mountains"],["e347","Take the south road"]]}]}]`),g=JSON.parse(`[{"tag":"e401","title":"Harbour Duties Paid","desc":["Cross off the 60 💎. The captain gives you a satisfied smile. 'Harbour duties all paid up. You may proceed,' he says mockingly.","He and his men leave the ship. Several of your crew curse or spit in disgust.","You sail on. Turn to e439."]},{"tag":"e402","title":"The Sokarans Left Behind","desc":["Your ship draws away, leaving the Sokarans behind. Your crew jeer at them, and you spot the captain shaking his fist at you in rage, before they disappear from sight.","Turn to e439."]},{"tag":"e403","title":"Amcha's Head Delivered","desc":["If there is a tick in the box, turn to e229 immediately. If not, put a tick there now and read on.","You dump the head of Amcha One-Eye on the guildmaster's desk. He stares at it in horror for a moment and then a look of joy crosses his features. 'At last! We are rid of that scourge of commerce! Well done, well done indeed!'","Cross Amcha's head off your Adventure Sheet. The guildmaster pays for you to have special training. You can choose which area you would like to improve – you gain one point for one ability of your choice (for example, +1 ⚔️).","When you are ready, you return to the city. 'Come back anytime,' yells the guildmaster as you go. Turn to e100."]},{"tag":"e404","title":"A Fellow Cultist","desc":["One of the cultists of Badogor the Unspoken is feigning distress in the hope of luring a sacrificial victim for dinner. He sits up when he recognizes you as a member of the cult, and says, rather disconsolately, 'Ah, hallo friend. We were hoping for a big banquet tonight.'","Two more cultists step from the shadows, holding a net. 'Oh well, perhaps another will come along,' one of them says optimistically.","They treat you as one of their own – even giving you a share of the cult's recent income. You get 20 💎. 'May you never speak his name,' they intone in parting.","You return to the city centre. Turn to e010."]},{"tag":"e405","title":"The Merchants' Guild of Yellowport","desc":["The merchants' guild of Yellowport is a large building of granite, plushly decorated inside to show off its wealth. Here you can bank your money for safe-keeping – or invest it in guild enterprises in the hope of making a profit. You hear that the guildmaster is looking for adventurers."],"tables":[{"cols":["Ref","Option"],"rows":[["e122","Visit the guildmaster"],["e046","Make an investment"],["e355","Check on investments"],["e605","Deposit or withdraw money (note that you are in Yellowport)"],["e010","Return to the town centre"]]}]},{"tag":"e406","title":"The Book of the Seven Sages","desc":["You know that the Book of the Seven Sages that Pyletes wanted you to get lies within the mound. If you don't want to go for it now, you can leave by turning to e492. Otherwise, you wait until nightfall, then creep towards the mound.","Make a THIEVERY roll at Difficulty 9."],"tables":[{"cols":["Ref","Result"],"rows":[["e449","Successful THIEVERY roll"],["e139","Failed THIEVERY roll"]]}]},{"tag":"e407","title":"Escaping the Palace","desc":["You hide in the kitchen pantry, and then, disguised as a kitchen scullion, sneak out unnoticed. The skill and daring of your exploit will be forever remembered! Long live the rightful king!","Turn to e010."]},{"tag":"e408","title":"You Decline the Mer-folk","desc":["You decline. They look at you inscrutably, and then sink beneath the waves with the body of their companion.","Turn to e507."]},{"tag":"e409","title":"Becoming an Initiate of Nagil","desc":["Becoming an initiate of Nagil gives you the benefit of paying less for services the temple can offer. You cannot do this if you are already an initiate of another temple. To become an initiate you have to pass a priestly exam.","If you want to take the exam, make a SANCTITY roll at Difficulty 10 unless there is a tick in the above box, in which case it is at Difficulty 15.","If you succeed, you become an initiate – write Nagil in the God box on your Adventure Sheet and turn to e071.","If you fail, put a tick in the box (unless one is already there) and turn to e100."]},{"tag":"e410","title":"The Tree is Unconvinced","desc":["'Oh, what a load of rotten leaves!' exclaims the tree. 'Anyone can see you're as bad as the next human. In fact, I'd say you're probably a... a lumberjack! Now, get lost!'"],"tables":[{"cols":["Ref","Option"],"rows":[["e678","Leave the forest"],["e570","Attack the tree"]]}]},{"tag":"e411","title":"The Golden Net of the Twin Gods","desc":["The high priest tells you that the golden net of the twin gods has been stolen. The repulsive ones have taken it to their palace beneath the sea in the Sunken City of Ziusudra. The repulsive ones worship the fish-god Oannes, who struggles with Alvir and Valmir for control of the sea.","'We must have that golden net, or the repulsive ones will use it against us. If you return it to us, we will reward you,' says the high priest. 'The Sunken City lies under the coastal waters off the Shadar Tor.'","If you take the mission, gain the codeword Anchor. When you are finished, turn to e220."]},{"tag":"e412","title":"The Road Between Yellowport and Trefoille","desc":["You are on the cobbled road between Yellowport and Trefoille. You meet a few merchants and pilgrims, but all in all it is an uneventful journey."],"tables":[{"cols":["Ref","Option"],"rows":[["e010","Head for Yellowport"],["e250","Head for Trefoille"]]}]},{"tag":"e413","title":"Faith Breaks the Spell","desc":["You are so devout that the king's spell cannot affect you for more than a few seconds. The queen, recognizing your faith in the gods, thanks you for entertaining them.","You wake up in the cabin aboard your ship. You are musing about the strange nature of your dream when you realize that you have something in your hand. It is a silver flute (CHARISMA +2). While you have the flute, it adds 2 to your CHARISMA. Note that it is worth 500 💎, and you can sell it at any market if you like.","Turn to e507."]},{"tag":"e414","title":"Haylie Reunited","desc":["Haylie runs into her mother's arms for a tearful reunion. Lynn, the mother, gives you a suit of chain mail (🛡️ +3) and a sword (an ordinary weapon).","'These have been in the family for generations – it's all I have to give,' she says.","Fourze is hauled off to the local magistrate for judgment – he will probably be sold into slavery.","Gain the codeword Attar and turn to e427."]},{"tag":"e415","title":"Death by Thirst","desc":["You cannot continue. You sink to your knees, gasping for water and pass out. Death is not long in coming. It is all over, unless you have a resurrection deal."]},{"tag":"e416","title":"Into the Violet Ocean","desc":["'The Violet Ocean's a dangerous place, Cap'n,' says the first mate. 'The crew probably won't follow you there if they don't think you're good enough!'","If your Rank is 4 or more, you can take the ship south west – turn to paragraph e077 in Over the Blood-Dark Sea, or head south east – turn to paragraph e066 in Over the Blood-Dark Sea.","If your Rank is less than 4, the first mate advises you against the ocean journey. If you take his advice, turn back to e559.","If you insist on making the trip, you need to make a CHARISMA roll at Difficulty 12 to convince the crew to follow you. If you succeed, you can take the ship south west – turn to e077 in Over the Blood-Dark Sea, or south east – turn to e066 in Over the Blood-Dark Sea. If you fail, turn back to e559."]},{"tag":"e417","title":"The Black Dragon Knight Defeated","desc":["The other knights are amazed by your skill, and they seem quite pleased that the Black Dragon Knight is dead. 'He was an evil man,' says the Green Dragon Knight.","You take the black dragon shield – note it on your Adventure Sheet. As you watch, the rest of your opponent's body dissolves into a foul-smelling smoke, armour and all.","Lose the codeword Axe. You leave the castle. Turn to e276."]},{"tag":"e418","title":"The Man with the Velvet Eyepatch","desc":["You have heard that the man with the velvet eyepatch should be in Caran Baru. If you want to search for him now, turn to e117. If not, turn to e400 and choose from the options there."]},{"tag":"e419","title":"The Ghoul's Trail","desc":["The trail of gruesome murders and tales of terror leads you to an old cemetery in a near-deserted part of the old quarter. It is early morning, a few hours before dawn, so you haven't much time before the ghoul goes into hiding.","At the gates of the cemetery, you find a small girl, hunched over, sobbing. When she sees you, she backs away, terrified.","Make a CHARISMA roll at Difficulty 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e553","Successful CHARISMA roll"],["e045","Failed CHARISMA roll"]]}]},{"tag":"e420","title":"Coastal Waters of Marlock City","desc":["Your ship is sailing in the coastal waters beside Marlock City. You notice an unusual number of Sokaran warships patrolling the area.","'The pirates are getting bolder and bolder – that's why the navy's out in force,' says the first mate."],"tables":[{"cols":["Ref","Option"],"rows":[["e119","Sail west (Cities of Gold and Glory)"],["e142","Sail into Marlock City"],["e120","Sail east along the coast"],["e502","Sail south into the Violet Ocean"]]}]},{"tag":"e421","title":"The Storm Demons Repelled","desc":["The storm demons shrink back with a wailing, mournful cry, like wind in the trees. The power of your faith is enough to repel them. You work free one of the stakes holding down Sul Veneris.","Turn to e365."]},{"tag":"e422","title":"The Gob-gobbler's Bandits Defeated","desc":["The bandits are dead. The man in the suit surrenders. It is Fourze, the master of the market. He terrified people with the monster disguise, and used a large pair of bellows full of gas to put his victims to sleep. Then he sold them to a slaver from Caran Baru, for work in the slave mines. You find Haylie, and several other villagers in the cellar of an old farm nearby.","'Don't hurt me,' begs Fourze, 'I'm only trying to make a few Shards!' 'What! By selling your own people into slavery!' says one of the villagers, giving him a good kick.","You lead them back to Venefax. Turn to e414."]},{"tag":"e423","title":"Ratmen Defeated in the Tunnels","desc":["The ratmen lie defeated at your feet. You find 15 💎 on the bodies, and a note which says: 'Parti! Kitchuns. Tonite. Rank and file rats only – no offsirs and no king allowed!'","The rest of the cavern is bare, so you press on down the tunnels ahead. After a while you come to a cleaner area of the sewers, a part of the old city now buried under Yellowport. It dates from the period when all of Harkuna was ruled by the Masked Ones of Uttaku, before the people overthrew them.","You come to two rotten wooden doors. Names have been scratched on to them by some half-literate ratman. One says 'Thrown Rum'; the other says 'Kitchuns'. You can hear gravelly rat voices from behind both doors."],"tables":[{"cols":["Ref","Option"],"rows":[["e572","Enter the 'kitchuns'"],["e202","Enter the 'thrown rum'"]]}]},{"tag":"e424","title":"Voyage to Copper Island","desc":["The ship's captain says, 'I'll take you but you should be warned – it's a dangerous place we're travelling to. You'd better be sure you can handle it – if you're not at least a master of your profession, I'd advise against. It's up to you, though.'","You must have Over the Blood-Dark Sea to travel to Copper Island. If you still want to go, cross off 30 💎 and turn to e099 in that book. If you decide not to go, turn back to e142 if you are in Marlock City or e555 if you are in Yellowport."]},{"tag":"e425","title":"Lauria Leads the Way","desc":["The woman tells you her name is Lauria. She leads you stealthily through winding cobblestoned streets to a town house standing at the back of a small tree-lined square.","A yellowish fog is descending with the coming of night. Lauria waits until it is thick enough to shroud your activities from any stray passersby, then jemmies a downstairs window. Within seconds the two of you are inside.","'You've got the easy job,' she says. 'Stay down here and keep watch. The stuff we're after is upstairs.' She bounds silently up to the next floor."],"tables":[{"cols":["Ref","Option"],"rows":[["e534","Stay on watch"],["e270","Search the ground floor"]]}]},{"tag":"e426","title":"Oliphard's Request","desc":["'Ah, I see that you are a student of the arcane arts,' says Oliphard the Wizardly. 'There is something I need – if you can get it for me I will teach you how to advance as a mage. It was Vayss the Sea Dragon who turned me into powder. He stole my MAGIC chest in which I store all my magical equipment. Without it, I am virtually powerless. Meet me in Trefoille when you have it.'","'Where is Vayss?' you ask. 'Why, in the Lake of the Sea Dragon, of course,' he replies.","Record the codeword Avenge. As he leaves, Oliphard gives you an amulet of protection. Note it on your Adventure Sheet. Now turn to e378."]},{"tag":"e427","title":"Venefax","desc":["If you have the codeword Attar, turn to e578 immediately. If not, read on.","Venefax is a strange-looking village. It looks like a single gigantic building. All the houses are joined together to form a jumbled mass, and none of the houses have doors – the only way in is through holes in the rooftop. Ladders lead up to the roof, which in effect forms a network of streets that the inhabitants travel across to get to certain buildings.","'We had to build it that way, for 🛡️,' says a passing farmer. 'You see, the scorpion men from the south cannot climb, so they can't get inside the town!'"],"tables":[{"cols":["Ref","Option"],"rows":[["e152","Visit the market"],["e497","Visit the Scorpion's Sting Tavern"],["e338","Visit the village healer"],["e063","Chat to villagers on the rooftop"],["e492","Go south into Scorpion Bight"],["e087","Take the road north to Blessed Springs"],["e621","South west on the road to Yellowport"],["e278","North into open countryside"]]}]},{"tag":"e428","title":"Charging King Skabb","desc":["With a martial cry you draw your weapon and charge. You manage to cut down two of the ratmen before they can react. The remaining two officers draw their swords while King Skabb ducks down behind his throne. You must fight them both at once, as if they were one opponent. If you have some rat poison, you can smear it on your weapon blade to add 3 to your dice rolls. Cross the rat poison off your Adventure Sheet after use.","If you win, turn to e145. If you lose, turn to e308."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Two Ratmen","8","11","12"]]}]},{"tag":"e429","title":"The Pirate Captain's Ghost","desc":["The gloomy wreck is filled with coral-encrusted skeletons of its drowned crew. You find the captain's cabin. Inside, a figure still sits in a chair, a chest of gems at its feet. With a thrill of horror, you realize it is a ghost, an undead remnant of a pirate captain, steeped in evil, its nacreous, fish-gnawed flesh still pulsing with a kind of half-life."],"tables":[{"cols":["Ref","Option"],"rows":[["e089","Swim straight in and grab the chest"],["e363","Try to steal it without being seen"]]}]},{"tag":"e430","title":"Waters Around Scorpion Bight","desc":["You are sailing in the waters around Scorpion Bight. 'I wouldn't want to put into land in these parts,' says your navigator. 'The scorpion men'll take all we've got, and our lives too, given half a chance!'","Roll two dice:"],"tables":[{"cols":["Ref","Score","Result"],"rows":[["e586","2–4","Storm"],["e085","5–7","An uneventful voyage"],["e056","8–9","A ship of bizarre design"],["e264","10–12","A floating island"]]}]},{"tag":"e431","title":"Oliphard's Doors of Teleportation","desc":["You notice that Oliphard has erected his pavilion over a verdigris trapdoor set into the floor. 'Ah, you have the key, I see!' says Oliphard. 'Please, be my guest – use the door.'","You open it up and climb some short stairs into a square chamber with three doors. 'They are doors of teleportation – step through and you will be taken to whatever land is displayed!' says Oliphard.","The first door leads to a teeming city of merchants – Metriciens in Golnir. Turn to paragraph e048 in Cities of Gold and Glory if you enter this door.","The second door leads to a huge mountain – Sky Mountain in the Great Steppes, far to the north. Turn to paragraph e185 in The Plains of Howling Darkness if you enter this door.","The third door leads to Dweomer, the City of Sorcerers, on Sorcerers' Isle. Turn to paragraph e100 in Over the Blood-Dark Sea if you open this door.","If you don't want to step through any of the doors, turn to e656 and choose again."]},{"tag":"e432","title":"Talanexor the Fireweaver","desc":["The militiamen are down. The tall gentleman watches you like a snake with its eyes on a mongoose. You have no time to bother with him now.","'We'll meet again, perhaps,' he says in a voice like slithering murder. 'Remember my name: Talanexor the Fireweaver.'","'Remember my name,' you call back as you lope off, 'Lauria the Housebreaker.'","Let the conniving vixen get into trouble. She nearly played you for her patsy, after all. Turn to e010."]},{"tag":"e433","title":"Rescuing the Scholar","desc":["You rush in, taking the ruffians by surprise. A couple of good buffets around the head, and they run off. The scholar lies groaning on the ground."],"tables":[{"cols":["Ref","Option"],"rows":[["e172","Help him up"],["e379","Rob him"]]}]},{"tag":"e434","title":"Your Town House in Yellowport","desc":["You can leave possessions and money here to save having to carry them around with you. You can also rest here safely and recover any ❤️ points you have lost. Record in the box anything you wish to leave.","Each time you return, roll two dice:"],"tables":[{"cols":["Score","Result"],"rows":[["2–10","Your possessions are safe"],["11","A thief. All the money you left here has gone"],["12","Earthquake! Lose all possessions you left here and the town house (erase the tick at e100)"]]}],"note":["When you are ready, turn to e100."]},{"tag":"e435","title":"Becoming an Initiate of Tyrnai","desc":["Becoming an initiate of Tyrnai gives you the benefit of paying less for blessings and other services the temple can offer. To qualify as an initiate you must have a ⚔️ score of at least 6. You cannot become an initiate of Tyrnai if you are already an initiate of another temple.","If you choose to become an initiate (and meet the qualification) write Tyrnai in the God box on your Adventure Sheet.","Turn to e526."]},{"tag":"e436","title":"Washed Up Near the Trading Post","desc":["You find yourself washed up on a rocky shore, battered and cold, but lucky to be alive. You haul yourself up the beach on to land. Fortunately for you, you are near the Trading Post on the Isle of Druids.","Turn to e195."]},{"tag":"e437","title":"Becoming an Initiate of Sig","desc":["Becoming an initiate of Sig gives you the benefit of paying less for blessings and other services. Also, you can add 1 to your THIEVERY score, as Sig will watch over your pilfering activities and keep you safe from the law. It costs 50 💎 to become an initiate. You cannot become an initiate if you are already an initiate of any other temple.","If you choose to become an initiate, write Sig in the God box on your Adventure Sheet and cross off 50 💎.","Turn to e235."]},{"tag":"e438","title":"The Climb Too Arduous","desc":["The climb is too arduous for you. The air becomes too thin to breathe, and you cannot find the footholds you need to pull yourself up. You are forced to abandon the attempt and climb back down.","Turn to e244."]},{"tag":"e439","title":"Coastal Waters of Yellowport","desc":["Your ship is sailing in the coastal waters beside Yellowport."],"tables":[{"cols":["Ref","Option"],"rows":[["e555","Sail into Yellowport Harbour"],["e430","Sail north east towards Scorpion Bight"],["e120","Sail south west along the coast"],["e366","Sail south into the Violet Ocean"]]}]},{"tag":"e440","title":"Becoming an Initiate of Elnir","desc":["Becoming an initiate of Elnir gives you the benefit of paying less for blessings and other services the temple can offer. It costs 60 💎 to become an initiate. You cannot become an initiate of Elnir if you are already an initiate of another temple.","If you choose to become an initiate, write Elnir in the God box on your Adventure Sheet and then cross off 60 💎.","Turn to e568."]},{"tag":"e441","title":"On the Battlements","desc":["You clamber up on to the battlements of the Temple of Tyrnai with relative ease and manoeuvre yourself into a position overlooking the golem guards at the gate. Now you have to reach down without being noticed.","Make a THIEVERY roll at Difficulty 11."],"tables":[{"cols":["Ref","Result"],"rows":[["e022","Successful THIEVERY roll"],["e168","Failed THIEVERY roll"]]}]},{"tag":"e442","title":"Yellowport by Night","desc":["You set out to explore the city of Yellowport at night, unwholesome though it is with its reeking air and dusty ochre streets."],"tables":[{"cols":["Ref","Option"],"rows":[["e021","Head for the rough part of the town"],["e178","Go to the wealthy area"],["e265","Explore the merchants' storehouses"]]}]},{"tag":"e443","title":"A Major Sea Battle","desc":["You are witness to a major sea battle, involving at least 40 warships, between the Sokaran navy and a pirate fleet. Arrows fill the air, and smoking fireballs are launched from catapults mounted on some of the ships. The shrieks of the dying carry across the waves. You decide it would be better not to get involved in such a conflict.","Turn to e420."]},{"tag":"e444","title":"Attempting to Outrun the Galley","desc":["You try to make a run for it. Roll two dice and add your Rank. Subtract 1 from the total if you have a poor crew. Add 1 if you have a good crew or add 2 if you have an excellent crew."],"tables":[{"cols":["Ref","Score","Result"],"rows":[["e051","1–7","The galley overtakes you"],["e402","8+","You outrun them"]]}]},{"tag":"e445","title":"Inside the Temple of Tyrnai","desc":["You climb up, and squeeze through an open window into a long hall. Thin wires are stretched across the room, but you are an able enough rogue to crawl through without touching any of them and setting off possible traps or alarms.","Inside the temple, it is cool and dark, filled with an unearthly stillness. Suddenly, the temple doors are flung open, and two figures lumber into the room. You realize with a thrill of horror that the bull-headed iron statues outside the gates have come to life. They are golems, set here to guard the temple."],"tables":[{"cols":["Ref","Option"],"rows":[["e349","Run for your life"],["e569","Fight them"]]}]},{"tag":"e446","title":"The Quest for the Ghoul","desc":["If there is a tick in this box, turn to e226 immediately. If not, put a tick there now and read on.","You set out that night, on your quest. Make a Magic roll at Difficulty 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e511","Successful Magic roll"],["e328","Failed Magic roll"]]}]},{"tag":"e447","title":"Washed Up at the Shadar Tor","desc":["You find yourself washed up on a rocky shore, beneath towering cliffs. You are battered and cold, but lucky to be alive. Eventually, you find a path up the cliff. You climb up, to find yourself at the Shadar Tor.","Turn to e035."]},{"tag":"e448","title":"Blessing of Safety from Storms","desc":["If you are an initiate it costs only 5 💎 to propitiate the twin gods of the sea. A non-initiate must pay 20 💎. Cross off the money and mark Safety from Storms in the Blessings box on your Adventure Sheet.","The blessing works by allowing you to ignore any one storm at sea. When you use the blessing, cross it off your Adventure Sheet. You can have only one Safety from Storms blessing at any one time. Once it is used up, you can return to any branch of the temple of Alvir and Valmir to buy a new one.","Turn to e220."]},{"tag":"e449","title":"Inside the Scorpion Mound","desc":["You creep past a scorpion man guard, which is dozing at the entrance to one of the burrows. The stench inside the mound is foul – a kind of acrid, rotting vegetable smell. You head for the centre of the mound, past tunnels, rooms and egg chambers, avoiding the inhabitants by skulking in the shadows.","Finally, you come to a room which is more like the laboratory of a sorcerer than a scorpion den – jars, alembics and scrolls lie all over the place. A scorpion man is at work at a desk. Unlike others of his kind, he wears rudimentary clothing.","Suddenly, what you took for a stuffed animal's head, mounted on the wall, says, 'There is an intruder, master.' The scorpion man wheels around and charges straight at you!","Make a Magic roll at Difficulty 9."],"tables":[{"cols":["Ref","Result"],"rows":[["e503","Successful Magic roll"],["e105","Failed Magic roll"]]}]},{"tag":"e450","title":"The Blessed Springs Spa","desc":["A wooden stockade encloses the springs. At the gate, two militiamen stand on guard, and a priest, dressed in blue robes, sits behind a desk.","'Thirty-five Shards to enjoy the divine spa,' says the priest."],"tables":[{"cols":["Ref","Option"],"rows":[["e378","Pay 35 💎 and enter"],["e510","Cannot or will not pay"]]}]},{"tag":"e451","title":"Yanryt the Son","desc":["You ask the innkeeper about Yanryt the Son. He looks at you oddly, clearly unsettled by your question.","'Some say he is the son of a mortal woman, and the god Tyrnai. But he has not been here for some time...' Suddenly he stops, and stares in amazement at the corner of the tavern.","You turn to look, and there, hunched over a stoop of ale, is Yanryt the Son. He greets you.","If you have a black dragon shield, turn to e575. If not, turn to e329."]},{"tag":"e452","title":"The Trading Post Market","desc":["The Trading Post has a small market place in the village square, where half a dozen stalls sell a few goods. Items with no purchase price are not available locally.","When you are finished, turn to e195."],"tables":[{"cols":["Armour","Buy","Sell"],"rows":[["Leather (🛡️ +1)","50 💎","45 💎"],["Ring mail (🛡️ +2)","–","90 💎"],["Chain mail (🛡️ +3)","–","180 💎"]]},{"cols":["Weapons","Buy","Sell"],"rows":[["No ⚔️ bonus","50 💎","40 💎"],["⚔️ bonus +1","–","200 💎"]]},{"cols":["Magical Equipment","Buy","Sell"],"rows":[["Amber wand (Magic +1)","–","400 💎"]]},{"cols":["Other Items","Buy","Sell"],"rows":[["Mandolin (Charisma +1)","300 💎","270 💎"],["Lockpicks (Thievery +1)","–","270 💎"],["Holy symbol (Sanctity +1)","–","100 💎"],["Compass (Scouting +1)","500 💎","450 💎"],["Rope","50 💎","45 💎"],["Lantern","100 💎","90 💎"],["Climbing gear","–","90 💎"],["Bag of pearls","–","100 💎"],["Rat poison","–","50 💎"],["Pickaxe","–","90 💎"],["Silver nugget","–","150 💎"]]}]},{"tag":"e453","title":"Washed Up at the River Grimm Delta","desc":["You find yourself washed up on a long, sandy beach, battered and cold, but lucky to be alive. You head inland until you realize you have arrived at the rivermouth delta of the River Grimm.","Turn to e579."]},{"tag":"e454","title":"Thrown in the Dungeons","desc":["If there is a tick in the box, turn to e188. If not, put a tick there now and read on.","You are thrown into a stinking prison cell. Your cell-mate, a half-dead old man with long white hair tells you his tale: 'The lair of the gorlock! A hideous beast that has backward-pointing feet – Krine and I, fleeing with our stolen treasure sought refuge in the cave near Blessed Springs. The tracks led us to believe it had just left its cave, but we didn't know about its feet – in fact it was at home. It took Krine but I managed to escape with my life, only to be taken by the militia. I will never live to see the treasure but you, forewarned, may defeat the gorlock and take the riches it guards...'","Gain the codeword Apache.","A few days later, you learn your own fate. You are to be sold into slavery, and taken to Caran Baru to work in the tin mines. Turn to e118."]},{"tag":"e455","title":"Passage to Wishport","desc":["A merchant ship, sailing for Wishport, will take you for 15 💎. You must have Cities of Gold and Glory before you can travel to Wishport. If you do not want to make the trip, turn back to e142. Otherwise, pay the 15 💎 and read on.","You have an uneventful journey and arrive in Wishport safely. Turn to Cities of Gold and Glory e217."]},{"tag":"e456","title":"Reporting to Marloes Marlock","desc":["'Ah, welcome, welcome,' says Marloes Marlock.","If you have the codeword Ambuscade, turn to e375. If not, but you have the codeword Ark and the royal ring, turn to e255.","Otherwise, you tell him you have not yet completed your mission. You are thrown out immediately before you have time to say more. 'Come back when you have better news, you worthless dog,' screams the provost marshal.","Turn to e010 and choose again."]},{"tag":"e457","title":"Unimpressive Music","desc":["They are unimpressed with your musical ability. The king waves his hand irritably. Suddenly, you wake up in your cabin, puzzled by your peculiar dream. If you have a blessing of Safety from Storms it is now gone – delete it from your blessings box. There are no other effects.","Turn to e507."]},{"tag":"e458","title":"The Road Between Caran Baru and Fort Mereth","desc":["The road between Caran Baru and Fort Mereth is another military highway for transporting troops and supplies."],"tables":[{"cols":["Ref","Option"],"rows":[["e060","North into the country"],["e548","South to the farmlands"],["e400","South west to Caran Baru"],["e299","North east to Fort Mereth"]]}]},{"tag":"e459","title":"The Mannekyn on a Leash","desc":["Cross off 50 💎. The little Mannekyn creature is handed over to you on a leash. Its wings have been tied together to stop it flying away. 'Who are you, then?' it pipes in a squeaky voice.","Just then, a palanquin, carried by four bearers, arrives. A man leans out and hails you, 'You there! I've come to buy that flying monkey but I see I am too late. Nevertheless, I will give you 75 💎 for it.'","'Don't sell me to that popinjay – free me instead,' chitters the Mannekyn."],"tables":[{"cols":["Ref","Option"],"rows":[["e659","Free it"],["e186","Sell it"]]}]},{"tag":"e460","title":"Down the Old Well","desc":["You climb down an old disused well in the poor quarter of Yellowport.","If you have the codeword Acid or a copper amulet, turn to e327 immediately. If not, read on.","It is dank, dark and smelly down below. If you do not have a light source, such as a lantern, you will have to return to the city – turn to e010. If you are a Mage you can use sorcery to create light. If you have a light source, read on.","You follow a tunnel into the darkness. Turn to e164."]},{"tag":"e461","title":"The Password Has Changed","desc":["You say the password 'Rebirth' to the door. 'Sorry,' says the Demon Door. 'The password changes once it has been used.' says the door smugly. 'I can't open for you.'","You will just have to leave."],"tables":[{"cols":["Ref","Option"],"rows":[["e110","North to the Bronze Hills"],["e333","West to the River Grimm"],["e560","South to the country"],["e387","East to the road"]]}]},{"tag":"e462","title":"Temple of the Twin Gods of the Sea","desc":["What service do you seek at the temple of the Twin Gods of the Sea?"],"tables":[{"cols":["Ref","Option"],"rows":[["e294","Become an initiate"],["e624","Renounce worship of Alvir and Valmir"],["e448","Seek a blessing"],["e010","Leave the temple"]]}]},{"tag":"e463","title":"The Gorlock is Inside","desc":["You remember the words of the old man you shared a prison cell with. This must be the lair of the gorlock that is said to have backward-pointing feet, so that the tracks it leaves will always show the opposite direction of travel! You realize that this means the gorlock is inside the cave."],"tables":[{"cols":["Ref","Option"],"rows":[["e174","Challenge the beast to combat"],["e287","Wait for it to leave the cave and sneak in"]]}]},{"tag":"e464","title":"Attacking the Crippled Ship","desc":["The ship, already crippled by a storm and with only half its crew, is easy meat for your hardy men. The strangely dressed foreigners surrender without much of a fight. You get 100 💎 as booty, and 1 Cargo Unit of spices, if you have the room to take it.","Now turn to e559."]},{"tag":"e465","title":"The Ker'ilk Attack","desc":["Several hideous creatures, which resemble giant lobsters, surge out of the water to attack you! You and your crew are taken by surprise, and things look bleak – some of your men are quickly killed, their bodies torn in two by powerful mandibles. The others begin to panic.","Make a Charisma roll at Difficulty 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e389","Successful Charisma roll"],["e214","Failed Charisma roll"]]}]},{"tag":"e466","title":"Road Between Blessed Springs and Fort Brilon","desc":["The road between Blessed Springs and Fort Brilon is patrolled by troopers of the Sokaran army. The fort is well-supplied from Blessed Springs, and traffic abounds."],"tables":[{"cols":["Ref","Option"],"rows":[["e259","Visit Fort Brilon"],["e510","Head for Blessed Springs"],["e548","Set off north into the farmlands"]]}]},{"tag":"e467","title":"Returning to the Temple of Tyrnai","desc":["The heavy wooden gates of the temple of Tyrnai are guarded by a couple of veteran warriors – the old iron bullmen are gone. Inside, the god is represented by a stone idol of a jaguar-headed warrior. He appears to be naked.","Suddenly, a priest shouts, 'It's the thief! The blasphemous devil has had the nerve to return here!' A score of warrior priests of Tyrnai boil out of the back rooms of the temple. You had better run for your life!","Roll a die. If the score is less than or equal to your Rank, turn to e395. Otherwise, turn to e551."]},{"tag":"e468","title":"The Man with the Velvet Eyepatch","desc":["You are walking down a side alley when a figure steps out of a doorway to block your path – it is a man with a velvet eyepatch. His one good eye glitters with evil humour from a face ravaged with the scars of many a fight.","'I hear you are looking for me,' he says in a silky voice.","Make a Thievery roll at Difficulty 11."],"tables":[{"cols":["Ref","Result"],"rows":[["e393","Successful Thievery roll"],["e014","Failed Thievery roll"]]}]},{"tag":"e469","title":"The Greatest Story Ever Told","desc":["He tells you of his life-long quest to find the 'Greatest Story Ever Told'. It is said that the god, Sig, in his aspect as the Divine Bard, passed this knowledge to a mystic called Damor the Hermit. He lives alone in a lost cave, awaiting the day when he can pass on the story to the one who finds him.","'I am too old now to pursue the quest – so I pass it on to you. I believe he can be found in the foothills of the Spine of Harkun, the mountains to the north. If you find Damor you will become a great Troubadour!'","Acquire the codeword Anthem. Turn to e100."]},{"tag":"e470","title":"The Would-be Pickpocket","desc":["You grab the woman's wrist and give it a painful twist. You are not being cruel for the sake of it – she was about to steal your money!","'Oh, let me go,' she pleads, showing you the little infant son she's carrying in her other arm. 'I need the money for my starving children and my poor crippled husband.'","Yellowport is full of wretched like this. With a snarl, you push her away, tossing a coin after her for good measure (cross 1 💎 off your Adventure Sheet).","Later, strolling down by the canal, you find a small bundle lying on the slick cobblestones. It is a doll wrapped in swaddling clothes to make it look like a baby. Turn to e010."]},{"tag":"e471","title":"The Shrine of Lacuna","desc":["If you have the codeword Animal, turn to e369. If not, read on.","The priestess, dressed in silken robes and wearing a wreath of oak leaves, says, 'I have need of an adventurer like yourself. For arcane reasons involving the secret mysteries of Lacuna, I need the tusk of a boar. A were-boar, in fact. I believe they can be found in the Forest of the Forsaken, in northern Golnir. Hunt down a were-boar, and bring me a boar's tusk. In return I will teach you how to be a better scout.'","If you accept the mission, acquire the codeword Animal. Turn to e544."]},{"tag":"e472","title":"Fort Estgard","desc":["If you have the codeword Dotage, turn to e667 immediately. If not, read on.","Fort Estgard is one of three forts along the wall that runs right along the border. Their purpose is to defend Sokara against the ravening manbeasts of Nerech, which are constantly trying to break through to raid the interior. The commander of the fort desperately wants to see you.","'My daughter, Alissia, has been kidnapped by the manbeasts!' he says. 'They are asking that I let one of their raiding parties through, to attack the farmlands. I'm delaying my response as long as possible, but if I don't do something soon, they will kill her! Please, I need a brave adventurer to rescue her!'","If you take up the quest, record the codeword Alissia."],"tables":[{"cols":["Ref","Option"],"rows":[["e225","Head east to Nerech (The Plains of Howling Darkness)"],["e299","North west to Fort Mereth"],["e259","South east to Fort Brilon"],["e548","West into the farmlands"]]}]},{"tag":"e473","title":"The Slave Market","desc":["The slave market is a large, canvas-covered square. The poor unfortunate slaves, people from all over Harkuna – from the Feathered Lands, Golnir, criminals of Sokara, nomads from the steppes – are paraded in chains on a dais. Merchants and nobles bid for the slaves they want. If there is a tick in the above box, turn to e610 immediately. If not, read on.","An unusual sale has come up – a little, furry, bat-winged humanoid. It is one of the Mannekyn People from Sky Mountain in the north and it is going for 50 💎.","If you want to buy it, turn to e459. If not, you head back into town. Turn to e400."]},{"tag":"e474","title":"The Coldbleak Mountains","desc":["The Coldbleak Mountains look as inhospitable and forbidding as their name implies, their frozen flanks climbing high into the icy clouds."],"tables":[{"cols":["Ref","Option"],"rows":[["e005","Climb into the mountains"],["e400","Enter Caran Baru"],["e347","Go west to the road"],["e548","Head into the farmlands"],["e135","Go south to the Lake of the Sea Dragon"]]}]},{"tag":"e475","title":"Slipping on the Ratman's Scraps","desc":["You slip on the rotting scraps of King Skabb's last meal and fall over with a crash. The ratmen turn to stare at you. 'A human! Get him!' screams Skabb.","The four ratmen charge toward you with a roar. Soon they have been joined by others and you have little choice but to turn and flee for your life! You race down the sewer tunnels, with an army of ratmen in hot pursuit."],"tables":[{"cols":["Ref","Option"],"rows":[["e079","Lose them in the tunnels"],["e296","Try some magic"],["e127","Hide"]]}]},{"tag":"e476","title":"The Eyepatch Man Draws His Sword","desc":["'Not bad,' says the man with the eye patch. 'But now I'll finish you!' He draws his sword, and you must fight.","If you win, turn to e092. If you lose you are dead unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Man with eyepatch","4","6","12"]]}]},{"tag":"e477","title":"Swallowed by Vayss","desc":["You cannot get away fast enough. With one gulp Vayss the Sea Dragon gobbles you up. Your adventuring days are over, unless you have a resurrection deal."]},{"tag":"e478","title":"Resurrection at the Temple of Nagil","desc":["Resurrection costs 200 💎 if you are an initiate, 600 💎 if not. It is the last word in insurance. Once you have arranged for resurrection you need not fear death, as you will be magically restored to life here at the temple.","To arrange resurrection, pay the fee and write 'Temple of Nagil (The War-Torn Kingdom e350)' in the Resurrection box on your Adventure Sheet. If you are later killed, turn to e350 in this book. You can have only one resurrection arranged at any one time. If you arrange resurrection later at a different temple, the original one is cancelled – cross it off your Adventure Sheet. You will not get a refund!","Turn to e071."]},{"tag":"e479","title":"Fighting the Tricksters","desc":["They seem quite alarmed to see you charge forward undaunted. As your first blow lands solidly and you hear a satisfying grunt of pain, you know for a fact that these are no ghosts that you are facing, but people of flesh and blood. Fight them one at a time:","If you win, turn to e171. If you lose, you are dead, unless you have a resurrection deal."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["First Trickster","2","3","3"],["Second Trickster","2","3","2"],["Third Trickster","2","3","2"]]}]},{"tag":"e480","title":"Damor's Teaching","desc":["'Well, tell you what – I'll teach you a few tricks, and then you can go away. What do you say?'","You've got nothing to lose so you accept. Damor was once a Troubadour, and he instructs you in its arts. Gain 1 Charisma point permanently. Afterwards, for a few hours, he lifts the curse that soured your water so you can make it down the mountain path safely.","Turn to e244."]},{"tag":"e481","title":"The Blessing of Maka","desc":["If you are an initiate it costs only 10 💎 to purchase Maka's blessing. A non-initiate must pay 20 💎. Cross off the money and mark Immunity to Disease and Poison in the Blessings box on your Adventure Sheet.","The blessing works by allowing you to ignore any one occasion when you would normally suffer from disease or poison – for instance, the venomous bite of a snake. When you use the blessing, cross it off your Adventure Sheet. You can have only one Immunity to Disease and Poison blessing at any one time. Once it is used up, you can return to any branch of the temple of Maka to buy a new one.","Turn to e141."]},{"tag":"e482","title":"The Blessing of Lacuna","desc":["If you are an initiate it costs only 10 💎 to purchase Lacuna's blessing. A non-initiate must pay 25 💎. Cross off the money and mark Scouting in the Blessings box on your Adventure Sheet.","The blessing works by allowing you to try again when you make a failed Scouting roll. It is only good for one reroll. When you use the blessing, cross it off your Adventure Sheet. You can have only one Scouting blessing at any one time. Once it is used up, you can return to any branch of the temple of Lacuna to buy a new one.","When you are finished here, turn to e615."]},{"tag":"e483","title":"The Tavern at Blessed Springs","desc":["The tavern costs you 1 💎 a day. Each day you spend here, you can recover 1 ❤️ if injured, up to the limit of your normal unwounded Stamina score.","If you want to spend 3 💎 buying drinks all round at the bar and listen for rumours, turn to e323. Otherwise, turn to e510."]},{"tag":"e484","title":"Lost at Sea","desc":["You sail for days without sight of land. Soon you have run out of water, and the crew start dying of thirst. You lose 1–6 ❤️ (the roll of one die) and several of your men. Reduce your crew to poor quality (unless it is already poor, in which case nothing happens).","Eventually, you find a familiar stretch of coast. Roll one die:"],"tables":[{"cols":["Score","Ref"],"rows":[["1–2","e120"],["3–4","e430"],["5–6","e136"]]}]},{"tag":"e485","title":"Ship Lost to the Deep","desc":["Your ship, crew and cargo are lost to the deep, dark sea. Your only thought now is to save yourself. Roll two dice. If the score is greater than your Rank, you are drowned – turn to e680. If the score is less than or equal to your Rank, you manage to find some driftwood and make it back to shore. Lose Stamina points equal to the score of one die roll and, if you can survive that, turn to e193."]},{"tag":"e486","title":"The Gorlock Surprises You","desc":["Everything indicated the cave is empty so you approach carefully, on the look out for attack from behind. Suddenly, something rushes out of the cave, taking you by surprise! It is a gorlock, a beast with legs like a bird, a body like a reptile, with two short forelimbs and a beaked, lizard-like head. You see that its two legs end in backward-pointing feet – the tracks it leaves will always show the wrong direction of travel!","It bites at you savagely, and you lose 4 ❤️. If you still live, you will have to fight.","If you win, turn to e315. If you lose, your bones will join the others at the entrance of the cave – turn to e680."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Gorlock","4","6","7"]]}]},{"tag":"e487","title":"Scouting the Sunken City","desc":["Make a Scouting roll at Difficulty 11."],"tables":[{"cols":["Ref","Result"],"rows":[["e348","Successful Scouting roll"],["e189","Failed Scouting roll"]]}]},{"tag":"e488","title":"Sold into Slavery by the Priests","desc":["You collapse, dying. A priest of Tyrnai, however, heals you so that you come round with 1 ❤️ left. It is not out of kindness that he has done this. The priests take all your money and possessions (cross them off your Adventure Sheet) and sell you into slavery. You are set to work in the tin mines outside the city.","Turn to e118."]},{"tag":"e489","title":"Enchanted Pebbles","desc":["Later, in your cabin, you examine the pearls more closely. To your horror, they lose their pearly sheen and return to their natural state – tiny pebbles. Some enchantment had been laid upon them to make them look like pearls. Cursing the young Sea Gypsy, you vow to be more careful next time.","Turn to e085."]},{"tag":"e490","title":"The Tomb Guardian Defeated","desc":["When you hit the guardian, you tear away great wispy chunks of its smoky essence. Eventually, it dissolves into nothingness.","Inside the sarcophagus you find the mouldering bones of a long-dead wizard. In his skeletal hands you find the Book of Excellence. As you scan the pages, you learn all sorts of new tricks – add one to the ability of your choice (such as Scouting or Combat) permanently. Once you have read it, the book disappears with a flash.","You thread your way out of the Tomb of the Wizard King, back into the Forest of Larun. Turn to e047."]},{"tag":"e491","title":"Overcome by the Noxious Breath","desc":["You succumb to the insidious breath of the beast. Death has claimed you. Your adventuring days are over, unless you have a resurrection deal."]},{"tag":"e492","title":"The Track to Scorpion Bight","desc":["You are on a rough track that runs between Venefax and the territories of the scorpion men, slogging your way through hot, dry scrubland. A hawk circles overhead, cawing harshly."],"tables":[{"cols":["Ref","Option"],"rows":[["e427","Go north to Venefax"],["e318","Go south into Scorpion Bight"]]}]},{"tag":"e493","title":"Swimming with Gills","desc":["Gills grow out of your neck as soon as you have read the runes aloud! You make your way down a track to the beach, and swim out to sea. The gills work perfectly, and you find yourself swimming in the eerie silence of a submarine world.","Suddenly, a hideous form looms out of the murk. It is rather like a giant squid, but it carries a spear in one of its many tentacles and wears rudimentary armour. Great black eyes shine with an implacable alien intelligence.","If you have the codeword Anchor, turn to e116. Otherwise, turn to e238."]},{"tag":"e494","title":"Disguised as a Ratman","desc":["You dodge down a side tunnel, and mutter an enchantment intended to give you the appearance of a ratman. Your pursuers come bundling around a corner – one of them stops to shout at you, 'Where'd the human go?'","Nonchalantly, you point down the tunnel, and the ratmen go haring off down it, whooping and yelling. You turn and walk the other way, a smile on your face.","Turn to e580."]},{"tag":"e495","title":"Disaster Bay","desc":["You arrive at Disaster Bay, where you find a community of fishermen. Judging by their wealth, they also make a living by other means – you suspect by looting the ships that get wrecked in the stormy waters of the bay.","A man offers to take you by boat, safely through the bay, and north to the port of Yarimura, on the Great Steppes. It will cost you 50 💎."],"tables":[{"cols":["Ref","Option"],"rows":[["e025","Pay 50 💎 to go to Yarimura (The Plains of Howling Darkness)"],["e244","Head north to the mountains"],["e518","Head for the road"],["e299","Head for Fort Mereth"]]}]},{"tag":"e496","title":"The Strange Craft","desc":["If there is a tick in the box, turn to e317 immediately. If not, put a tick there now, and read on.","You manoeuvre your ship as close as possible, and then take a rowboat over to the craft. Climbing inside, you find yourself in a small cabin which is lit by wining red and green lights set into the walls. A figure lies sprawled beside an ornate couch. The figure, although manlike, appears to have silver skin, and a great big round head, with one black, glittering eye that seems to fill its whole face. Whatever it is appears to be dead.","Quickly you search the craft, and find a kind of spear that fires steel balls from one end. It counts as a magic spear (Combat +2).","Worried that you may be meddling with a ship of demons, you head back quickly, and sail on. Turn to e085."]},{"tag":"e497","title":"The Scorpion's Sting Tavern","desc":["The tavern costs you 1 💎 a day. Each day you spend here, you can recover 1 ❤️ if injured, up to the limit of your normal unwounded Stamina score.","If you want to spend 3 💎 buying drinks for the locals and ask them about the scorpion men, turn to e525. Otherwise, turn to e427."]},{"tag":"e498","title":"Beaten by the Soldiers","desc":["There are too many of them, and they give you a good hiding. 'Maybe that'll teach you some respect,' one of them says, as they swagger off, leaving you groaning in the gutter. You are reduced to only 1 ❤️. You decide to call it a night.","Turn to e100."]},{"tag":"e499","title":"Back Aboard Ship","desc":["You board your ship, which is docked in the harbour. The crew give a drunken cheer as you come on board. 'Where are we bound, Cap'n?' asks the first mate."],"tables":[{"cols":["Ref","Option"],"rows":[["e555","Return to shore"],["e029","Set sail"]]}]},{"tag":"e500","title":"Resurrected at the Temple of Tyrnai","desc":["You are restored to life at the war-god's temple in Yellowport. Your Stamina is back to its normal score. The possessions and cash you were carrying at the time of your death are lost – cross them off your Adventure Sheet. Also remember to delete the entry in the Resurrection box now it has been used.","The high priest, pale and wan after the effort of interceding with the god to bring you back to life says, 'You have returned from beyond the dark mirror of death. Tyrnai has granted you another chance – strive to seek battle in his name!'","Turn to e526."]}]`),_=JSON.parse(`[{"tag":"e501","title":"Released After Ransom","desc":["If you didn't have enough money in the bank to cover the ransom demand, turn to e288. Otherwise, your captors take the money and run. You are released into Yellowport.","Turn to e010."]},{"tag":"e502","title":"Into the Violet Ocean","desc":["'The Violet Ocean's a dangerous place, Cap'n,' says the first mate. 'The crew probably won't follow you there if they don't think you're good enough!'","If your Rank is 4 or more, turn to paragraph e077 in Over the Blood-Dark Sea.","If your Rank is less than 4, the first mate advises you against the ocean journey. If you take his advice, turn back to e420.","If you insist on making the trip, you need to make a Charisma roll at Difficulty 12 to convince the crew to follow you."],"tables":[{"cols":["Ref","Result"],"rows":[["e077","Successful Charisma roll"],["e420","Failed Charisma roll"]]}]},{"tag":"e503","title":"The Scorpion Man is an Illusion","desc":["Your magical awareness tells you that something is wrong. You realize that the scorpion man is an illusion – a magically created disguise! The illusion falls away under your keen magical sight, and a rather fat little fellow is standing before you, dressed in a dirty, food-stained tunic.","'Ah...' he says, realizing his subterfuge has been uncovered. He drops to his knees, pleading, 'Please don't kill me! Please don't kill me!'","You manage to calm him down enough to find out his story. His name is Kaimren the Portly, a minor sorcerer. He came here in the guise of a scorpion man, and swiftly rose to power using his magical skills. He had planned to use the scorpion men as an army.","Fearfully, he hands you the Book of the Seven Sages, which he stole to further his campaign of conquest. Note it on your Adventure Sheet.","Then Kaimren leads you through a secret tunnel, out of the mound, and back to the village of Venefax, where you hand him over to the Venefax authorities for trial.","Record the codeword Afraid and turn to e427."]},{"tag":"e504","title":"A Wrecked Ship Spotted","desc":["If there is a tick in the box, turn to e345 immediately. If not, put a tick there now, and read on.","The lookout spots a ship, its back broken on some rocks near the shore. The vessel will not last long before it is washed away."],"tables":[{"cols":["Ref","Option"],"rows":[["e209","Ignore it"],["e039","Explore the wreck"]]}]},{"tag":"e505","title":"Tribute Paid to Vayss","desc":["Cross the silver nugget off your Adventure Sheet. 'Excellent,' says the dragon, catching the nugget in one of its clawed forelimbs.","With that, it rolls over, and dives down into the lake. At the last second, its tail whips up out of the water, inches from your face. You could reach out and grab it, if you wanted to."],"tables":[{"cols":["Ref","Option"],"rows":[["e362","Catch the tail"],["e561","Leave it well alone"]]}]},{"tag":"e506","title":"The Gold Dust Tavern","desc":["The Gold Dust Tavern is a plush inn besides the city gates. The tavern costs you 1 💎 a day. Each day you spend here, you can recover 1 ❤️ if injured, up to the limit of your normal unwounded Stamina score.","If you want to spend a further 3 💎 buying drinks all round at the bar and listen for rumours, turn to e331. Otherwise, turn to e010."]},{"tag":"e507","title":"The Sea of Whispers","desc":["You are sailing across the Sea of Whispers with a clear, blue sky and a salty wind to help you on your way."],"tables":[{"cols":["Ref","Option"],"rows":[["e195","Dock at the Isle of Druids"],["e430","Sail west towards Scorpion Bight"],["e190","Sail north west into coastal waters"],["e312","Sail north into coastal waters"],["e013","Sail south into the Violet Ocean"],["e206","Sail east into the Unbounded Ocean"]]}]},{"tag":"e508","title":"Captured by the Unspeakable Ones","desc":["You come round inside a disused warehouse, enmeshed in the net. You have been stripped of all your possessions – they are in a tidy pile nearby. Several men surround you. They are dressed in furs and robes that are adorned with hundreds of multi-coloured feathers. Each man wears a necklace of animal skulls and has his teeth sharpened to needle-like points.","'Hallo,' the leader says reasonably. 'We are the Unspeakable Ones – it is our way to eat people in sacrifice of our god.' He points to a squat wooden idol of a grossly fat half-man, half-ape with ivory needles for teeth. You notice the name 'Badogor the Unspoken' inscribed on a plaque at the base of the idol.","'Badogor the Unspoken – who's he?' you ask. 'Do not speak his name!' shouts the cannibal, 'Or you will be forever cursed!'","You notice a large cauldron of boiling water into which another cultist is tossing herbs and garlic. He stares at you and licks his lips.","Turn to e320."]},{"tag":"e509","title":"The Chain Mail Taken Without Triggering the Trap","desc":["You spot a pressure pad at the base of the idol just in time – who knows what unpleasant trap that would have set off! Quickly, you remove the chain mail and sling it over your shoulder. Note the gold chain mail of Tyrnai on your Adventure Sheet – as it is gold, it is useless as actual armour.","The eyes of the jaguar-headed idol seem to turn to look at you. Make a Sanctity roll at Difficulty 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e625","Successful Sanctity roll"],["e279","Failed Sanctity roll"]]}]},{"tag":"e510","title":"Blessed Springs","desc":["The village of Blessed Springs, nestling at the foot of a tall hill, has grown up around the holy waters, a special spring said to have healing powers. It has been fenced off by the villagers, and a priesthood appointed to supervise the supplicants who come to bathe, or drink of the spring's waters. There is no market, but an alchemist has set up shop here."],"tables":[{"cols":["Ref","Option"],"rows":[["e450","Visit the Holy Waters"],["e342","Visit the alchemist's shop"],["e483","Visit the Blessed Ale Tavern"],["e398","Explore the hill"],["e466","Head north towards Fort Brilon"],["e087","South towards Venefax"],["e278","West into the countryside"],["e548","North west into farmlands"]]}]},{"tag":"e511","title":"Knowledge of Ghouls","desc":["Your arcane knowledge tells you much about the undead. Ghouls are known to eat the flesh of the dead as well as the living. They like to make their homes in crypts and graveyards and they never venture out during the day, as sunlight burns their pallid undead flesh. Also, they cannot abide a powder of salt and iron filings mixed together.","You can purchase these ingredients for 15 💎 at many a market stall. If you make the purchase, note you have salt and iron filings on your Adventure Sheet.","When you are ready, you set off to search the cemeteries of Marlock City. Make a Scouting roll at Difficulty 9."],"tables":[{"cols":["Ref","Result"],"rows":[["e419","Successful Scouting roll"],["e360","Failed Scouting roll"]]}]},{"tag":"e512","title":"Report to the Merchants' Guild","desc":["If you have a pirate captain's head and want to give it to the guildmaster, turn to e163. If not, read on.","'Do you have the head of Amcha the Pirate?' asks the guildmaster. 'No! Then what are you doing here? He is plying his evil trade in the seas to the south, and his base lies to the east of the Sorcerers' Isle. Now go!'","Turn to e100."]},{"tag":"e513","title":"Transformed into a Sea Centaur","desc":["One of them gives you a conch shell full of a greenish liquid. You drink it, and dive into the sea. Miraculously, you can breathe underwater! You follow the sea centaurs down into the depths until you arrive at a sunken ship, which is encrusted in barnacles and seaweed.","Suddenly, the sea centaurs swim away, leaving you alone. You notice that you are giving off a glow like the sea centaurs. Looking down, you see that the lower half of your body has turned into that of a sea centaur! You have been taken and transformed to replace their lost companion."],"tables":[{"cols":["Ref","Option"],"rows":[["e429","Explore the sunken wreck"],["e616","Swim back up to your ship"]]}]},{"tag":"e514","title":"Renouncing the Worship of Tyrnai","desc":["To renounce the worship of Tyrnai, you must pay 50 💎 to the warrior priests, and suffer the 'Wrathful Blow'. A priest will strike you once – it is better to be struck by a priest than by Tyrnai himself!","If you are determined to renounce your initiate status, pay the 50 💎 and delete Tyrnai from the God box on your Adventure Sheet. The high priest smashes you across the jaw, saying 'I'm doing you a favour – believe me!' Lose 1 ❤️. If you earlier arranged a resurrection here, it is cancelled with no refund.","When you have finished, turn to e282."]},{"tag":"e515","title":"Reading the Runes","desc":["Make a Magic roll at Difficulty 11."],"tables":[{"cols":["Ref","Result"],"rows":[["e205","Successful Magic roll"],["e314","Failed Magic roll"]]}]},{"tag":"e516","title":"Into the Wolf Cave","desc":["You pull the wolf pelt over you, and drop to all fours. Gingerly, you crawl in. In the dark, you now look and smell like a wolf. At the back of the cave, you find a hole in the roof and an iron ladder leading up to it."],"tables":[{"cols":["Ref","Option"],"rows":[["e350","Climb the ladder (The Plains of Howling Darkness)"],["e003","Leave the cave"]]}]},{"tag":"e517","title":"The Temple of Nagil","desc":["If you have a ghoul's head, turn to e597. If not, a priest asks which service you require."],"tables":[{"cols":["Ref","Option"],"rows":[["e409","Become an initiate"],["e187","Renounce worship"],["e478","Make resurrection arrangements"],["e100","Leave the temple"]]}]},{"tag":"e518","title":"Road Between the Citadel and Fort Mereth","desc":["You are on the road between the Citadel of Velis Corin and Fort Mereth. This is quite rarely travelled – the military guardposts are few and far between.","Roll one die:"],"tables":[{"cols":["Score","Result"],"rows":[["1–2","Lose 10 💎 gambling (if you have it)"],["3–4","Nothing happens"],["5–6","A sweet spring heals you of up to 3 ❤️"]]},{"cols":["Ref","Option"],"rows":[["e495","Go to Disaster Bay"],["e271","Head for the Citadel of Velis Corin"],["e299","Travel to Fort Mereth"],["e060","Go south west into wild country"]]}]},{"tag":"e519","title":"The Ker'ilk Driven Off","desc":["Your crew have driven off the other ker'ilk, which dive into the sea. The ship was carrying 1 Cargo Unit of furs, which you can take if your ship has room. You clean up the dead sailors and give them a proper burial at sea. There is nothing else of interest, so you sail on.","Turn to e209."]},{"tag":"e520","title":"Prayer Has No Effect","desc":["You hold up your arms and utter the mightiest prayer that you know. It has no effect.","The three white figures pelt you with a barrage of plates and knives. Something heavy hits you on the side of the head and you fall with a groan. The ghosts take advantage of this to snatch up the casket of silver and run off. Lose 2 ❤️.","If you still live, you recover your wits to find that the three figures have vanished. But you are sure now that they were not ghosts."],"tables":[{"cols":["Ref","Option"],"rows":[["e541","Try to track them down"],["e576","Follow the river north"],["e082","Follow the river south"],["e278","Head east into the countryside"],["e558","West to the main road"]]}]},{"tag":"e521","title":"Seeking the Black Dragon Knight","desc":["You are looking for the Black Dragon Knight on a quest that was set for you by Yanryt the Son. You ask the knights if he is here.","'The Black Dragon Knight? Yes, he is,' replies one of them. 'But he fights only to the death – there is no wager save the greatest of all for him, that is to say, life itself.'"],"tables":[{"cols":["Ref","Option"],"rows":[["e321","Fight the Black Dragon Knight"],["e276","Don't fight and leave instead"]]}]},{"tag":"e522","title":"The Sea Centaurs Come at Night","desc":["That night several sea centaurs emerge from the waters, their spiny skins glittering with phosphorescent flashes of light.","One of them speaks in a burbling voice. 'Where is our brother, whom you caught in your cruel nets, this day?' 'He is dead, I'm afraid,' you reply, readying yourself for a fight.","The sea centaurs remain silent for a few moments, then the leader says, 'His destiny was always bleak. We would be grateful if you were to return his body to us.'","You cannot think of a reason not to, so you pass the body down to them. 'We thank you,' burbles the sea centaur. 'If you wish, we will give you the power to breathe the waters, so that you may swim down to the wreck that lies below, and take its treasures, those things that the surface-dwellers hold dear.'"],"tables":[{"cols":["Ref","Option"],"rows":[["e513","Accept the offer"],["e408","Refuse the offer"]]}]},{"tag":"e523","title":"The Provost Marshal's Office","desc":["If you have the codeword Assassin, turn to e027 immediately. If not, if you have the title Protector of Sokara, you are sent in to see the provost marshal immediately – turn to e095.","Otherwise, you have to wait several hours to be seen by one of the provost marshal's aides, a certain Captain Royzer.","If you have the codeword Artery, Royzer sends you in to see Marloes Marlock immediately – turn to e456.","Otherwise, you will have to convince the captain it is worth his while to let you see the provost marshal. If you are a Warrior, Rogue or Troubadour, Royzer will let you in for the modest bribe of 5 💎 – turn to e191.","If you are a Wayfarer, Priest or Mage, you will have to convince the captain of your loyalty to Sokara first. Make a Charisma roll at Difficulty 9. If you are successful, you can then bribe him – pay 5 💎 and turn to e191.","If you fail your Charisma roll or do not wish to pay the bribe, Captain Royzer dismisses you rudely. Turn to e010."]},{"tag":"e524","title":"Struggling On to the Well","desc":["You struggle on. Only your iron will and hardiness keep you alive. Eventually, the path leads to a bubbling well of springwater in the rocks, just at the opening of a cave. You drink your fill, and soon you feel much better.","Turn to e232."]},{"tag":"e525","title":"Tales of the Scorpion Men","desc":["'They're vicious, evil devils,' says an old peasant. 'Like huge scorpions they are, save they have the head and shoulders of a man – intelligent too, forever seeking to pillage our town, but they can't climb up the ladders!'","A soldier in the local militia speaks up, 'They hate fire, too. All we have to do is sit atop the town, and pepper them with flaming arrows. They can't stand that for long. Mind you, things are getting bad – they've got a sorcerer now!'","A young man, blind in one eye and paralysed down one side, says, 'They got a terrible sting as well – their venom did this to me,' pointing at his eye and side.","There's not much else to hear, so you leave. Turn to e427."]},{"tag":"e526","title":"The Temple of Tyrnai in Yellowport","desc":["The temple of Tyrnai, the God of War, is built in the shape of a spear with a long, pillared nave, and an altar at the far end. Two massive stone warriors guard its gates.","Tyrnai is depicted here as the insensate spirit of war – a blood-drenched warrior with the head of a maddened jaguar."],"tables":[{"cols":["Ref","Option"],"rows":[["e435","Become an initiate"],["e069","Renounce his worship"],["e373","Seek a blessing"],["e599","Make resurrection arrangements"],["e010","Leave the temple"]]}]},{"tag":"e527","title":"Fleeing the Gob-gobbler","desc":["You run off, leaving the terrible Gob-gobbler behind. The villagers of Venefax greet you with snorts of derision and contempt, and the young boy, Mikail, looks away, disappointed. It would be prudent to leave Venefax for a while."],"tables":[{"cols":["Ref","Option"],"rows":[["e492","South into Scorpion Bight"],["e087","North east towards Blessed Springs"],["e621","South west on the road to Yellowport"],["e278","North into open countryside"]]}]},{"tag":"e528","title":"Sneaking into the Temple","desc":["You attempt to sneak in through the back of the temple that night. Make a Thievery roll at Difficulty 11."],"tables":[{"cols":["Ref","Result"],"rows":[["e445","Successful Thievery roll"],["e284","Failed Thievery roll"]]}]},{"tag":"e529","title":"A Nasty Fall","desc":["You loose your footing, and fall. Fortunately, some bushes break your fall, and you lose only 4 ❤️. If you still live, turn back to e474."]},{"tag":"e530","title":"Storm-tossed and Lost","desc":["Your ship is thrown about like flotsam and jetsam. When the storm subsides, you take stock. Much has been swept overboard – you lose 1 Cargo Unit, if you had any, of your choice. Also, the ship has been swept way off course and the mate has no idea where you are. 'We're lost at sea, Cap'n!' he moans.","Turn to e090."]},{"tag":"e531","title":"At the Temple of Alvir and Valmir","desc":["If you have a golden net, turn to e004. If you do not have one, turn to e462."]},{"tag":"e532","title":"The Scorpion Shaman Falls","desc":["The scorpion men's shaman falls dead with an uncannily human cry. If you were wounded in that fight, you have been poisoned by the scorpion man's venom. Subtract 1 from your Combat, Thievery and Scouting abilities, as you are severely weakened (though no ability can drop to zero). Note that you are poisoned – you can restore your ratings to normal if you get cured. If you have some scorpion antidote, it will cure the poison immediately (cross off the antidote).","A quick search reveals what you were looking for – the Book of the Seven Sages. Note it on your Adventure Sheet.","You steal out of the mound unnoticed and make it safely back to the village of Venefax, to the north. Turn to e427."]},{"tag":"e533","title":"The Man Takes the Money","desc":["The man takes the money, bites a coin and spits. Satisfied he says, 'The Witches' Cauldron – that's where you'll find him.'","Later, you find the Witches' Cauldron Tavern in a maze of backstreets. Looking through a window, you spot a man with a velvet eyepatch sitting at a table, eating a meal."],"tables":[{"cols":["Ref","Option"],"rows":[["e589","Walk in and challenge him"],["e211","Ambush him when he leaves"]]}]},{"tag":"e534","title":"Waiting for Lauria","desc":["A long time passes. After a while, you risk calling up to Lauria in a whisper. Your voice sounds thick, rasping – choked with growing fear. Lauria does not reply.","Each second you remain in the house increases the risk of discovery."],"tables":[{"cols":["Ref","Option"],"rows":[["e119","Wait a little longer"],["e386","Go upstairs to find Lauria"],["e010","Leave at once"]]}]},{"tag":"e535","title":"The House of Priests","desc":["The House of Priests is an impressive building, a roundhouse of multi-coloured bricks. The myriad colours give it a bizarre and garish look, calculated to unsettle the visitor. Inside, a hundred offices teem with the administration of the polytheistic religion of Sokara and Golnir.","If you are a Priest, turn to e009. If not, there is little for you here, turn back to e100."]},{"tag":"e536","title":"Climbing into the Mountains","desc":["If you have some climbing gear, turn to e628. If not, make a Scouting roll at Difficulty 12."],"tables":[{"cols":["Ref","Result"],"rows":[["e562","Successful Scouting roll"],["e438","Failed Scouting roll"]]}]},{"tag":"e537","title":"The Sea Gypsies","desc":["You find out that they call themselves the Gypsies of the Sea, wandering nomads of the waves, who find their islands naturally occurring in the Sea of Weeds. They make their homes upon them, and live a life of aimless drifting.","A tanned young man, full of wit and charm, explains that he makes his living from pearl diving, and selling what he finds to people like yourself. He offers you a bag of pearls for 25 💎."],"tables":[{"cols":["Ref","Option"],"rows":[["e106","Buy the pearls"],["e085","Leave and resume your journey"]]}]},{"tag":"e538","title":"Refusing to Pay Taxes","desc":["'Refusing to pay your taxes, eh!' says their leader. 'That's a crime for sure!'","They close in around you. You'll have to think fast. Make a Charisma roll at Difficulty 11."],"tables":[{"cols":["Ref","Result"],"rows":[["e018","Successful Charisma roll"],["e157","Failed Charisma roll"]]}]},{"tag":"e539","title":"Disabling the Second Golem","desc":["You roll across the eaves of the gate and reach down to pull the plug on the other golem in one deft movement. It ceases to function before it can give the alarm. It is an easy matter to get into the temple from the roof.","Inside, it is cool and dark, filled with an unearthly stillness. You reach forward to strip the armour off the idol of Tyrnai.","Make a Thievery roll at Difficulty 12."],"tables":[{"cols":["Ref","Result"],"rows":[["e509","Successful Thievery roll"],["e228","Failed Thievery roll"]]}]},{"tag":"e540","title":"Following the Ruffians","desc":["Sure enough, when the scholar leaves, purse bulging with Shards, the two ruffians also leave. You follow at a slight distance. As you suspected, the ruffians wait for a suitable moment and then set about the scholar.","'Help, help! Thieves!' cries the scholar in a thin, reedy voice."],"tables":[{"cols":["Ref","Option"],"rows":[["e100","Return to the city centre"],["e433","Chase the muggers off"]]}]},{"tag":"e541","title":"Following the Footprints","desc":["Burdened by the heavy chest full of coins, the three figures have left deep footprints in the grass.","Make a Scouting roll at a Difficulty of 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e326","Successful Scouting roll"],["e245","Failed Scouting roll"]]}]},{"tag":"e542","title":"Celebrated by Drunken Soldiers","desc":["If there is a tick in the box, turn to e620 immediately. If not, put a tick there now, and read on.","'By Tyrnai! It's the one who killed that pretender to the throne, Nergan Corin!' says one of them. They line up and give you a drunken salute, and then fall to slapping you on the back, and offering to buy you beers all night.","They also give you a present – a potion of strength (Combat +1). Note it on your Adventure Sheet. When used it will add 1 to your Combat rating, for one Combat roll, or one fight only, after which it will wear off.","Turn to e100."]},{"tag":"e543","title":"The Guildmaster is Too Busy","desc":["Guildmaster Vernon is too busy to see you. It seems he doesn't want to know you, now that he doesn't need you anymore. Such is life.","Turn to e405 and choose again."]},{"tag":"e544","title":"The Shrine of Lacuna at the Trading Post","desc":["The shrine is set in a wooded grove. Birds twitter in the trees, and a deer darts away into the forest at your approach. A priestess is tending a low altar, where food and drink has been laid out in honour of Lacuna, the Goddess of the Wilderness. She is the patron of hunters, trappers, woodsmen, and all those who seek oneness with nature."],"tables":[{"cols":["Ref","Option"],"rows":[["e618","Become an initiate of Lacuna"],["e334","Renounce the worship of Lacuna"],["e052","Seek a blessing"],["e471","Talk to the priestess"],["e195","Leave the temple"]]}]},{"tag":"e545","title":"The Trau in the Cage","desc":["You are given the cage. The trau speaks to you so quickly that you can barely distinguish the syllables.","'Let me out of here, and I'll reward you!' it says."],"tables":[{"cols":["Ref","Option"],"rows":[["e642","Free it"],["e651","Sell it to the mines in the Bronze Hills"]]}]},{"tag":"e546","title":"Saving the Sorceress","desc":["With a heroic effort, you manage to get to the woman. Gathering her up, you run for the door, and stagger out into the cool night air, smoke and flame licking at your heels. The townsfolk give you a rousing cheer and the girl thanks you effusively for saving her mother.","Later, it transpires that the woman is actually a powerful sorceress whose experiments in fire magic went slightly wrong. Her name is Elissia the Traveller and she gives you a gift – a pale moonstone. Note moonstone of teleportation – The War-Torn Kingdom, e650 on your Adventure Sheet.","Elissia tells you that you can use the moonstone by rubbing it, and you will be instantly teleported to the vicinity of the sunstone – which she carries on a necklace.","'I will be here in Marlock City. Whenever you are desperate, at the end of your tether, or just want to get here fast, use the moonstone and you will appear beside me. I will do everything in my power to aid you, and then my debt to you will be repaid.'","Whenever you want to use the moonstone, turn to e650 in this book. Now turn to e100."]},{"tag":"e547","title":"The Sunken City of Ziusudra","desc":["Your instinct was correct. The sea bed suddenly drops away, to reveal the ruins of the Sunken City of Ziusudra. Crumbling towers climb out of the hazy green depths, and shoals of flashing silverfish dart through the abandoned windows and doors of coral-encrusted buildings.","The creature you are following arrows down towards a large dome-like structure covered in waving tendrils of seaweed. It disappears through a hole in the roof of the dome.","Carefully, you swim down to the hole and look through, into the palace of the repulsive ones.","Turn to e041."]},{"tag":"e548","title":"The Farmlands","desc":["You are crossing an area of fertile farmland, where much of the food is grown to feed the army. Little farmsteads dot the landscape, and the ploughed fields have the appearance of a patchwork quilt.","Roll one die:"],"tables":[{"cols":["Score","Result"],"rows":[["1–2","Mistaken for a murderer! Forced to flee into the mountains – turn to e474"],["3–4","Nothing happens"],["5–6","Find some leather armour (Defence +1)"]]},{"cols":["Ref","Option"],"rows":[["e472","East to Fort Estgard"],["e458","North to the road"],["e510","South to Blessed Springs"],["e474","To the Coldbleak Mountains"],["e135","To the Lake of the Sea Dragon"]]}]},{"tag":"e549","title":"Another Boar's Tusk","desc":["The priestess, dressed in a cloak made entirely of the leaves of trees, with her face smeared with moss, greets you. 'A tusk!' she exclaims. 'But I have no need of another.'","You ask if she might need it for the next time. 'Next time? Mmm, maybe you have a point.' She offers you 15 💎. If you accept, cross off the boar's tusk.","Either way, when you leave, turn to e195."]},{"tag":"e550","title":"Delivering the Chain Mail","desc":["If you have the gold chain mail of Tyrnai, turn to e380. If not, turn to e134."]},{"tag":"e551","title":"Overpowered by the Warrior Priests","desc":["You cannot escape – there are too many of them and all of them are seasoned warriors of Tyrnai. You are overpowered and given a savage beating – you are reduced to only 1 ❤️. They take all your money and possessions. Cross them off your Adventure Sheet. The priests do not have you sacrificed to Tyrnai – instead you are sold into slavery and set to work in the tin mines outside the city.","Turn to e118."]},{"tag":"e552","title":"The Sokaran Captain's Demands","desc":["A swaggering Sokaran captain marches on board with a complement of marines. 'I don't think you've paid your harbour duties,' he says.","'Harbour duties! We're in the middle of the sea!' you exclaim angrily.","The captain smiles smugly at you. 'You'd better cough up 50 Shards, or I'll impound your ship and its cargo.' 'But that's no better than common piracy!' says your first mate, outraged.","'The duty will be 60 Shards now, for calling a captain in the Sokaran Imperial Navy a pirate!' he sneers. Several of his men burst into laughter.","If you have the title Protector of Sokara, turn to e185. Otherwise, you can:"],"tables":[{"cols":["Ref","Option"],"rows":[["e401","Hand over the money (if you have it!)"],["e311","Refuse outright"]]}]},{"tag":"e553","title":"The Little Girl at the Cemetery","desc":["You convince her that you mean no harm. The little girl tells you that she was placing flowers at the grave of her father, when a horrible monster came for her. Fortunately, she was able to run away. She points to a large tomb behind which the thing was hiding.","You tell the girl to go home and then you set out warily for the tomb. Suddenly, a foul stench fills your nostrils, and a figure rises up out of the shadows! Yellow eyes glow with feral blood-lust, and the creature's talons, encrusted with dried blood, reach for you hungrily. You've found the ghoul!"],"tables":[{"cols":["Ref","Option"],"rows":[["e617","Fight it"],["e144","Invoke the power of the gods"],["e303","Use some salt and iron filings"]]}]},{"tag":"e554","title":"King Skabb Defeated","desc":["King Skabb's rusty iron crown shattered when he fell, so you take the copper amulet from around his neck. Note it on your Adventure Sheet. You also find a chest in the corner of the room but it is clearly booby-trapped. You can open it using magic, or your skills as a thief.","To pick the lock, make a Thievery roll at Difficulty 9. To use sorcery, make a Magic roll at Difficulty 9."],"tables":[{"cols":["Ref","Option"],"rows":[["e006","Successful roll"],["e064","Failed roll"],["e010","Leave the chest and return to the surface"]]}]},{"tag":"e555","title":"Yellowport Harbourmaster","desc":["All shipping in and out of Yellowport must come through the offices of the harbourmaster. Here you can buy passage to far lands, or even a ship of your own, to fill with cargo and crew.","You can buy one-way passage on a ship to the following destinations: (see table below)","If you buy a ship, you are the captain and can take it where you wish, exploring or trading. Three types of ship are available.","If you buy a ship, add it to the Ship's Manifest and name it as you wish. The quality of the ship's crew is poor, unless you upgrade it. If you already own a ship you can sell it back to the harbourmaster at half the above prices.","It costs 50 💎 to upgrade a poor crew to average, and 100 💎 to upgrade an average crew to good. Excellent quality is not available in Yellowport.","If you own a ship, you can buy as many Cargo Units as it has room for. You may also sell cargo, if you have any. Prices are for single Cargo Units.","Fill in your current cargo on the Ship's Manifest. If you own a ship and wish to set sail, turn to e499. If not, you can go to the city centre. Turn to e010."],"tables":[{"cols":["Ref","Destination","Cost"],"rows":[["e150","Marlock City","10 💎"],["e301","Isle of the Druids","15 💎"],["e234","Sorcerer's Isle","30 💎"],["e424","Copper Island","30 💎"]]},{"cols":["Ship Type","Cost","Capacity"],"rows":[["Barque","250 💎","1 Cargo Unit"],["Brigantine","450 💎","2 Cargo Units"],["Galleon","900 💎","3 Cargo Units"]]},{"cols":["Cargo","Buy","Sell"],"rows":[["Furs","190 💎","170 💎"],["Grain","200 💎","180 💎"],["Metals","600 💎","500 💎"],["Minerals","350 💎","250 💎"],["Spices","900 💎","810 💎"],["Textiles","350 💎","300 💎"],["Timber","180 💎","160 💎"]]}]},{"tag":"e556","title":"Oliphard the Wizardly Restored","desc":["Gain the codeword Amends.","You scatter the powder on the surface of the waters. Cross the vial of yellow dust off your Adventure Sheet.","There is a flash, and a cloud of yellow smoke billows up out of the pond. When it clears, you find yourself face to face with a white-bearded bespectacled old man, floating a few feet off the water! He is dressed in long, flowing ornate robes.","He blinks at you for a moment before saying, 'Thank you, thank you. That worthless apprentice of mine! Can you imagine – I told him to throw the dust into the holy waters but the idiot couldn't even be trusted to do that!'","The old man's name is Oliphard the Wizardly. As a reward, he casts a spell that enhances your skill – add one to the ability of your choice, permanently.","If you are a Mage, turn to e426. If not, he thanks you and says, 'If you ever need some help, look for me in Trefoille.' Then he leaves – turn to e378."]},{"tag":"e557","title":"The Soldier's Question","desc":["'Who is the rightful ruler of Sokara – General Grieve Marlock, or the son of the old king, Nergan Corin?' asks the soldier."],"tables":[{"cols":["Ref","Option"],"rows":[["e631","Grieve Marlock"],["e664","Nergan Corin"]]}]},{"tag":"e558","title":"The Road Between Trefoille and Caran Baru","desc":["You join the much-travelled road that connects Trefoille and Caran Baru. The traffic mostly consists of convoys of troops and supplies."],"tables":[{"cols":["Ref","Option"],"rows":[["e250","Go to Trefoille"],["e387","Follow the road north"],["e175","Go north into the Curstmoor"],["e310","Go east to the river"]]}]},{"tag":"e559","title":"Coastal Waters off the Shadar Tor","desc":["Your ship is sailing in the coastal waters off the Shadar Tor."],"tables":[{"cols":["Ref","Option"],"rows":[["e222","Sail north west towards Marlock City"],["e029","Sail north east towards Yellowport"],["e416","Sail south into the Violet Ocean"]]}]},{"tag":"e560","title":"The Western Wilderness","desc":["You are crossing the western wilderness, an expanse of wild, sparsely-populated countryside. A few trappers and woodsmen make a living from the natural resources of the area.","A tall spire of rock, a towering anomaly of geology, rises up into the clouds, dominating the horizon. A local hunter tells you it is known as Devil's Peak and that the summit is infested with demons."],"tables":[{"cols":["Ref","Option"],"rows":[["e658","Climb the peak"],["e099","Head west to the river"],["e047","Head north into the Forest of Larun"],["e175","Go south to the Curstmoor"],["e558","Travel east to the road"]]}]},{"tag":"e561","title":"Fishing for Smoulder Fish","desc":["You are left alone, free to trawl for smoulder fish. Roll one die – the result is the number of smoulder fish you catch. When you are ready, you return to shore and give the boat back.","Turn to e135."]},{"tag":"e562","title":"Halfway Up the Mountain","desc":["After a gruelling climb of some hours, you are halfway up the side of a mountain, when you discover a thin, precarious path, leading up. You take a swig of water from your canteen and proceed up the path.","After a while you have to stop to take more water. To your horror, your water supply has turned sour and undrinkable!","Make a Magic roll at Difficulty 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e374","Successful Magic roll"],["e643","Failed Magic roll"]]}]},{"tag":"e563","title":"Renouncing the Worship of Sig","desc":["To renounce the worship of Sig, you must pay 50 💎 in compensation to the priesthood. 'Sig will no longer watch over you!' says a priest.","If you are certain you want to renounce Sig's worship, cross off the 50 💎, erase Sig from the God box on your Adventure Sheet, and lose 1 point of Thievery.","'The dungeons are full of would-be rogues who renounced the faith!' yells a priest as you leave.","Turn to e100."]},{"tag":"e564","title":"The Curse of Tyrnai","desc":["You tell the high priest about the Curse of Tyrnai. 'Ah, I see. Well, you have to appease the god. You need a weapon (Combat +1), which you can buy in most markets, or acquire by some other means. Throw the weapon into the holy waters at the village of Blessed Springs, and ask for his forgiveness.'","Acquire the codeword Appease and turn to e100."]},{"tag":"e565","title":"Escaping on Your Own","desc":["Make a Thievery roll at Difficulty 10."],"tables":[{"cols":["Ref","Result"],"rows":[["e654","Successful Thievery roll"],["e376","Failed Thievery roll"]]}]},{"tag":"e566","title":"Discovered in the Pantry","desc":["You are discovered hiding in the kitchen pantry. You are hauled off and thrown into the dungeons to await judgement – lose all your money and possessions and turn to e454."]},{"tag":"e567","title":"Not Worthy","desc":["'You are not worthy,' he says gruffly, and walks on without a backward glance. You sense it would not be wise to press him further.","Turn to e412."]},{"tag":"e568","title":"The Temple of Elnir","desc":["The temple of Elnir is a single spire reaching skywards. Eagles roost in its lofty belfry – they are sacred to the priests of the Skylord. Elnir is the Divine Ruler of the Heavens, patron of statesmen and kings, and his sons are the stormlords.","'Thunder is the sound of the Sons of Elnir smiting the cloud demons,' says a passing peasant."],"tables":[{"cols":["Ref","Option"],"rows":[["e440","Become an initiate"],["e241","Renounce worship"],["e073","Seek a blessing"],["e100","Leave the temple"]]}]},{"tag":"e569","title":"Fighting the Iron Golems","desc":["You will have to fight them one at a time. They are tough opponents because their skin is made of iron.","If you win, turn to e162. If you lose, turn to e488."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["First Golem","5","11","10"],["Second Golem","5","11","10"]]}]},{"tag":"e570","title":"Attacking the Tree Guard","desc":["'Aargh, you fiendish human!' roars the tree, flailing its branches at you. You must fight.","If you reduce the tree to 5 or less ❤️, turn to e148. If you lose, you are battered into unconsciousness and wake up in the Trading Post on 1 ❤️ with all your money gone – turn to e195."],"tables":[{"cols":["Name","⚔️","🛡️","❤️"],"rows":[["Tree Guard","3","7","10"]]}]},{"tag":"e571","title":"The Merchants' Guild of Marlock City","desc":["The merchants' guild of Marlock City is a large, many-storeyed building of marble. Inside, many clerks and scribes are at work. Here you can bank your money for safekeeping, or invest it in guild enterprises in the hope of making a profit. A sign on the guildmaster's door reads 'Help wanted.'"],"tables":[{"cols":["Ref","Option"],"rows":[["e290","Visit the guildmaster"],["e104","Make an investment"],["e088","Check on investments"],["e605","Deposit or withdraw money"],["e100","Return to the town centre"]]}]},{"tag":"e572","title":"Crashing the Ratman Banquet","desc":["You open the door on to a large dining hall and kitchen. About thirty ratmen are standing around, eating and drinking. Everything goes quiet as they turn to stare at you with their black beady eyes.","'Er, I do have an invitation,' you stutter, holding up the note. 'And we'd love to have you for dinner,' one of them snarls.","Yelling noisily, they charge toward you. You have little choice but to turn and flee for your life! You race down the sewer tunnels, with the ratmen in hot pursuit."],"tables":[{"cols":["Ref","Option"],"rows":[["e079","Lose them in the tunnels"],["e296","Try some magic"],["e127","Hide"]]}]},{"tag":"e573","title":"Renouncing the Three Fortunes","desc":["To renounce the worship of the Three Fortunes, you will have to undergo a ritual. 'We must determine what the Three Fortunes have to say about the matter,' says the high priest.","Roll one die. On a 1 or a 2, you are free to go; on a 3 or 4 you must pay 25 💎 in compensation; and on a 5 or 6, they demand a sacrifice of some of your blood – lose 1 ❤️.","Do you want to reconsider? If you are determined to renounce your faith, pay whatever price the die dictates, and delete The Three Fortunes from the God box on your Adventure Sheet.","When you have finished here, turn to e086."]},{"tag":"e574","title":"The General's Reward","desc":["'Ah, the saviour of the citadel. What can I do for you?' asks the general.","He can arrange for you to be healed of all your wounds, cured of poison and disease (but his court sorcerer cannot lift a curse).","If you have no weapons or armour anywhere at all, he will give you an ordinary sword and a suit of chain mail (Defence +1). If you are completely out of money, with no Shards either banked or invested with the merchants' guild, or stored at a town house, he will give you 200 💎.","'Any time you are in real need, just come to me,' he adds.","If you have a coded missive, turn to e677. Otherwise, turn to e100."]},{"tag":"e575","title":"Yanryt the Son's Judgement","desc":["You hand him the black dragon shield. Cross it off your Adventure Sheet, and lose the codeword Axe.","'You are indeed worthy,' he says. 'And will you teach me your fighting arts?' you ask. 'You have already learned all I can teach you,' he says.","You realize that what he says is true – your defeat of the Black Dragon Knight has taught you much. Gain 1 Rank and roll one die. The score is the number of Stamina points you can add to your unwounded total, permanently. Also, don't forget to increase your Defence by 1 as a result of your gain in Rank.","You look up, but Yanryt the Son has gone. Turn to e400."]},{"tag":"e576","title":"Near the Source of the Stinking River","desc":["You are up the Stinking River, near its source – the Lake of the Sea Dragon. From here, the yellow waters rush down to the sea. The smell of the bubbling, sulphur-laden water is abominable."],"tables":[{"cols":["Ref","Option"],"rows":[["e135","Go to the Lake of the Sea Dragon"],["e310","Follow the river south"],["e558","Go west to the road"],["e278","East into the countryside"]]}]}]`),v=f,y=p,b=m,x=h,S=g,C=_;function w(){let e=[...v,...y,...b,...x,...S,...C];return{getEventData:()=>e?e.map(({tag:e,title:t})=>({tag:e,title:t})):[],getEventByTag:t=>e.find(e=>e.tag===t),getEventCount:()=>e.length}}var T=()=>{let e=`fabled-lands`;return{addToHistory:(t,n)=>{let r=JSON.parse(localStorage.getItem(e)||`[]`).filter(e=>e.tag!==t),i=[{tag:t,title:n},...r].slice(0,20);localStorage.setItem(e,JSON.stringify(i))},getHistory:()=>JSON.parse(localStorage.getItem(e)||`[]`)}},E=e(n(),1),D=t(),O=()=>{let{tag:e}=r(),{getEventByTag:t}=w(),n=t(e),{addToHistory:a}=T();if((0,E.useEffect)(()=>{n&&a(n.tag,n.title)},[a,n]),!n)return null;let f=parseInt(e.replace(/\D/g,``),10),p=e.replace(/\d+$/,``),m=`${p}${String(f-1).padStart(3,`0`)}`,h=`${p}${String(f+1).padStart(3,`0`)}`;return(0,D.jsxs)(D.Fragment,{children:[n.desc&&n.desc?.length>=1&&(0,D.jsx)(o,{title:n.title,children:(0,D.jsxs)(`div`,{style:{display:`flow-root`},children:[n.image&&(0,D.jsx)(l,{tag:e,title:n.title}),n.desc.map((e,t)=>(0,D.jsx)(`p`,{children:s(e)},t))]})}),n.tables?.map((e,t)=>(0,D.jsx)(c,{table:e},t)),n.note&&(0,D.jsx)(o,{title:`Notes`,children:n.note?.map((e,t)=>(0,D.jsx)(`p`,{children:s(e)},t))}),(0,D.jsxs)(`div`,{className:`flex justify-center gap-5`,children:[(0,D.jsx)(i,{to:`/event/${m}`,children:(0,D.jsx)(u,{size:30})}),(0,D.jsx)(i,{to:`/event/${h}`,children:(0,D.jsx)(d,{size:30})})]})]})};export{O as default};